// ===== Android WebView JS Bridge =====
var isAndroidApp = navigator.userAgent.indexOf('LingVerse') >= 0;
if (isAndroidApp) {
    var gt = document.getElementById('headerGameTime');
    if (gt) gt.style.marginLeft = 'auto';
    var pBtn = document.querySelector('.btn-toggle-player');
    if (pBtn) pBtn.style.marginLeft = '15px';
    if (gt) gt.style.marginRight = '15px';
}

function requestXianyuanAd() {
    if (typeof LingVerseNative !== 'undefined' && LingVerseNative.requestXianyuanAd) {
        LingVerseNative.requestXianyuanAd();
    }
}

window.onAdRewardResult = function(success) {
    if (success) {
        showToast('仙缘获取成功！');
        loadPlayerInfo();
        var adModal = document.getElementById('adPointsModal');
        if (adModal && !adModal.classList.contains('hidden')) {
            showAdPointsModal();
        }
    } else {
        showToast('仙缘获取失败，请稍后再试');
    }
};

function setupAdPointsEarnBtn() {
    var btn = document.getElementById('adPointsEarnBtn');
    if (!btn) return;
    if (isAndroidApp) {
        btn.textContent = '获取仙缘';
        btn.removeAttribute('href');
        btn.removeAttribute('target');
        btn.onclick = function(e) {
            e.preventDefault();
            requestXianyuanAd();
        };
        var howTo = document.getElementById('adPointsHowToGet');
        if (howTo) howTo.style.display = 'none';
    } else {
        // Web端：从接口获取下载链接
        api.get('/api/app/update').then(function(res) {
            if (res.code === 200 && res.data && res.data.url) {
                btn.href = res.data.url;
            }
        }).catch(function() {});
    }
}

