// ===== 游戏说明折叠 =====
var _guideEncyclopediaCache = null;
var _guideSearchTimer = null;
var _guideSearchSeq = 0;

function toggleGuideSection(headerEl) {
    var section = headerEl.parentElement;
    section.classList.toggle('open');
}

function filterGuide() {
    var input = document.getElementById('guideSearchInput');
    if (!input) return;
    var keyword = input.value.trim().toLowerCase();
    scheduleGuideItemSearch(keyword);
    var sections = document.querySelectorAll('#guidePanel .guide-section');
    sections.forEach(function(section) {
        if (!keyword) {
            section.style.display = '';
            section.classList.remove('open');
            return;
        }
        var text = section.textContent || section.innerText;
        if (text.toLowerCase().indexOf(keyword) > -1) {
            section.style.display = '';
            section.classList.add('open');
        } else {
            section.style.display = 'none';
        }
    });
}

function scheduleGuideItemSearch(keyword) {
    var resultEl = document.getElementById('guideSearchResult');
    if (!resultEl) return;
    if (_guideSearchTimer) clearTimeout(_guideSearchTimer);
    if (!keyword) {
        resultEl.classList.add('hidden');
        resultEl.innerHTML = '';
        return;
    }
    _guideSearchTimer = setTimeout(function() {
        updateGuideItemSearch(keyword);
    }, 180);
}

async function getGuideEncyclopediaData() {
    if (_guideEncyclopediaCache) return _guideEncyclopediaCache;
    if (typeof api === 'undefined' || typeof api.get !== 'function') return [];
    var res = await api.get('/api/game/encyclopedia');
    _guideEncyclopediaCache = (res && res.code === 200 && Array.isArray(res.data)) ? res.data : [];
    return _guideEncyclopediaCache;
}

async function updateGuideItemSearch(keyword) {
    var resultEl = document.getElementById('guideSearchResult');
    if (!resultEl || !keyword) return;
    var seq = ++_guideSearchSeq;
    try {
        var items = await getGuideEncyclopediaData();
        if (seq !== _guideSearchSeq) return;
        var currentKeyword = (document.getElementById('guideSearchInput')?.value || '').trim().toLowerCase();
        if (currentKeyword !== keyword) return;
        var matched = items.find(function(item) {
            return (item.name || '').toLowerCase() === keyword || (item.id || '').toLowerCase() === keyword;
        }) || items.find(function(item) {
            return (item.name || '').toLowerCase().indexOf(keyword) >= 0 || (item.id || '').toLowerCase().indexOf(keyword) >= 0;
        });
        if (!matched) {
            resultEl.classList.add('hidden');
            resultEl.innerHTML = '';
            return;
        }
        var locText = (matched.dropLocations || []).slice(0, 5).map(function(loc) {
            return (loc.continentName ? loc.continentName + ' - ' : '') + (loc.areaName || '') + (loc.dropRateText ? '(' + loc.dropRateText + ')' : '');
        }).filter(Boolean).join('、');
        var sourceText = locText || (matched.source || '');
        var usageText = (matched.usageDesc || '').split('\n').filter(Boolean).join('；') || '暂无已登记用途';
        resultEl.innerHTML =
            '<div class="guide-search-result__name">' + escapeHtml(matched.name || matched.id || keyword) + '</div>' +
            '<div class="guide-search-result__line">' + escapeHtml(matched.description || '') + '</div>' +
            '<div class="guide-search-result__line"><span class="guide-search-result__label">用途：</span>' + escapeHtml(usageText) + '</div>' +
            (sourceText ? '<div class="guide-search-result__line"><span class="guide-search-result__label">产地：</span>' + escapeHtml(sourceText) + '</div>' : '');
        resultEl.classList.remove('hidden');
    } catch (e) {
        if (seq !== _guideSearchSeq) return;
        resultEl.classList.add('hidden');
        resultEl.innerHTML = '';
    }
}

function showLuckGuide() {
    var guidePanel = document.getElementById('guidePanel');
    if (guidePanel && guidePanel.classList.contains('hidden')) {
        if (typeof togglePanel === 'function') togglePanel('guide');
    }
    var luckSection = document.getElementById('guideLuckSection');
    if (luckSection) {
        luckSection.classList.add('open');
        setTimeout(() => {
            luckSection.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }, 300);
    }
}

