function checkAnnouncement() {
    var readVersion = localStorage.getItem('announce_read') || '';
    if (ANNOUNCEMENT.version !== readVersion) {
        showAnnouncement();
    }
}

function showAnnouncement() {
    document.getElementById('announceTitle').textContent = '-- ' + ANNOUNCEMENT.title + ' --';
    document.getElementById('announceBody').innerHTML = ANNOUNCEMENT.content;
    document.getElementById('announceOverlay').classList.remove('hidden');
}

function closeAnnouncement() {
    localStorage.setItem('announce_read', ANNOUNCEMENT.version);
    document.getElementById('announceOverlay').classList.add('hidden');
}

function showAllAnnouncements() {
    showAnnouncement();
}

function closeAllAnnouncements() {
    closeAnnouncement();
}

// ===== 游戏时间前端计算 (与 GameTimeConfig.kt 同步) =====
var GAME_TIME_EPOCH = 1741449600000; // 2025-03-09 00:00:00 UTC+8
var GAME_TIME_RATIO = 365;
var SHICHEN_NAMES = ['子时(夜)','丑时(夜)','寅时(夜)','卯时(昼)','辰时(昼)','巳时(昼)','午时(昼)','未时(昼)','申时(昼)','酉时(昼)','戌时(夜)','亥时(夜)'];
var SEASON_NAMES = ['春','夏','秋','冬'];
var GAME_DAY_MS = 86400000;
var GAME_DAY_NIGHT_START_HOUR = 5;
var GAME_NIGHT_START_HOUR = 19;

function calcGameTime() {
    var elapsed = Date.now() - GAME_TIME_EPOCH;
    var gameMs = elapsed * GAME_TIME_RATIO;
    var gameDays = Math.floor(gameMs / GAME_DAY_MS);
    var dayRemainder = ((gameMs % GAME_DAY_MS) + GAME_DAY_MS) % GAME_DAY_MS;
    var gameHour = Math.floor((dayRemainder * 24) / GAME_DAY_MS);
    var year = Math.floor(gameDays / 365) + 1;
    var dayOfYear = gameDays % 365;
    var month = Math.min(Math.floor(dayOfYear / 30), 11) + 1;
    var day = (dayOfYear % 30) + 1;
    var shichenIdx = Math.min(Math.max(Math.floor(gameHour / 2), 0), 11);
    var seasonIdx = 3;
    if (month >= 3 && month <= 5) seasonIdx = 0;
    else if (month >= 6 && month <= 8) seasonIdx = 1;
    else if (month >= 9 && month <= 11) seasonIdx = 2;
    var isNight = gameHour < GAME_DAY_NIGHT_START_HOUR || gameHour >= GAME_NIGHT_START_HOUR;
    var nextBoundaryHour = isNight
        ? (gameHour < GAME_DAY_NIGHT_START_HOUR ? GAME_DAY_NIGHT_START_HOUR : GAME_DAY_NIGHT_START_HOUR + 24)
        : GAME_NIGHT_START_HOUR;
    var nextBoundaryMs = nextBoundaryHour * GAME_DAY_MS / 24;
    var remainingGameMs = nextBoundaryMs - dayRemainder;
    if (remainingGameMs <= 0) remainingGameMs += GAME_DAY_MS;
    return {
        displayText: '灵历' + year + '年 ' + SEASON_NAMES[seasonIdx] + ' ' + month + '月' + day + '日 ' + SHICHEN_NAMES[shichenIdx],
        isNight: isNight,
        seasonIdx: seasonIdx,
        dayNightRemainingMs: Math.ceil(remainingGameMs / GAME_TIME_RATIO),
        nextDayNightLabel: isNight ? '天明' : '入夜'
    };
}

function formatDayNightCountdown(ms) {
    var totalSeconds = Math.max(0, Math.ceil((Number(ms) || 0) / 1000));
    var minutes = Math.floor(totalSeconds / 60);
    var seconds = totalSeconds % 60;
    if (minutes > 0) return minutes + '分' + String(seconds).padStart(2, '0') + '秒';
    return seconds + '秒';
}

function updateGameTimeDisplay() {
    var gt = calcGameTime();
    var el = document.getElementById('headerGameTime');
    if (el) {
        el.textContent = gt.displayText;
        el.className = 'header-gametime' + (gt.isNight ? ' is-night' : '');
    }
    var envOverlay = document.getElementById('envOverlay');
    if (envOverlay && !envOverlay.classList.contains('hidden')) {
        renderEnvEffects(gt);
    }
}

function startGameTimeTicker() {
    updateGameTimeDisplay();
    setInterval(updateGameTimeDisplay, 1000);
}

var _wbPollTimer = null;
var _wbPollInterval = 15000;
var _wbInactiveCount = 0;

function pollGlobalWorldBossStatus() {
    if (document.hidden) return; // P1-C4: 切后台不轮询
    api.get('/api/world_boss/status').then(function(res) {
        var statusEl = document.getElementById('headerWbStatus');
        if (!statusEl) return;
        if (res.code === 200 && res.data && res.data.isActive) {
            _wbInactiveCount = 0;
            if (_wbPollInterval !== 15000) {
                _wbPollInterval = 15000;
                resetWbTimer();
            }
            statusEl.classList.remove('hidden');
            var pct = Math.max(0, Math.floor((res.data.currentHp / (res.data.maxHp || 1)) * 100));
            var bossName = res.data.name || '世界Boss';
            statusEl.textContent = bossName + ' ' + pct + '%';
            if (pct <= 0) {
               statusEl.classList.add('hidden');
            }
        } else {
            statusEl.classList.add('hidden');
            _wbInactiveCount++;
            if (_wbInactiveCount >= 2 && _wbPollInterval !== 60000) {
                _wbPollInterval = 60000; // P1-C4: 多次非激活时降频到 60s
                resetWbTimer();
            }
        }
    }).catch(function() {});
}

function resetWbTimer() {
    if (_wbPollTimer) clearInterval(_wbPollTimer);
    _wbPollTimer = setInterval(pollGlobalWorldBossStatus, _wbPollInterval);
}

function startGlobalWorldBossPolling() {
    pollGlobalWorldBossStatus();
    resetWbTimer();
}

function renderEnvEffects(gt) {
    gt = gt || calcGameTime();
    var seasons = ['春', '夏', '秋', '冬'];
    var seasonDesc = [
        '<span style="color:var(--accent-jade)">万物复苏</span><br>基础资源寻获概率 <b style="color:var(--accent-jade)">+20%</b>',
        '<span style="color:#e06060">酷暑炎炎</span><br>妖兽遭遇率 <b style="color:#e06060">+10%</b>, 经验获取 <b style="color:var(--accent-gold)">+10%</b>',
        '<span style="color:#d4a373">金秋丰收</span><br>灵石掉落量 <b style="color:#d4a373">+20%</b>',
        '<span style="color:#8ecae6">凛冬将至</span><br>妖兽防御 <b style="color:#8ecae6">+10%</b>, 稀有掉落 <b style="color:var(--accent-jade)">+5%</b>'
    ];
    var seasonTitle = document.getElementById('envSeasonTitle');
    var seasonDescEl = document.getElementById('envSeasonDesc');
    if (seasonTitle) seasonTitle.textContent = '当前季节: ' + seasons[gt.seasonIdx];
    if (seasonDescEl) seasonDescEl.innerHTML = seasonDesc[gt.seasonIdx];

    var dayNightTitle = gt.isNight ? '当前：黑夜 (19点~次日5点)' : '当前：白昼 (5点~19点)';
    dayNightTitle += ' · 距离' + gt.nextDayNightLabel + ' ' + formatDayNightCountdown(gt.dayNightRemainingMs);
    var dayNightDesc = gt.isNight 
        ? '<span style="color:var(--text-red)">夜色深沉</span><br>危机: 妖兽攻击 <b style="color:var(--text-red)">+20%</b><br>机遇: 掉落率 <b style="color:var(--accent-gold)">+10%</b>, 经验 <b style="color:var(--accent-gold)">+15%</b>'
        : '<span style="color:var(--text-muted)">风平浪静，修行稳步精进。</span>';
    
    var dayNightTitleEl = document.getElementById('envDayNightTitle');
    var dayNightDescEl = document.getElementById('envDayNightDesc');
    if (dayNightTitleEl) dayNightTitleEl.textContent = dayNightTitle;
    if (dayNightDescEl) dayNightDescEl.innerHTML = dayNightDesc;
}

function showEnvEffects() {
    renderEnvEffects();
    
    var overlay = document.getElementById('envOverlay');
    if (overlay) overlay.classList.remove('hidden');
}

function closeEnvEffects() {
    var overlay = document.getElementById('envOverlay');
    if (overlay) overlay.classList.add('hidden');
}

