var _uiPaletteSyncing = false;
var UI_PALETTE_CUSTOM_INPUTS = {
    primary: { color: 'uiPalettePrimaryInput', hex: 'uiPalettePrimaryHexInput' },
    secondary: { color: 'uiPaletteSecondaryInput', hex: 'uiPaletteSecondaryHexInput' },
    background: { color: 'uiPaletteBackgroundInput', hex: 'uiPaletteBackgroundHexInput' }
};

function normalizeUiPaletteHex(value) {
    var hex = String(value || '').trim().toLowerCase();
    if (/^[0-9a-f]{6}$/.test(hex)) hex = '#' + hex;
    return /^#[0-9a-f]{6}$/.test(hex) ? hex : '';
}

function formatUiPaletteHexInputValue(hex) {
    var normalized = normalizeUiPaletteHex(hex);
    return normalized ? normalized.toUpperCase() : '';
}

function getCustomUiPaletteInputPair(kind) {
    return UI_PALETTE_CUSTOM_INPUTS[kind] || null;
}

function setCustomUiPaletteInputPair(kind, hex) {
    var pair = getCustomUiPaletteInputPair(kind);
    var normalized = normalizeUiPaletteHex(hex);
    if (!pair || !normalized) return;
    var colorInput = document.getElementById(pair.color);
    var hexInput = document.getElementById(pair.hex);
    if (colorInput) colorInput.value = normalized;
    if (hexInput) {
        hexInput.value = formatUiPaletteHexInputValue(normalized);
        hexInput.classList.remove('is-invalid');
    }
}

function readCustomUiPaletteHex(kind) {
    var pair = getCustomUiPaletteInputPair(kind);
    if (!pair) return '';
    var hexInput = document.getElementById(pair.hex);
    if (hexInput) {
        var raw = String(hexInput.value || '').trim();
        var normalized = normalizeUiPaletteHex(raw);
        hexInput.classList.toggle('is-invalid', raw !== '' && !normalized);
        return normalized;
    }
    var colorInput = document.getElementById(pair.color);
    return normalizeUiPaletteHex(colorInput && colorInput.value);
}

function syncUiPaletteHexFromColor(kind) {
    var pair = getCustomUiPaletteInputPair(kind);
    if (!pair) return;
    var colorInput = document.getElementById(pair.color);
    var normalized = normalizeUiPaletteHex(colorInput && colorInput.value);
    if (normalized) setCustomUiPaletteInputPair(kind, normalized);
}

function syncUiPaletteColorFromHex(kind) {
    var normalized = readCustomUiPaletteHex(kind);
    var pair = getCustomUiPaletteInputPair(kind);
    var colorInput = pair ? document.getElementById(pair.color) : null;
    if (normalized && colorInput) colorInput.value = normalized;
    return normalized;
}

function normalizeCustomUiPaletteHexInput(kind) {
    var normalized = syncUiPaletteColorFromHex(kind);
    if (normalized) setCustomUiPaletteInputPair(kind, normalized);
}

function normalizeUiPaletteMode(mode) {
    mode = String(mode || 'default').trim().toLowerCase();
    if (mode === 'custom') return mode;
    return Object.prototype.hasOwnProperty.call(UI_PALETTE_PRESETS, mode) ? mode : 'default';
}

function uiPaletteRgba(hex, alpha) {
    var rgb = uiPaletteRgb(hex);
    return 'rgba(' + rgb.r + ', ' + rgb.g + ', ' + rgb.b + ', ' + alpha + ')';
}

function uiPaletteRgb(hex) {
    hex = normalizeUiPaletteHex(hex) || '#000000';
    var r = parseInt(hex.slice(1, 3), 16);
    var g = parseInt(hex.slice(3, 5), 16);
    var b = parseInt(hex.slice(5, 7), 16);
    return { r: r, g: g, b: b };
}

function uiPaletteHexPart(value) {
    var hex = Math.round(value).toString(16);
    return hex.length === 1 ? '0' + hex : hex;
}

function uiPaletteMix(hex, targetHex, targetWeight) {
    var source = uiPaletteRgb(hex);
    var target = uiPaletteRgb(targetHex);
    var weight = Math.max(0, Math.min(1, Number(targetWeight) || 0));
    return '#' +
        uiPaletteHexPart(source.r * (1 - weight) + target.r * weight) +
        uiPaletteHexPart(source.g * (1 - weight) + target.g * weight) +
        uiPaletteHexPart(source.b * (1 - weight) + target.b * weight);
}

function uiPaletteLuminance(hex) {
    var rgb = uiPaletteRgb(hex);
    function channel(value) {
        value = value / 255;
        return value <= 0.03928 ? value / 12.92 : Math.pow((value + 0.055) / 1.055, 2.4);
    }
    return channel(rgb.r) * 0.2126 + channel(rgb.g) * 0.7152 + channel(rgb.b) * 0.0722;
}

function isUiPaletteDarkTheme() {
    return document.documentElement.classList.contains('theme-dark');
}

function getUiPalettePresetBackground(preset) {
    preset = preset || UI_PALETTE_PRESETS.default;
    return isUiPaletteDarkTheme() ? preset.backgroundDark : preset.backgroundLight;
}

function getUiPaletteDefaultBackground() {
    return getUiPalettePresetBackground(UI_PALETTE_PRESETS.default);
}

function buildUiPaletteSurfaceTokens(background) {
    var bg = normalizeUiPaletteHex(background) || getUiPaletteDefaultBackground();
    var dark = uiPaletteLuminance(bg) < 0.42;
    var lift = dark ? '#ffffff' : '#000000';
    var cardTarget = dark ? '#ffffff' : '#ffffff';
    var softTint = dark ? '#ffffff' : '#000000';
    var textPrimary = dark ? '#d8dde0' : '#2f2f2b';
    var textSecondary = dark ? '#a9b1b6' : '#56564f';
    var textMuted = dark ? '#7f8a91' : '#79786f';

    return {
        background: bg,
        secondary: uiPaletteMix(bg, softTint, dark ? 0.045 : 0.035),
        panel: uiPaletteMix(bg, lift, dark ? 0.055 : 0.025),
        card: uiPaletteMix(bg, cardTarget, dark ? 0.085 : 0.58),
        cardHover: uiPaletteMix(bg, lift, dark ? 0.13 : 0.055),
        lighter: uiPaletteMix(bg, lift, dark ? 0.12 : 0.06),
        input: dark ? 'rgba(220, 230, 236, 0.045)' : 'rgba(255, 255, 255, 0.70)',
        active: dark ? 'rgba(220, 230, 236, 0.07)' : 'rgba(42, 42, 38, 0.055)',
        glass: dark ? 'rgba(220, 230, 236, 0.03)' : 'rgba(255, 255, 255, 0.66)',
        border: dark ? 'rgba(172, 186, 196, 0.15)' : 'rgba(42, 42, 38, 0.13)',
        textPrimary: textPrimary,
        textSecondary: textSecondary,
        textMuted: textMuted
    };
}

function forEachUiPaletteTarget(callback) {
    callback(document.documentElement);
    if (document.body) callback(document.body);
}

function getStoredUiPaletteConfig() {
    var mode = 'default';
    try {
        mode = normalizeUiPaletteMode(localStorage.getItem('lv_ui_palette') || 'default');
    } catch (e) {}
    if (mode === 'custom') {
        return getStoredCustomUiPaletteConfig();
    }
    var preset = UI_PALETTE_PRESETS[mode] || UI_PALETTE_PRESETS.default;
    return {
        mode: mode,
        primary: preset.primary,
        secondary: preset.secondary,
        background: getUiPalettePresetBackground(preset)
    };
}

function getStoredCustomUiPaletteConfig() {
    var primary = '';
    var secondary = '';
    var background = '';
    try {
        primary = normalizeUiPaletteHex(localStorage.getItem('lv_ui_palette_primary'));
        secondary = normalizeUiPaletteHex(localStorage.getItem('lv_ui_palette_secondary'));
        background = normalizeUiPaletteHex(localStorage.getItem('lv_ui_palette_background'));
    } catch (e) {}
    return {
        mode: 'custom',
        primary: primary || UI_PALETTE_PRESETS.default.primary,
        secondary: secondary || UI_PALETTE_PRESETS.default.secondary,
        background: background || getUiPaletteDefaultBackground()
    };
}

function storeCustomUiPaletteValues(config) {
    config = config || {};
    try {
        var primary = normalizeUiPaletteHex(config.primary);
        var secondary = normalizeUiPaletteHex(config.secondary);
        var background = normalizeUiPaletteHex(config.background);
        if (primary) localStorage.setItem('lv_ui_palette_primary', primary);
        if (secondary) localStorage.setItem('lv_ui_palette_secondary', secondary);
        if (background) localStorage.setItem('lv_ui_palette_background', background);
    } catch (e) {}
}

function storeUiPaletteConfig(config) {
    config = config || getStoredUiPaletteConfig();
    try {
        localStorage.setItem('lv_ui_palette', config.mode || 'default');
        if (config.mode === 'custom') {
            storeCustomUiPaletteValues(config);
        }
    } catch (e) {}
}

function updateUiPaletteControls(config) {
    config = config || getStoredUiPaletteConfig();
    var mode = config.mode || 'default';
    document.querySelectorAll('.ui-palette-btn').forEach(function(btn) {
        var active = btn.getAttribute('data-palette') === mode;
        btn.classList.toggle('active', active);
        btn.setAttribute('aria-checked', active ? 'true' : 'false');
    });
    var customFields = document.getElementById('uiPaletteCustomFields');
    if (customFields) customFields.classList.toggle('hidden', mode !== 'custom');
    var customConfig = mode === 'custom' ? config : getStoredCustomUiPaletteConfig();
    var customPrimary = normalizeUiPaletteHex(customConfig.primary) || UI_PALETTE_PRESETS.default.primary;
    var customSecondary = normalizeUiPaletteHex(customConfig.secondary) || UI_PALETTE_PRESETS.default.secondary;
    var customBackground = normalizeUiPaletteHex(customConfig.background) || getUiPaletteDefaultBackground();
    setCustomUiPaletteInputPair('primary', customPrimary);
    setCustomUiPaletteInputPair('secondary', customSecondary);
    setCustomUiPaletteInputPair('background', customBackground);
    var customBtn = document.querySelector('.ui-palette-btn[data-palette="custom"]');
    if (customBtn) {
        customBtn.style.setProperty('--swatch-primary', customPrimary);
        customBtn.style.setProperty('--swatch-secondary', customSecondary);
        customBtn.style.setProperty('--swatch-bg', customBackground);
    }
}

function applyUiPalette(config) {
    config = config || getStoredUiPaletteConfig();
    forEachUiPaletteTarget(function(target) {
        UI_PALETTE_STYLE_VARS.forEach(function(name) {
            target.style.removeProperty(name);
        });
    });
    if (config.mode !== 'default') {
        var primary = normalizeUiPaletteHex(config.primary) || UI_PALETTE_PRESETS.default.primary;
        var secondary = normalizeUiPaletteHex(config.secondary) || UI_PALETTE_PRESETS.default.secondary;
        var surface = buildUiPaletteSurfaceTokens(config.background);
        forEachUiPaletteTarget(function(target) {
            target.style.setProperty('--bg-primary', surface.background);
            target.style.setProperty('--bg-secondary', surface.secondary);
            target.style.setProperty('--bg-card', surface.card);
            target.style.setProperty('--bg-card-hover', surface.cardHover);
            target.style.setProperty('--bg-panel', surface.panel);
            target.style.setProperty('--bg-body', surface.background);
            target.style.setProperty('--bg-lighter', surface.lighter);
            target.style.setProperty('--bg-input', surface.input);
            target.style.setProperty('--bg-active', surface.active);
            target.style.setProperty('--bg-glass', surface.glass);
            target.style.setProperty('--gradient-bg', surface.background);
            target.style.setProperty('--border-color', surface.border);
            target.style.setProperty('--text-primary', surface.textPrimary);
            target.style.setProperty('--text-secondary', surface.textSecondary);
            target.style.setProperty('--text-muted', surface.textMuted);
            target.style.setProperty('--text-main', surface.textPrimary);
            target.style.setProperty('--text-color', surface.textPrimary);
            target.style.setProperty('--accent-gold', primary);
            target.style.setProperty('--text-gold', primary);
            target.style.setProperty('--border-gold', uiPaletteRgba(primary, 0.26));
            target.style.setProperty('--gradient-gold', uiPaletteRgba(primary, 0.11));
            target.style.setProperty('--accent-jade', secondary);
            target.style.setProperty('--text-jade', secondary);
            target.style.setProperty('--border-jade', uiPaletteRgba(secondary, 0.24));
            target.style.setProperty('--gradient-jade', uiPaletteRgba(secondary, 0.11));
            target.style.setProperty('--accent-orange', primary);
            target.style.setProperty('--text-orange', primary);
            target.style.setProperty('--border-orange', uiPaletteRgba(primary, 0.24));
            target.style.setProperty('--bg-orange-glass', uiPaletteRgba(primary, 0.06));
            target.style.setProperty('--primary', secondary);
            target.style.setProperty('--ui-button-bg', uiPaletteRgba(primary, 0.18));
            target.style.setProperty('--ui-button-bg-hover', uiPaletteRgba(primary, 0.28));
            target.style.setProperty('--ui-button-border', uiPaletteRgba(primary, 0.48));
            target.style.setProperty('--ui-button-text', primary);
            target.style.setProperty('--ui-primary-action-bg', uiPaletteRgba(secondary, 0.20));
            target.style.setProperty('--ui-primary-action-bg-hover', uiPaletteRgba(secondary, 0.30));
            target.style.setProperty('--ui-primary-action-border', uiPaletteRgba(secondary, 0.52));
            target.style.setProperty('--ui-primary-action-border-hover', uiPaletteRgba(secondary, 0.68));
            target.style.setProperty('--ui-primary-action-color', secondary);
            target.style.setProperty('--ui-primary-action-color-hover', secondary);
        });
    }
    updateUiPaletteControls(config);
}

function currentCustomUiPaletteConfig() {
    return {
        mode: 'custom',
        primary: readCustomUiPaletteHex('primary'),
        secondary: readCustomUiPaletteHex('secondary'),
        background: readCustomUiPaletteHex('background')
    };
}

function persistUiPaletteToServer(config, silent) {
    config = config || getStoredUiPaletteConfig();
    if (typeof api === 'undefined' || typeof api.post !== 'function') return Promise.resolve(false);
    if (!localStorage.getItem('token')) return Promise.resolve(false);
    var payload = {
        mode: config.mode || 'default'
    };
    if (payload.mode === 'custom') {
        payload.primary = normalizeUiPaletteHex(config.primary) || '';
        payload.secondary = normalizeUiPaletteHex(config.secondary) || '';
        payload.background = normalizeUiPaletteHex(config.background) || '';
    }
    return api.post('/api/player/settings/ui-palette', payload).then(function(res) {
        if (res && res.code === 200) return true;
        if (!silent) showToast((res && res.message) || '界面配色保存失败');
        return false;
    }).catch(function() {
        if (!silent) showToast('界面配色已保存在本机，云端同步失败');
        return false;
    });
}

function switchUiPalette(mode) {
    mode = normalizeUiPaletteMode(mode);
    var config;
    if (mode === 'custom') {
        var stored = getStoredCustomUiPaletteConfig();
        config = {
            mode: 'custom',
            primary: stored.primary || UI_PALETTE_PRESETS.default.primary,
            secondary: stored.secondary || UI_PALETTE_PRESETS.default.secondary,
            background: stored.background || getUiPaletteDefaultBackground()
        };
    } else {
        var preset = UI_PALETTE_PRESETS[mode] || UI_PALETTE_PRESETS.default;
        config = {
            mode: mode,
            primary: preset.primary,
            secondary: preset.secondary,
            background: getUiPalettePresetBackground(preset)
        };
    }
    storeUiPaletteConfig(config);
    applyUiPalette(config);
    persistUiPaletteToServer(config, true);
}

function previewCustomUiPalette() {
    var config = currentCustomUiPaletteConfig();
    if (!config.primary || !config.secondary || !config.background) return;
    applyUiPalette(config);
}

function saveCustomUiPalette() {
    var config = currentCustomUiPaletteConfig();
    if (!config.primary || !config.secondary || !config.background) {
        showToast('请选择合法的主色、辅色和背景色');
        return;
    }
    storeUiPaletteConfig(config);
    applyUiPalette(config);
    persistUiPaletteToServer(config, false);
    showToast('界面配色已应用');
}

async function syncUiPaletteFromServer() {
    if (_uiPaletteSyncing) return;
    if (typeof api === 'undefined' || typeof api.get !== 'function') return;
    if (!localStorage.getItem('token')) return;
    _uiPaletteSyncing = true;
    try {
        var res = await api.get('/api/player/settings');
        var settings = (res && res.code === 200 && res.data) ? res.data : null;
        if (!settings || typeof settings.ui_palette_mode === 'undefined') return;
        var mode = normalizeUiPaletteMode(settings.ui_palette_mode);
        var primary = normalizeUiPaletteHex(settings.ui_palette_primary);
        var secondary = normalizeUiPaletteHex(settings.ui_palette_secondary);
        var serverBackground = normalizeUiPaletteHex(settings.ui_palette_background);
        var background = mode === 'custom' ? serverBackground : '';
        storeCustomUiPaletteValues({
            primary: primary,
            secondary: secondary,
            background: serverBackground
        });
        var preset = UI_PALETTE_PRESETS[mode] || UI_PALETTE_PRESETS.default;
        var storedCustom = getStoredCustomUiPaletteConfig();
        var config = mode === 'custom'
            ? {
                mode: mode,
                primary: primary || storedCustom.primary,
                secondary: secondary || storedCustom.secondary,
                background: background || storedCustom.background
            }
            : {
                mode: mode,
                primary: preset.primary,
                secondary: preset.secondary,
                background: getUiPalettePresetBackground(preset)
            };
        storeUiPaletteConfig(config);
        applyUiPalette(config);
    } catch (e) {
        applyUiPalette();
    } finally {
        _uiPaletteSyncing = false;
    }
}

// ===== 初始化 =====
(function init() {
    if (!localStorage.getItem('token')) {
        window.location.href = '/';
        return;
    }
    applyUiPalette();
    syncUiPaletteFromServer();
    // 首屏关键: 角色信息 + 日志 + 遭遇检查 + 聊天连接
    connectChatWs();
    loadPlayerInfo(true, true);
    loadGameLogs();
    checkPendingEncounter();
    checkPendingMerchant();
    checkAnnouncement(); // 纯本地操作，无网络开销
    startGameTimeTicker(); // 纯前端计算，无网络开销
    _chatHistoryLoaded = true;
    loadChatHistory().catch(function() { _chatHistoryLoaded = false; });
    refreshMasterChatChannels();

    // 注册时填写引荐码的处理结果：进入游戏后立即弹一次 toast 后清除
    try {
        var pendingHint = sessionStorage.getItem('pending_invite_hint');
        if (pendingHint) {
            sessionStorage.removeItem('pending_invite_hint');
            setTimeout(function () { showToast(pendingHint); }, 1500);
        }
    } catch (e) { /* ignore */ }

    // 延迟3秒加载非关键请求，降低首屏并发压力
    setTimeout(function() {
        startGlobalWorldBossPolling();
        if (typeof FriendModule !== 'undefined') FriendModule.loadUnreadCount();
        if (typeof FeedbackModule !== 'undefined') FeedbackModule.loadUnreadCount();
        // 师徒红点由 game-master.js 内部独立轮询，保证不依赖脚本加载顺序
        loadTasks(); // 引导脉冲 + 红点
    }, 3000);
})();


// ===== 加载游戏日志 =====
async function loadGameLogs() {
    var res = null;
    try {
        res = await api.get('/api/game/logs');
    } catch (e) {
        return;
    }
    var logContent = document.getElementById('logContent');
    if (!logContent || res.code !== 200 || !res.data) return;
    var logPanel = document.getElementById('logPanel');
    // iOS Safari 上 `scroll-behavior: smooth` 会在重建内容后产生"先上移再下滑"的动画；
    // 用 DocumentFragment 一次性替换，并用 behavior:'auto' 强制瞬时定位到底部。
    var fragment = document.createDocumentFragment();
    res.data.forEach(function (log) {
        var p = document.createElement('p');
        p.className = 'log-line log-' + (log.type || 'explore');
        p.textContent = log.content;
        fragment.appendChild(p);
    });
    logContent.textContent = '';
    logContent.appendChild(fragment);
    if (logPanel) {
        var target = logPanel.scrollHeight;
        if (typeof logPanel.scrollTo === 'function') {
            logPanel.scrollTo({ top: target, behavior: 'auto' });
        } else {
            logPanel.scrollTop = target;
        }
    }
}

// ===== 加载角色信息 =====
var _playerInfoLastFetch = 0;
var _playerInfoPending = null;
var _playerInfoPendingDetail = false;
var _playerInfoPendingForce = false;
var _playerInfoDetailWarmupTimer = null;
window._playerInfoHasDetail = window._playerInfoHasDetail || false;
var _playerInfoSeq = 0;        // 请求单调序号
var _playerInfoAppliedSeq = 0; // 已应用的最大序号
var _PLAYER_INFO_THROTTLE_MS = 2000; // 2秒节流

// 武道大会红点节流：仅在海选阶段且剩余 > 0 时显示
// 暴露到 window 供 TournamentModule._syncBadge 同步推进时间戳
window._tournamentBadgeLastFetch = window._tournamentBadgeLastFetch || 0;
var _TOURNAMENT_BADGE_THROTTLE_MS = 60000; // 60 秒节流（红点变化不需要太敏感）
function refreshTournamentBadge(force) {
    var now = Date.now();
    if (!force && (now - window._tournamentBadgeLastFetch) < _TOURNAMENT_BADGE_THROTTLE_MS) return;
    window._tournamentBadgeLastFetch = now;
    api.get('/api/tournament/my-info').then(function (res) {
        var d = (res && res.code === 200) ? res.data : null;
        var show = false;
        if (d && /海选征战中/.test(d.stageLabel || '')) {
            var remaining = (d.maxMatchTimes || 10) - (d.matchTimes || 0);
            show = remaining > 0;
            // 用户已打开过武道面板后不再重新显示红点
            if (show && window._tournamentBadgeDismissed) show = false;
        } else {
            // 阶段变化时重置 dismissed 标记，允许下次海选重新显示红点
            window._tournamentBadgeDismissed = false;
        }
        var badgeD = document.getElementById('tournamentBadgeDesktop');
        var badgeM = document.getElementById('tournamentBadgeMobile');
        if (show) {
            if (badgeD) badgeD.classList.remove('hidden');
            if (badgeM) badgeM.classList.remove('hidden');
        } else {
            if (badgeD) badgeD.classList.add('hidden');
            if (badgeM) badgeM.classList.add('hidden');
        }
    }).catch(function (e) {
        // 静默不弹 toast（多数情况是未参赛），但保留 console 警告便于排查 401/网络中断
        if (window.console && console.warn) console.warn('refreshTournamentBadge failed', e);
    });
}

// 页面从后台切回前台时强制刷新一次红点，避免长时间挂后台跳过合法刷新
if (typeof document !== 'undefined' && document.addEventListener) {
    document.addEventListener('visibilitychange', function () {
        if (document.visibilityState === 'visible') {
            window._tournamentBadgeLastFetch = 0;
            refreshTournamentBadge(true);
        }
    });
}

async function loadPlayerInfo(force, detail) {
    var calledWithoutArgs = arguments.length === 0;
    if (force && typeof force === 'object') {
        force = !!force.force;
    }
    // 无参数调用通常来自用户动作成功后的资源/属性刷新；这类刷新不能被 2 秒节流吞掉，
    // 否则左侧属性面板会停留在旧值，直到手动刷新页面。
    if (calledWithoutArgs) force = true;
    var wantDetail = true;
    var now = Date.now();
    // 节流: 2秒内不重复请求(force 可跳过)
    if (_playerInfoPending) {
        if (force && !_playerInfoPendingForce) {
            var pendingBeforeForce = _playerInfoPending;
            try {
                await pendingBeforeForce;
            } catch (e) {
                // 旧的普通刷新失败也不能吞掉后续 fresh=1 强制刷新。
            } finally {
                if (_playerInfoPending === pendingBeforeForce) {
                    _playerInfoPending = null;
                    _playerInfoPendingDetail = false;
                    _playerInfoPendingForce = false;
                }
            }
            return loadPlayerInfo(true, wantDetail);
        }
        if (wantDetail && !_playerInfoPendingDetail) {
            return _playerInfoPending;
        }
        if (!force || _playerInfoPendingForce) {
            return _playerInfoPending;
        }
        return _playerInfoPending;
    }
    if (!force && (now - _playerInfoLastFetch) < _PLAYER_INFO_THROTTLE_MS) return;

    _playerInfoLastFetch = now;
    _playerInfoPendingDetail = wantDetail;
    _playerInfoPendingForce = !!force;
    var pending = _doLoadPlayerInfo(force, wantDetail);
    _playerInfoPending = pending;
    try {
        await pending;
    } finally {
        if (_playerInfoPending === pending) {
            _playerInfoPending = null;
            _playerInfoPendingDetail = false;
            _playerInfoPendingForce = false;
        }
    }
}

async function ensurePlayerInfoDetail() {
    if (window._lastPlayerData && window._playerInfoHasDetail) return;
    await loadPlayerInfo(true, true);
}

function schedulePlayerInfoDetailWarmup(delayMs) {
    if (window._playerInfoHasDetail || _playerInfoDetailWarmupTimer) return;
    var delay = (typeof delayMs === 'number' && delayMs >= 0) ? delayMs : 1200;
    _playerInfoDetailWarmupTimer = setTimeout(function() {
        _playerInfoDetailWarmupTimer = null;
        if (!window._playerInfoHasDetail) {
            loadPlayerInfo(false, true);
        }
    }, delay);
}

async function refreshPlayerInfoAfterDeferredRecovery(delayMs) {
    await loadPlayerInfo(true);
    var delay = (typeof delayMs === 'number' && delayMs >= 0) ? delayMs : 800;
    if (delay > 0) {
        setTimeout(function() {
            loadPlayerInfo(true);
        }, delay);
    }
}

function renderSpiritStatusSnapshot(p) {
    if (!p) return;
    var spirit = Math.max(0, Number(p.spirit) || 0);
    var maxSpirit = Math.max(0, Number(p.maxSpirit) || 0);
    var exact = spirit + '/' + maxSpirit;

    var msbSpirit = document.getElementById('msbSpirit');
    if (msbSpirit) {
        msbSpirit.textContent = exact;
        msbSpirit.title = exact;
    }

    var statSpirit = document.getElementById('statSpirit');
    if (statSpirit) {
        statSpirit.innerHTML = formatNumber(spirit) + '/' + formatNumber(maxSpirit);
        var spIcon = document.createElement('i');
        spIcon.textContent = ' ⓘ';
        spIcon.style.cursor = 'pointer';
        spIcon.style.fontStyle = 'normal';
        spIcon.style.color = 'var(--text-gold)';
        spIcon.style.fontSize = '11px';
        spIcon.onclick = function() { showSpiritModal(); };
        statSpirit.appendChild(spIcon);
    }
}

function applyExplorePlayerSnapshot(data, requestPlayerInfoSeq) {
    if (!data || data.remainingSpirit === undefined || data.remainingSpirit === null || !window._lastPlayerData) return;
    if (typeof requestPlayerInfoSeq === 'number' && _playerInfoAppliedSeq > requestPlayerInfoSeq) {
        setTimeout(function() { loadPlayerInfo(true); }, 80);
        return;
    }
    var remainingSpirit = parseInt(data.remainingSpirit, 10);
    if (!isFinite(remainingSpirit)) return;
    window._lastPlayerData.spirit = Math.max(0, remainingSpirit);
    renderSpiritStatusSnapshot(window._lastPlayerData);
}

function showStatBreakdownModal(title, statValue, breakdown, fallbackBonus) {
    var breakdownStr = '<div class="modal-feat-list" style="margin-left: 4px;">';
    var rootBaseOnly = !!(window._lastPlayerData && window._lastPlayerData.spiritRootName === '雷灵根');
    if (breakdown) {
        breakdownStr += '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--orange">◈</span><span>基础数值: <b style="color:var(--text-primary);">' + breakdown.base + '</b></span></div>';
        if (breakdown.equip > 0) breakdownStr += '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--jade">◈</span><span>装备法宝: <b style="color:var(--accent-jade)">+' + breakdown.equip + '</b></span></div>';
        if (breakdown.art > 0) breakdownStr += '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--blue">◈</span><span>功法秘籍: <b style="color:var(--accent-blue)">+' + breakdown.art + '</b></span></div>';
        if (breakdown.buff > 0) breakdownStr += '<div class="modal-feat-row"><span class="modal-feat-icon" style="color:var(--text-gold)">◈</span><span>特殊增幅: <b style="color:var(--text-gold)">+' + breakdown.buff + '</b></span></div>';
        if (breakdown.cultivation > 0) breakdownStr += '<div class="modal-feat-row"><span class="modal-feat-icon" style="color:var(--accent-cyan)">◈</span><span>修为底蕴: <b style="color:var(--accent-cyan)">+' + breakdown.cultivation + '</b></span></div>';
        if (breakdown.petMult > 0) breakdownStr += '<div class="modal-feat-row"><span class="modal-feat-icon" style="color:#FFB6C1">◈</span><span>灵宠加成: <b style="color:#FFB6C1">+' + (breakdown.petMult * 100).toFixed(0) + '%</b></span></div>';
        if (breakdown.rootMult > 0) breakdownStr += '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--purple">◈</span><span>' + (rootBaseOnly ? '灵根基础加成' : '天赋异禀') + ': <b style="color:var(--text-purple)">+' + (breakdown.rootMult * 100).toFixed(0) + '%</b></span></div>';
        if (breakdown.rootMult < 0) breakdownStr += '<div class="modal-feat-row"><span class="modal-feat-icon" style="color:var(--text-danger)">◈</span><span>' + (rootBaseOnly ? '灵根基础代价' : '灵根代价') + ': <b style="color:var(--text-danger)">' + (breakdown.rootMult * 100).toFixed(0) + '%</b></span></div>';
        if (breakdown.buffMult > 0) breakdownStr += '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--jade">◈</span><span>涅槃丹增幅: <b style="color:var(--accent-jade)">+' + (breakdown.buffMult * 100).toFixed(0) + '%</b></span></div>';
        if (breakdown.originPenaltyMult > 0) breakdownStr += '<div class="modal-feat-row"><span class="modal-feat-icon" style="color:var(--text-danger)">◈</span><span>本源受损: <b style="color:var(--text-danger)">-' + (breakdown.originPenaltyMult * 100).toFixed(0) + '%</b></span></div>';
    } else {
        var baseStat = statValue - (fallbackBonus || 0);
        breakdownStr += '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--orange">◈</span><span>基础数值: <b style="color:var(--text-primary);">' + baseStat + '</b></span></div>';
        if (fallbackBonus > 0) breakdownStr += '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--jade">◈</span><span>外物增益: <b style="color:var(--accent-jade)">+' + fallbackBonus + '</b></span></div>';
    }
    breakdownStr += '</div>';

    var html = '<div class="modal-header-deco">' + 
        '<div class="modal-header-deco__subtitle">' + title + '感知</div>' +
        '<div class="modal-header-deco__value" style="margin-bottom: 4px;">' +
        '<span class="modal-header-deco__num" style="color:var(--text-gold);">' + statValue + '</span>' +
        '</div>' +
        '<div style="font-size:12px; color:var(--text-muted);">道友当前由各项造化叠加后的最终力量。</div>' +
        '</div>' + 
        
        '<div class="modal-body-padded">' +
        '<div class="modal-info-card modal-info-card--jade" style="margin-bottom:12px;">' +
        '<div class="modal-info-card__title modal-info-card__title--jade">✦ 属性构成</div>' +
        breakdownStr + 
        '</div>' +
        '<div class="modal-btn-row" style="padding: 0; margin-top: 16px;">' +
        '<button class="modal-btn modal-btn--outline" style="width:100%;" onclick="closeModal()">我已知晓</button>' +
        '</div>' +
        '</div>';

    showModal(html, 'modal-overlay--top ui-scrollable-modal');
}

function hasMeaningfulStatBreakdown(breakdown, fallbackBonus, cultivationBonus) {
    if (breakdown && typeof breakdown === 'object') {
        var keys = ['equip', 'art', 'buff', 'cultivation', 'rootMult', 'petMult', 'buffMult', 'originPenaltyMult'];
        for (var i = 0; i < keys.length; i++) {
            var value = Number(breakdown[keys[i]] || 0);
            if (Math.abs(value) > 0.000001) return true;
        }
        if (Number(breakdown.total || 0) !== Number(breakdown.base || 0)) return true;
    }
    return Number(fallbackBonus || 0) !== 0 || Number(cultivationBonus || 0) !== 0;
}

async function _doLoadPlayerInfo(force, detail) {
    var mySeq = ++_playerInfoSeq;
    var requestStartedAt = Date.now();
    var url = '/api/player/info';
    var params = [];
    if (force) params.push('fresh=1');
    params.push('detail=1');
    if (params.length) url += '?' + params.join('&');
    var res = await api.get(url);
    // 过期响应（有更新的请求已应用）直接丢弃，防止旧数据覆盖新数据——合道+陨落复活race
    if (mySeq < _playerInfoAppliedSeq) return;
    if (res.code !== 200 || !res.data) {
        showToast(res.message || '加载角色信息失败');
        return;
    }
    _playerInfoAppliedSeq = mySeq;
    var previousPlayerData = window._lastPlayerData;
    var p = res.data;
    var areaChanged = !!(previousPlayerData && previousPlayerData.currentArea && previousPlayerData.currentArea !== p.currentArea);
    if (areaChanged) {
        window._npcPanelClosed = false;
    }
    window._lastPlayerData = p;
    window._playerInfoHasDetail = true;
    window._playerRealmStage = p.realmStage;
    try {
        localStorage.setItem('playerId', String(p.id));
        localStorage.setItem('playerName', p.name || '');
    } catch (e) {}

    // 同步跳过战斗偏好到本地(多终端同步，pending时跳过防闪回)
    if (p.isSkipCombat !== undefined && !window._skipCombatPending) {
        localStorage.setItem('skip_combat', p.isSkipCombat ? 'true' : 'false');
        var toggle = document.getElementById('skipCombatToggle');
        if (toggle) toggle.checked = p.isSkipCombat;
    }

    // 同步跑马灯偏好到本地(多终端同步，pending时跳过防闪回)
    if (p.isMarqueeEnabled !== undefined && !window._marqueePending) {
        _marqueeEnabled = p.isMarqueeEnabled;
        localStorage.setItem('lv_marquee', p.isMarqueeEnabled ? 'on' : 'off');
        var marqueeToggle = document.getElementById('marqueeToggle');
        if (marqueeToggle) marqueeToggle.checked = p.isMarqueeEnabled;
    }
    if (p.natalOverdriveEnabled !== undefined && !window._natalOverdrivePending) {
        updateNatalOverdriveUi(!!p.natalOverdriveEnabled);
    }
    if (p.adventureToggleDisabled !== undefined && !window._adventureTogglePending) {
        setAdventureToggleDisabledState(!!p.adventureToggleDisabled);
    }

    document.getElementById('headerPlayerName').textContent = p.name;
    document.getElementById('headerRealm').textContent = p.realmLevelName;

    // 游戏时间显示
    var gtEl = document.getElementById('headerGameTime');
    if (gtEl) {
        updateGameTimeDisplay();
    }

    var genderTag = p.gender && p.gender !== 'unknown'
        ? '<span class="stat-name-chip stat-name-chip--gender" title="性别已登记，可消耗仙缘重塑" onclick="event.stopPropagation();openGenderDialog();">' + escapeHtml(p.genderLabel || genderLabel(p.gender)) + '</span>'
        : '<span class="stat-name-chip stat-name-chip--empty" title="道侣同修前需先设置性别" onclick="event.stopPropagation();openGenderDialog();">未设性别</span>';
    var statusTag = '';
    if (p.isMeditating) {
        statusTag = '<span class="stat-name-chip stat-name-chip--meditating" title="闭关冥想中，暂不可护道接单">闭关冥想中</span>';
    } else if (p.isProtectorActive) {
        statusTag = '<span class="stat-name-chip stat-name-chip--protector" title="已在护道设置中开启接单">护道接单中</span>';
    }
    document.getElementById('statName').innerHTML = '<span class="stat-name-text">' + escapeHtml(p.name) + '</span>' + genderTag + statusTag;
    if (typeof DungeonModule !== 'undefined' && DungeonModule.updateMyProtectorStatus) {
        DungeonModule.updateMyProtectorStatus(p);
    }
    document.getElementById('statRealm').textContent = p.realmLevelName;
    if (p.breakthroughMaterials && p.breakthroughMaterials.length > 0) {
        var btIcon = document.createElement('i');
        btIcon.textContent = ' ⓘ';
        btIcon.style.cursor = 'pointer';
        btIcon.style.fontStyle = 'normal';
        btIcon.style.color = 'var(--text-gold)';
        btIcon.title = '查看下阶突破辅材';
        btIcon.onclick = function(e) {
            e.stopPropagation();
            showBreakthroughMaterialsModal();
        };
        document.getElementById('statRealm').appendChild(btIcon);
    }
    document.getElementById('statCultivation').textContent =
        formatNumber(p.cultivation) + ' / ' + formatNumber(p.cultivationNeeded);
    document.getElementById('statHp').innerHTML = formatCompactNumber(p.hp) + ' / ' + formatCompactNumber(p.maxHp);
    document.getElementById('statHp').title = p.hp + ' / ' + p.maxHp;
    if (p.hpBonus > 0) {
        var hpIcon = document.createElement('i');
        hpIcon.textContent = ' ⓘ';
        hpIcon.style.cursor = 'pointer';
        hpIcon.style.fontStyle = 'normal';
        hpIcon.style.color = 'var(--text-gold)';
        hpIcon.onclick = function(e) {
            e.stopPropagation();
            showHpModal();
        };
        document.getElementById('statHp').appendChild(hpIcon);
    }
    
    document.getElementById('statMp').innerHTML = formatCompactNumber(p.mp) + ' / ' + formatCompactNumber(p.maxMp);
    document.getElementById('statMp').title = p.mp + ' / ' + p.maxMp;
    var mpIcon = document.createElement('i');
    mpIcon.textContent = ' ⓘ';
    mpIcon.style.cursor = 'pointer';
    mpIcon.style.fontStyle = 'normal';
    mpIcon.style.color = 'var(--text-gold)';
    mpIcon.onclick = function(e) {
        e.stopPropagation();
        showMpModal();
    };
    document.getElementById('statMp').appendChild(mpIcon);

    // 锻体期无灵力，隐藏灵力行
    document.getElementById('statMp').parentElement.style.display = p.maxMp > 0 ? '' : 'none';
    // 疗伤、回灵按钮现已移入气血和灵力详情弹窗，通过点击标签触发
    document.getElementById('statAttack').innerHTML = formatNumber(p.attack);
    document.getElementById('statAttack').title = p.attack;
    if (hasMeaningfulStatBreakdown(p.atkBreakdown, p.attackBonus, p.cultivationAtkBonus)) {
        var aIcon = document.createElement('i');
        aIcon.textContent = ' ⓘ';
        aIcon.style.cursor = 'pointer';
        aIcon.style.fontStyle = 'normal';
        aIcon.style.color = 'var(--text-gold)';
        aIcon.onclick = function() {
            showStatBreakdownModal('攻击力', p.attack, p.atkBreakdown, p.attackBonus);
        };
        document.getElementById('statAttack').appendChild(aIcon);
    }

    document.getElementById('statDefense').innerHTML = formatNumber(p.defense);
    document.getElementById('statDefense').title = p.defense;
    if (hasMeaningfulStatBreakdown(p.defBreakdown, p.defenseBonus, p.cultivationDefBonus)) {
        var dIcon = document.createElement('i');
        dIcon.textContent = ' ⓘ';
        dIcon.style.cursor = 'pointer';
        dIcon.style.fontStyle = 'normal';
        dIcon.style.color = 'var(--text-gold)';
        dIcon.onclick = function() {
            showStatBreakdownModal('防御力', p.defense, p.defBreakdown, p.defenseBonus);
        };
        document.getElementById('statDefense').appendChild(dIcon);
    }
    var combatPowerEl = document.getElementById('statCombatPower');
    if (combatPowerEl) {
        var combatPower = Number(p.combatPower) || 0;
        combatPowerEl.innerHTML = (typeof formatCompactNumber === 'function' ? formatCompactNumber(combatPower) : formatNumber(combatPower)) +
            ' <i style="font-style:normal;font-size:11px;opacity:0.6;margin-left:2px;">ⓘ</i>';
        combatPowerEl.title = formatNumber(combatPower) + '，点击查看战力口径';
    }
    // 移动端状态栏同步
    function setMobileStatusNumber(el, current, maxValue, showExact) {
        if (!el) return;
        var exact = current + '/' + maxValue;
        var ratio = maxValue > 0 ? current / maxValue : 0;
        var pct = Math.max(0, Math.min(100, Math.round(ratio * 100)));
        el.textContent = showExact ? exact : (pct + '%');
        el.title = exact;
    }

    var msbHp = document.getElementById('msbHp');
    if (msbHp) {
        setMobileStatusNumber(msbHp, p.hp, p.maxHp);
        var hpItem = msbHp.closest('.msb-hp');
        if (hpItem) {
            hpItem.classList.remove('msb-warn', 'msb-danger');
            var hpRatio = p.maxHp > 0 ? p.hp / p.maxHp : 1;
            if (hpRatio <= 0.25) hpItem.classList.add('msb-danger');
            else if (hpRatio <= 0.5) hpItem.classList.add('msb-warn');
        }
    }
    var msbMp = document.getElementById('msbMp');
    setMobileStatusNumber(msbMp, p.mp, p.maxMp);
    var msbMpItem = document.getElementById('msbMpItem');
    if (msbMpItem) msbMpItem.style.display = p.maxMp > 0 ? '' : 'none';
    var msbBar = document.getElementById('mobileStatusBar');
    if (msbBar) msbBar.classList.toggle('mobile-status-bar--no-mp', !(p.maxMp > 0));
    var msbAtk = document.getElementById('msbAtk');
    if (msbAtk) {
        msbAtk.textContent = (typeof formatCompactNumber === 'function') ? formatCompactNumber(p.attack) : p.attack;
        msbAtk.title = p.attack;
    }
    var msbDef = document.getElementById('msbDef');
    if (msbDef) {
        msbDef.textContent = (typeof formatCompactNumber === 'function') ? formatCompactNumber(p.defense) : p.defense;
        msbDef.title = p.defense;
    }
    var msbSpirit = document.getElementById('msbSpirit');
    setMobileStatusNumber(msbSpirit, p.spirit, p.maxSpirit, true);
    var spiritText = formatNumber(p.spirit) + '/' + formatNumber(p.maxSpirit);
    if (window._spiritRegenTimer) {
        clearInterval(window._spiritRegenTimer);
        window._spiritRegenTimer = null;
    }
    document.getElementById('statSpirit').innerHTML = spiritText;
    // 神识详情图标
    var spIcon = document.createElement('i');
    spIcon.textContent = ' ⓘ';
    spIcon.style.cursor = 'pointer';
    spIcon.style.fontStyle = 'normal';
    spIcon.style.color = 'var(--text-gold)';
    spIcon.style.fontSize = '11px';
    spIcon.onclick = function() { showSpiritModal(); };
    document.getElementById('statSpirit').appendChild(spIcon);
    // 毒素状态
    function getToxinState(toxinRatio) {
        if (toxinRatio >= 0.75) return 'critical';
        if (toxinRatio >= 0.50) return 'high';
        if (toxinRatio >= 0.25) return 'mid';
        return 'low';
    }

    function clearToxinStateClass(el) {
        if (!el) return;
        el.classList.remove('toxin-state-low', 'toxin-state-mid', 'toxin-state-high', 'toxin-state-critical');
    }

    function setToxinStateClass(el, state) {
        clearToxinStateClass(el);
        if (el && state) el.classList.add('toxin-state-' + state);
    }

    var toxinRow = document.getElementById('statPillToxinRow');
    var toxinEl = document.getElementById('statPillToxin');
    var msbToxinItem = document.getElementById('msbToxinItem');
    var msbToxin = document.getElementById('msbToxin');
    var toxinValue = Number(p.pillToxin) || 0;
    var toxinMax = Number(p.maxPillToxin) || 0;
    var toxinRatio = toxinValue > 0 ? (toxinMax > 0 ? toxinValue / toxinMax : 1) : 0;
    var toxinPct = Math.floor(toxinRatio * 100);
    var toxinState = toxinValue > 0 ? getToxinState(toxinRatio) : '';
    if (toxinRow && toxinEl) {
        if (toxinValue > 0) {
            toxinRow.style.display = '';
            setToxinStateClass(toxinRow, toxinState);
            toxinEl.style.removeProperty('color');
            toxinEl.innerHTML = toxinValue + '/' + toxinMax + '(' + toxinPct + '%) <i style="font-style:normal;font-size:11px;opacity:0.6;margin-left:2px;">ⓘ</i>';
        } else {
            toxinRow.style.display = 'none';
            clearToxinStateClass(toxinRow);
            toxinEl.style.removeProperty('color');
        }
    }
    if (msbToxinItem && msbToxin) {
        if (toxinValue > 0) {
            msbToxinItem.classList.remove('hidden');
            setToxinStateClass(msbToxinItem, toxinState);
            msbToxin.textContent = toxinPct + '%';
            msbToxin.title = toxinValue + '/' + toxinMax;
        } else {
            msbToxinItem.classList.add('hidden');
            clearToxinStateClass(msbToxinItem);
        }
    }
    var originRow = document.getElementById('statOriginDamageRow');
    var originEl = document.getElementById('statOriginDamage');
    if (originRow && originEl) {
        var origin = p.originDamage || {};
        if (origin.hasDamage && origin.totalStacks > 0) {
            originRow.style.display = '';
            var originStacks = Number(origin.totalStacks) || 0;
            originEl.style.color = originStacks >= 8 ? 'var(--text-red)' : (originStacks >= 4 ? 'var(--accent-orange)' : 'var(--text-gold)');
            originEl.innerHTML = '裂损' + originStacks + '层 <i style="font-style:normal;font-size:11px;opacity:0.6;margin-left:2px;">ⓘ</i>';
        } else {
            originRow.style.display = 'none';
        }
    }
    document.getElementById('statLuck').innerHTML = formatCompactNumber(p.luck) + ' <i style="font-style:normal;font-size:12px;opacity:0.6;margin-left:2px;">ⓘ</i>';
    // 出战灵兽状态显示
    var petRow = document.getElementById('statPetRow');
    var petHpEl = document.getElementById('statPetHp');
    if (petRow && petHpEl) {
        var dp = p.deployedPet;
        if (dp && dp.maxHp > 0) {
            petRow.style.display = '';
            var petHpPct = Math.round(dp.hp / dp.maxHp * 100);
            var petMpPct = dp.maxMp > 0 ? Math.round(dp.mp / dp.maxMp * 100) : -1;
            var petColor = petHpPct < 30 ? 'var(--text-red)' : petHpPct < 60 ? 'var(--accent-orange)' : 'var(--text-jade)';
            var hpText = '<span style="color:' + petColor + '">' + escapeHtml(dp.name) + '</span> ' + petHpPct + '%';
            if (petMpPct >= 0) hpText += ' <span style="color:var(--text-muted);font-size:11px;">灵' + petMpPct + '%</span>';
            petHpEl.innerHTML = hpText;
        } else {
            petRow.style.display = 'none';
        }
    }
    if (window.CompanionPet &&
        typeof window.CompanionPet.setEnabled === 'function' &&
        typeof p.petCompanionVisible === 'boolean' &&
        !window._companionVisiblePending) {
        window.CompanionPet.setEnabled(p.petCompanionVisible);
    }
    if (window.CompanionPet) window.CompanionPet.syncPlayer(p);
    // 凶煞值显示（仅 >0 时显示）
    var infamyRow = document.getElementById('statInfamyRow');
    var infamyEl = document.getElementById('statInfamy');
    if (infamyRow && infamyEl) {
        if ((p.infamy || 0) > 0) {
            infamyRow.style.display = '';
            var inf = p.infamy;
            if (inf >= 100) infamyEl.style.color = 'var(--text-red)';
            else if (inf >= 50) infamyEl.style.color = 'var(--accent-orange)';
            else infamyEl.style.color = 'var(--text-gold)';
            infamyEl.innerHTML = inf + (p.isNotorious ? ' <span style="color:var(--text-red);font-size:11px;">[恶名通缉]</span>' : '');
        } else {
            infamyRow.style.display = 'none';
        }
    }
    // 寿元显示
    var lifespanEl = document.getElementById('statLifespan');
    if (lifespanEl) {
        var remaining = p.maxAge - p.age;
        var lifeText = formatCompactNumber(p.age) + '岁 / ' + (p.maxAge > 999999 ? '永生' : formatCompactNumber(p.maxAge) + '岁');
        var lifespanLossYears = Number(p.lifespanLossYears || 0);
        var hasLifespanLoss = lifespanLossYears > 0 && p.maxAge < 999999;
        if (remaining < p.maxAge * 0.2 && p.maxAge < 999999) {
            lifespanEl.style.color = 'var(--text-red)';
            lifeText += ' (寿元将尽!)';
        } else {
            lifespanEl.style.color = '';
        }
        lifespanEl.textContent = lifeText;
        lifespanEl.title = hasLifespanLoss ? '点击查看寿元折损详情' : '点击查看寿元详情';
        if (hasLifespanLoss) {
            var detailMark = document.createElement('span');
            detailMark.className = 'lifespan-detail-mark';
            detailMark.textContent = '!';
            detailMark.style.cssText = 'display:inline-flex;align-items:center;justify-content:center;width:14px;height:14px;margin-left:3px;border:1px solid currentColor;border-radius:50%;color:var(--text-gold);font-size:10px;line-height:1;vertical-align:1px;';
            detailMark.setAttribute('aria-hidden', 'true');
            lifespanEl.appendChild(document.createTextNode(' '));
            lifespanEl.appendChild(detailMark);
        }
    }
    // 虚空淬体丹显示
    var voidBodyRow = document.getElementById('statVoidBodyRow');
    var voidBodyEl = document.getElementById('statVoidBodyExpire');
    if (voidBodyRow && voidBodyEl) {
        if (p.voidBodyBuffExpire && p.voidBodyBuffExpire > Date.now()) {
            voidBodyRow.style.display = '';
            window._voidBodyExpire = p.voidBodyBuffExpire;
            
            // 立即更新一次文本
            var dRemain = Math.max(0, Math.floor((p.voidBodyBuffExpire - Date.now()) / 1000));
            var dh = Math.floor(dRemain / 3600);
            var dm = Math.floor((dRemain % 3600) / 60);
            var ds = dRemain % 60;
            var dText = '';
            if (dh > 0) dText += dh + '小时';
            if (dm > 0) dText += dm + '分';
            dText += ds + '秒';
            var iconHtml = ' <i style="font-style:normal;font-size:12px;opacity:0.8;color:inherit;">ⓘ</i>';
            voidBodyEl.innerHTML = dText + iconHtml;

            if (!window._voidBodyTimer) {
                window._voidBodyTimer = setInterval(function() {
                    var el = document.getElementById('statVoidBodyRow');
                    if (!el) { clearInterval(window._voidBodyTimer); window._voidBodyTimer = null; return; }
                    var remainSecs = Math.max(0, Math.floor((window._voidBodyExpire - Date.now()) / 1000));
                    if (remainSecs <= 0) {
                        el.style.display = 'none';
                        clearInterval(window._voidBodyTimer);
                        window._voidBodyTimer = null;
                        return;
                    }
                    var h = Math.floor(remainSecs / 3600);
                    var m = Math.floor((remainSecs % 3600) / 60);
                    var s = remainSecs % 60;
                    var text = '';
                    if (h > 0) text += h + '小时';
                    if (m > 0) text += m + '分';
                    text += s + '秒';
                    var expEl = document.getElementById('statVoidBodyExpire');
                    if (expEl) expEl.innerHTML = text + iconHtml;
                }, 1000);
            }
        } else {
            voidBodyRow.style.display = 'none';
            if (window._voidBodyTimer) {
                clearInterval(window._voidBodyTimer);
                window._voidBodyTimer = null;
            }
        }
    }
    // 五行通灵 buff 显示
    var fiveRootRow = document.getElementById('statFiveRootRow');
    var fiveRootEl = document.getElementById('statFiveRootExpire');
    if (fiveRootRow && fiveRootEl) {
        if (p.fiveRootBuffGrade > 0 && p.fiveRootBuffExpire && p.fiveRootBuffExpire > Date.now()) {
            fiveRootRow.style.display = '';
            window._fiveRootExpire = p.fiveRootBuffExpire;
            window._fiveRootGrade = p.fiveRootBuffGrade;
            var fr = Math.max(0, Math.floor((p.fiveRootBuffExpire - Date.now()) / 1000));
            var fh = Math.floor(fr / 3600);
            var fm = Math.floor((fr % 3600) / 60);
            var fs = fr % 60;
            var fText = '';
            if (fh > 0) fText += fh + '小时';
            if (fm > 0) fText += fm + '分';
            fText += fs + '秒';
            var iconHtml2 = ' <i style="font-style:normal;font-size:12px;opacity:0.8;color:inherit;">ⓘ</i>';
            var queueText = (p.fiveRootBuffQueueSize && p.fiveRootBuffQueueSize > 1) ? (' · ' + p.fiveRootBuffQueueSize + '段') : '';
            window._fiveRootQueueText = queueText;
            fiveRootEl.innerHTML = fText + queueText + iconHtml2;
            if (!window._fiveRootTimer) {
                window._fiveRootTimer = setInterval(function() {
                    var el = document.getElementById('statFiveRootRow');
                    if (!el) { clearInterval(window._fiveRootTimer); window._fiveRootTimer = null; return; }
                    var rs = Math.max(0, Math.floor((window._fiveRootExpire - Date.now()) / 1000));
                    if (rs <= 0) {
                        el.style.display = 'none';
                        clearInterval(window._fiveRootTimer);
                        window._fiveRootTimer = null;
                        return;
                    }
                    var hh = Math.floor(rs / 3600);
                    var mm = Math.floor((rs % 3600) / 60);
                    var ss = rs % 60;
                    var t = '';
                    if (hh > 0) t += hh + '小时';
                    if (mm > 0) t += mm + '分';
                    t += ss + '秒';
                    var ee = document.getElementById('statFiveRootExpire');
                    if (ee) ee.innerHTML = t + (window._fiveRootQueueText || '') + iconHtml2;
                }, 1000);
            }
        } else {
            fiveRootRow.style.display = 'none';
            if (window._fiveRootTimer) {
                clearInterval(window._fiveRootTimer);
                window._fiveRootTimer = null;
            }
        }
    }
    // 隐匿符状态显示
    var stealthRow = document.getElementById('statStealthRow');
    var stealthEl = document.getElementById('statStealthExpire');
    if (stealthRow && stealthEl) {
        if (p.isStealthed && p.stealthUntil && p.stealthUntil > Date.now()) {
            stealthRow.style.display = '';
            window._stealthExpire = p.stealthUntil;
            var renderStealth = function() {
                var remain = Math.max(0, Math.floor((window._stealthExpire - Date.now()) / 1000));
                if (remain <= 0) {
                    stealthRow.style.display = 'none';
                    if (window._stealthTimer) {
                        clearInterval(window._stealthTimer);
                        window._stealthTimer = null;
                    }
                    return;
                }
                stealthEl.innerHTML = formatCompactRemain(remain) +
                    ' <button class="btn-ink-soft" style="font-size:11px;padding:1px 6px;margin-left:6px;" onclick="cancelStealth()">解除</button>';
            };
            renderStealth();
            if (!window._stealthTimer) {
                window._stealthTimer = setInterval(renderStealth, 1000);
            }
        } else {
            stealthRow.style.display = 'none';
            if (window._stealthTimer) {
                clearInterval(window._stealthTimer);
                window._stealthTimer = null;
            }
        }
    }
    renderActiveBuffSummary(p);
    document.getElementById('statLowerStone').textContent = formatNumber(p.lowerStone);
    document.getElementById('statLowerStone').title = formatNumber(p.lowerStone);
    document.getElementById('statSkill').textContent = p.artName || '无';
    // 灵根显示
    var rootEl = document.getElementById('statSpiritRoot');
    rootEl.textContent = '';
    if (p.spiritRootName) {
        var span = document.createElement('span');
        span.style.color = p.spiritRootColor;
        span.textContent = p.spiritRootName;
        rootEl.appendChild(span);
        
        var infoIcon = document.createElement('i');
        infoIcon.innerHTML = ' ⓘ';
        infoIcon.style.fontStyle = 'normal';
        infoIcon.style.fontSize = '12px';
        infoIcon.style.opacity = '0.6';
        infoIcon.style.marginLeft = '2px';
        rootEl.appendChild(infoIcon);
    } else if (p.canAwaken) {
        rootEl.textContent = '可觉醒';
        rootEl.style.color = 'var(--text-gold)';
    } else {
        rootEl.textContent = '未觉醒';
    }
    document.getElementById('statArea').textContent = p.areaName || p.currentArea;
    var lyProjectionRow = document.getElementById('statLingyuanProjectionRow');
    var lyProjectionEl = document.getElementById('statLingyuanProjection');
    if (lyProjectionRow && lyProjectionEl) {
        if (p.realmStage === 9 && p.portal !== 'immortal') {
            lyProjectionRow.style.display = '';
            lyProjectionEl.innerHTML = '查看 <i style="font-style:normal;font-size:11px;opacity:0.7;">ⓘ</i>';
        } else {
            lyProjectionRow.style.display = 'none';
        }
    }
    // 求助/协助次数
    var helpCount = p.dailyHelpRequestCount || 0;
    var assistCount = p.dailyAssistCount || 0;
    var helpEl = document.getElementById('statDailyHelp');
    var assistEl = document.getElementById('statDailyAssist');
    if (helpEl) {
        if (helpCount < 0) {
            helpEl.innerHTML = '0/30 <span style="color:var(--text-gold);font-size:11px;">(+' + Math.abs(helpCount) + ')</span>';
        } else {
            helpEl.textContent = helpCount + '/30';
        }
    }
    if (assistEl) assistEl.textContent = assistCount + '/30';
    var exploreBtnLabel = document.getElementById('exploreBtnLabel');
    if (exploreBtnLabel) {
        var _mul = (typeof getExploreMultiplier === 'function') ? getExploreMultiplier() : 1;
        exploreBtnLabel.textContent = getExploreButtonLabel(p, _mul);
    }
    // 突破信息区(修为条下方)
    var btArea = document.getElementById('breakthroughArea');
    if (btArea) {
        btArea.classList.remove('bt-area--ready', 'bt-area--preview');
        if (p.breakthroughRate >= 0) {
            btArea.style.display = '';
            btArea.classList.add('bt-area--ready');
            btArea.innerHTML = '';
            // 只要满足突破条件，无论是否有材料都显示按钮
            var btn = document.createElement('button');
            btn.className = 'btn-action btn-breakthrough bt-area-btn';
            btn.onclick = handleBreakthrough;
            btn.textContent = '突破境界(' + p.breakthroughRate + '%)';
            if (p.breakthroughDetail) {
                var infoIcon = document.createElement('i');
                infoIcon.textContent = ' ⓘ';
                infoIcon.style.cursor = 'pointer';
                infoIcon.style.fontStyle = 'normal';
                infoIcon.title = '查看雷劫详情';
                infoIcon.style.color = 'gold';
                infoIcon.onclick = function(e) {
                    e.stopPropagation();
                    showDecoratedActionDialog({
                        subtitle: '雷劫成算详情',
                        bodyHtml:
                            '<div class="modal-info-card modal-info-card--jade" style="margin-top:0;">' +
                            '<div class="modal-info-card__title modal-info-card__title--jade">✦ 天机推演</div>' +
                            '<div style="font-size:14px;line-height:1.7;color:var(--text-color);text-align:left;">' +
                            sanitizeDetailHtml(p.breakthroughDetail) +
                            '</div>' +
                            '</div>',
                        actionsHtml: '<button class="modal-btn modal-btn--outline" onclick="closeModal()">关闭</button>'
                    });
                };
                btn.appendChild(infoIcon);
            }
            btArea.appendChild(btn);
            var luckBonusPct = getBreakthroughLuckBonusPercent(p);
            var compactHints = [];
            if (luckBonusPct > 0 && (parseInt(p.realmStage || 0, 10) || 0) > 0) {
                compactHints.push('气运 +' + formatBreakthroughPercent(luckBonusPct));
            }
            if (p.breakthroughCultivationClearWarning) {
                compactHints.push('有天劫警示');
            }
            if (p.breakthroughMaterials && p.breakthroughMaterials.length > 0) {
                compactHints.push('辅材 ' + p.breakthroughMaterials.length + ' 种');
            }
            if (compactHints.length > 0) {
                var summaryDiv = document.createElement('div');
                summaryDiv.className = 'bt-area-material';
                summaryDiv.style.fontSize = '11px';
                summaryDiv.style.marginTop = '4px';
                summaryDiv.style.lineHeight = '1.45';
                summaryDiv.style.color = 'var(--text-muted)';
                summaryDiv.textContent = compactHints.join(' · ');
                if (p.breakthroughMaterials && p.breakthroughMaterials.length > 0) {
                    var matBtn = document.createElement('button');
                    matBtn.type = 'button';
                    matBtn.textContent = '详情';
                    matBtn.style.cssText = 'margin-left:6px;border:0;background:transparent;color:var(--text-gold);font:inherit;text-decoration:underline;cursor:pointer;padding:0;';
                    matBtn.onclick = function(e) {
                        e.stopPropagation();
                        showBreakthroughMaterialsModal();
                    };
                    summaryDiv.appendChild(matBtn);
                }
                btArea.appendChild(summaryDiv);
            }
        } else {
            btArea.style.display = 'none';
            btArea.innerHTML = '';
            if (p.breakthroughDetail) {
                btArea.style.display = '';
                btArea.classList.add('bt-area--preview');
                var previewDiv = document.createElement('div');
                previewDiv.className = 'bt-area-material';
                previewDiv.style.fontSize = '12px';
                previewDiv.style.marginTop = '2px';
                var previewIcon = document.createElement('i');
                previewIcon.textContent = ' ⓘ';
                previewIcon.style.cursor = 'pointer';
                previewIcon.style.fontStyle = 'normal';
                previewIcon.style.color = 'var(--text-gold)';
                previewIcon.title = '查看下阶突破天材';
                previewIcon.onclick = function(e) {
                    e.stopPropagation();
                    showDecoratedActionDialog({
                        subtitle: '下阶突破天材预告',
                        bodyHtml:
                            '<div class="modal-info-card modal-info-card--jade" style="margin-top:0;">' +
                            '<div class="modal-info-card__title modal-info-card__title--jade">✦ 天机推演</div>' +
                            '<div style="font-size:14px;line-height:1.7;color:var(--text-color);text-align:left;">' +
                            sanitizeDetailHtml(p.breakthroughDetail) +
                            '</div>' +
                            '</div>',
                        actionsHtml: '<button class="modal-btn modal-btn--outline" onclick="closeModal()">关闭</button>'
                    });
                };
                previewDiv.appendChild(document.createTextNode('突破天材 '));
                previewDiv.appendChild(previewIcon);
                btArea.appendChild(previewDiv);
            }
        }
    }
    // 散修身份码显示 (仅角色面板)
    var idCodeEl = document.getElementById('statIdentityCode');
    if (p.isGuest && p.identityCode) {
        if (idCodeEl) {
            idCodeEl.textContent = p.identityCode;
            idCodeEl.parentElement.style.display = '';
        }
    } else {
        if (idCodeEl) idCodeEl.parentElement.style.display = 'none';
    }
    // 官职显示
    var courtEl = document.getElementById('statCourtTitle');
    if (courtEl) {
        if (p.courtTitle) {
            courtEl.textContent = p.courtTitle;
            courtEl.parentElement.style.display = '';
        } else {
            courtEl.parentElement.style.display = 'none';
        }
    }

    // 顶部/移动端入口按钮：神庭 ↔ 灵渊 ↔ 仙界（根据 portal 字段切换）
    window._currentPortal = p.portal || 'court';
    // 刷新移动端自定义导航
    if (typeof applyNavCustomConfig === 'function') applyNavCustomConfig();
    ['courtBtn', 'courtBtnMobile'].forEach(function(btnId) {
        var btn = document.getElementById(btnId);
        if (!btn) return;
        var badge = btn.querySelector('.court-task-badge');
        if (p.portal === 'immortal') {
            btn.firstChild.nodeValue = '仙界';
            btn.title = '仙界破界';
        } else if (p.portal === 'lingyuan') {
            btn.firstChild.nodeValue = '灵渊';
            btn.title = '叶天烬·灵渊议事厅';
        } else {
            btn.firstChild.nodeValue = '神庭';
            btn.title = '九霄神庭';
        }
        if (badge) btn.appendChild(badge);
    });
    if (typeof updateCourtTaskBadges === 'function') updateCourtTaskBadges();
    // 当前佩戴的称号(统一)
    var equippedTitleEl = document.getElementById('statEquippedTitle');
    if (equippedTitleEl) {
        if (p.equippedTitle && p.equippedTitle.name) {
            equippedTitleEl.textContent = p.equippedTitle.name;
            equippedTitleEl.style.color = p.equippedTitle.color || '#ffd166';
            equippedTitleEl.parentElement.style.display = '';
        } else {
            equippedTitleEl.parentElement.style.display = 'none';
        }
    }

    // 渡劫起号·自封仙号
    var divineRow = document.getElementById('statDivineTitleRow');
    var divineSetRow = document.getElementById('statDivineTitleSetRow');
    var divineEl = document.getElementById('statDivineTitle');
    if (divineRow && divineSetRow && divineEl) {
        if (p.divineTitle) {
            divineEl.textContent = p.divineTitle;
            divineRow.style.display = '';
            divineSetRow.style.display = 'none';
        } else if (p.canSetDivineTitle) {
            divineRow.style.display = 'none';
            divineSetRow.style.display = '';
        } else {
            divineRow.style.display = 'none';
            divineSetRow.style.display = 'none';
        }
    }

    // 仙缘点数显示
    var adPointsEl = document.getElementById('statAdPoints');
    if (adPointsEl) {
        if (p.isGuest) {
            adPointsEl.textContent = '散修不支持';
            adPointsEl.style.cursor = 'default';
            adPointsEl.style.textDecoration = 'none';
            adPointsEl.style.color = 'var(--text-muted)';
            adPointsEl.onclick = null;
        } else {
            var pts = p.adPoints || 0;
            adPointsEl.innerHTML = pts + ' <i style="font-style:normal;font-size:12px;opacity:0.6;margin-left:2px;">ⓘ</i>';
            adPointsEl.style.color = pts > 0 ? 'var(--text-gold)' : 'var(--text-muted)';
        }
    }

    // 修为进度条
    var progress = p.cultivationNeeded > 0
        ? Math.min(100, (p.cultivation / p.cultivationNeeded * 100))
        : 0;
    var progressTrunc = Math.floor(progress * 10) / 10;
    document.getElementById('cultivationProgress').style.width = progressTrunc + '%';
    document.getElementById('cultivationProgressText').textContent = progressTrunc.toFixed(1) + '%';

    // 冥想恢复
    if (p.isMeditating) {
        startMeditationUI();
        checkMeditationStatus();
    }

    // 死亡状态检测。复活成功前发起的旧请求可能晚到，不能用旧的“已陨落”状态重开遮罩。
    var staleDeathBeforeRevive = !!p.isDead && _reviveCompletedAt > 0 && requestStartedAt < _reviveCompletedAt;
    var staleAliveBeforeDeath = !p.isDead && _deathOverlayShownAt > 0 && requestStartedAt < _deathOverlayShownAt;
    playerIsGuest = !!p.isGuest;
    playerCanSelfRevive = !!p.canSelfRevive;
    if (staleDeathBeforeRevive) {
        var hasNewerDeathOverlay = _deathOverlayShownAt > _reviveCompletedAt;
        playerDead = hasNewerDeathOverlay;
        if (window._lastPlayerData) window._lastPlayerData.isDead = hasNewerDeathOverlay;
        if (!hasNewerDeathOverlay) {
            hideDeathOverlay();
            _reviveInProgress = false;
            setTimeout(function() { loadPlayerInfo(true); }, 80);
        }
    } else if (staleAliveBeforeDeath) {
        playerDead = true;
        if (window._lastPlayerData) window._lastPlayerData.isDead = true;
    } else if (p.isDead) {
        playerDead = true;
        showDeathOverlay(playerCanSelfRevive, p.reviveCost, p.adPoints);
    } else {
        playerDead = false;
        hideDeathOverlay();
        _reviveInProgress = false;
    }

    // 设置弹窗: 账号安全区域 (仅注册修士可见)
    var resetSection = document.getElementById('settingResetSection');
    var changeEmailSection = document.getElementById('settingChangeEmailSection');
    var currentEmailText = document.getElementById('settingCurrentEmailText');
    if (resetSection) {
        if (!p.isGuest && p.email) {
            resetSection.classList.remove('hidden');
            document.getElementById('settingResetEmail').value = p.email;
        } else {
            resetSection.classList.add('hidden');
        }
    }
    if (changeEmailSection) {
        if (!p.isGuest && p.email) {
            changeEmailSection.classList.remove('hidden');
            if (currentEmailText) currentEmailText.textContent = p.email;
        } else {
            changeEmailSection.classList.add('hidden');
            if (currentEmailText) currentEmailText.textContent = '';
        }
    }

    // 药田成熟红点
    var sectBadgeD = document.getElementById('sectBadgeDesktop');
    var sectBadgeM = document.getElementById('sectBadgeMobile');
    var sectGardenBadge = document.getElementById('sectGardenTabBadge');
    var hasOfficialSectBadge = p.hasMatureCrops;
    var hasPlayerSectFarmBadge = (p.playerSectFarmMatureCount || 0) > 0;
    var playerSectPendingApplications = p.playerSectPendingApplicationCount || 0;
    var playerSectPendingExchangeRequests = p.playerSectPendingExchangeRequestCount || 0;
    var playerSectBadgeCount = (p.playerSectFarmMatureCount || 0) + playerSectPendingApplications + playerSectPendingExchangeRequests;
    if (hasOfficialSectBadge) {
        if (sectBadgeD) { sectBadgeD.textContent = ''; sectBadgeD.classList.remove('hidden'); }
        if (sectBadgeM) { sectBadgeM.textContent = ''; sectBadgeM.classList.remove('hidden'); }
        if (sectGardenBadge) sectGardenBadge.classList.remove('hidden');
    } else if (hasPlayerSectFarmBadge || playerSectPendingApplications > 0 || playerSectPendingExchangeRequests > 0) {
        var sectBadgeText = playerSectBadgeCount > 9 ? '9+' : playerSectBadgeCount;
        if (sectBadgeD) { sectBadgeD.textContent = sectBadgeText; sectBadgeD.classList.remove('hidden'); }
        if (sectBadgeM) { sectBadgeM.textContent = sectBadgeText; sectBadgeM.classList.remove('hidden'); }
    } else {
        if (sectBadgeD) sectBadgeD.classList.add('hidden');
        if (sectBadgeM) sectBadgeM.classList.add('hidden');
        if (sectGardenBadge) sectGardenBadge.classList.add('hidden');
    }

    // 武道大会剩余挑战次数红点（独立节流，避免每次玩家信息刷新都打武道接口）
    refreshTournamentBadge();

    // 世界 Boss / NPC 面板切换逻辑
    var wpPanel = document.getElementById('worldBossPanel');
    var npcPanel = document.getElementById('npcPanel');
    var lPanel = document.getElementById('logPanel');
    var actionBar = document.querySelector('.action-bar');
    var meditBar = document.getElementById('meditationBar');
    if (p.currentArea === 'qingyun_rift') {
        if (actionBar) actionBar.classList.remove('hidden');

        if (window._wbShowingLogs) {
            if (lPanel) lPanel.classList.remove('hidden');
            if (wpPanel) wpPanel.classList.add('hidden');
            if (npcPanel) npcPanel.classList.add('hidden');
        } else {
            if (window._npcPanelClosed || currentPanel === 'dungeon') {
                if (lPanel) lPanel.classList.remove('hidden');
                if (wpPanel) wpPanel.classList.add('hidden');
                if (npcPanel) npcPanel.classList.add('hidden');
            } else {
                if (lPanel) lPanel.classList.add('hidden');
                loadRiftPanel();
            }
        }
    } else {
        if (lPanel) lPanel.classList.remove('hidden');
        if (actionBar) actionBar.classList.remove('hidden');
        if (wpPanel) wpPanel.classList.add('hidden');
        if (npcPanel) npcPanel.classList.add('hidden');
    }

    // 刷新储物容量显示（避免并发请求导致的过时数据覆盖）
    var capacityEl = document.getElementById('inventoryCapacityText');
    if (capacityEl && p.inventoryCapacity !== undefined) {
        var usedCap = p.inventoryUsed || 0;
        var maxCap = p.inventoryCapacity || 100;
        capacityEl.textContent = '(' + usedCap + ' / ' + maxCap + ')';
        if (usedCap >= maxCap * 0.9) {
            capacityEl.style.color = '#ff6b6b';
        } else {
            capacityEl.style.color = 'var(--text-gray)';
        }
    }

    if (typeof renderEquipGrid === 'function') {
        renderEquipGrid();
    }

    // 动态拉取副本信息渲染主界面预告条（首次加载、大境界变化或位置变化时重新拉取）
    if (typeof DungeonModule !== 'undefined' && DungeonModule.loadDungeonList) {
        if (areaChanged || !window._dungeonPreviewLoaded || window._dungeonPreviewLastStage !== p.realmStage) {
            window._dungeonPreviewLoaded = true;
            window._dungeonPreviewLastStage = p.realmStage;
            DungeonModule.loadDungeonList();
        }
    }
    // 动态更新求助弹窗数据
    if (!document.getElementById('assistDialog')?.classList.contains('hidden')) {
        renderAssistDailyCounts(p);
    }

    // 新手引导：首次登录自动弹出灵根觉醒
    if (p.canAwaken && !window._awakenPopupShown) {
        window._awakenPopupShown = true;
        setTimeout(function() {
            showSpiritRootModal();
        }, 800);
    }

    // 新手引导：当前任务对应按钮脉冲提示
    updateTutorialPulse();
}

