        if (bd.rootMult > 0) breakdownStr += '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--purple">◈</span><span>' + (rootBaseOnly ? '灵根基础加成' : '天赋异禀') + ': <b style="color:var(--text-purple)">+' + (bd.rootMult * 100).toFixed(0) + '%</b></span></div>';
        if (bd.rootMult < 0) breakdownStr += '<div class="modal-feat-row"><span class="modal-feat-icon" style="color:var(--text-danger)">◈</span><span>' + (rootBaseOnly ? '灵根基础代价' : '灵根代价') + ': <b style="color:var(--text-danger)">' + (bd.rootMult * 100).toFixed(0) + '%</b></span></div>';
