function appendAssistInviteCard(msg, cardId) {
    var myName = localStorage.getItem('playerName') || '';
    var rawContent = msg.content || '';
    var lines = rawContent.split('\n').filter(function(line) { return line && line.trim(); });
    var targetLine = lines[0] || rawContent;
    var rewardLine = lines[1] || '';
    var realmLine = lines[2] || '';
    var playerMatch = targetLine.match(/【([^】]+)】/);
    var monsterMatch = targetLine.match(/遭遇了可怕的\s+(.+?)，不敌求助/);
    var shareMatch = rewardLine.match(/悬赏\s+(\d+)%/);
    var realmMatch = realmLine.match(/妖兽境界:\s*(.+)/);
    var ownerName = playerMatch ? playerMatch[1] : '';
    var monsterName = monsterMatch ? monsterMatch[1] : '未知大妖';
    var sharePercent = shareMatch ? shareMatch[1] : '';
    var monsterRealm = realmMatch ? realmMatch[1].trim() : '';
    var isSelf = ownerName && ownerName === myName;

    var timeHtml = '';
    if (msg.ts) {
        var d = new Date(msg.ts);
        var hh = String(d.getHours()).padStart(2, '0');
        var mm = String(d.getMinutes()).padStart(2, '0');
        timeHtml = '<span class="chat-msg-time">' + hh + ':' + mm + '</span>';
    }

    var titleText = (ownerName ? '【' + ownerName + '】' : '某位道友') + '遭遇' + monsterName;
    var rewardText = sharePercent
        ? '悬赏 ' + sharePercent + '% 的修为与掉落'
        : (rewardLine || '高阶道友可前往相助');
    var realmHtml = monsterRealm
        ? '<span class="chat-recruit-info chat-assist-realm">' + escapeHtml(monsterRealm) + '</span>'
        : '';
    var actionHtml = isSelf
        ? '<span class="recruit-self-tag">[等待道友接令]</span>'
        : '<button class="btn-recruit-join" onclick="joinAssistCombat(' + msg.ownerId + ', \'' + (msg.areaId || '') + '\')">前往相助</button>';

    var html = timeHtml +
        '<div class="chat-recruit-card chat-assist-card">' +
            '<div class="chat-recruit-header">' +
                '<span class="chat-recruit-label">[悬赏求助]</span>' +
                '<span class="chat-recruit-name">' + escapeHtml((typeof window.formatFriendName === 'function' && msg.ownerId) ? window.formatFriendName(msg.ownerId, msg.name || '悬赏榜') : (msg.name || '悬赏榜')) + '</span>' +
            '</div>' +
            '<div class="chat-recruit-body">' +
                '<span class="chat-recruit-dungeon">' + escapeHtml(titleText) + '</span>' +
                realmHtml +
                '<span class="chat-recruit-info">' + escapeHtml(rewardText) + '</span>' +
            '</div>' +
            '<div class="chat-recruit-action">' + actionHtml + '</div>' +
        '</div>';

    var cid = cardId || (msg.type + ':' + (msg.ownerId || 0));
    appendMessageWithScrollProtect(html, 'chat-msg chat-msg-recruit chat-msg-assist chat-card-msg', cid);
}

