    var isAuction = msg.type === 'auction_listing';
    var label = isMarket ? '[坊市上架]' : (isAuction ? '[拍卖上架]' : '[传功上架]');
    var panelName = isMarket ? 'market' : (isAuction ? 'auction' : 'transmit');
