function findCachedInventoryItem(itemId) {
    var targetId = Number(itemId);
    return (_inventoryCache || []).find(function(i) { return Number(i.id) === targetId || Number(i.itemId) === targetId; }) || null;
}

function getCachedPillBatchKind(itemId) {
    var item = findCachedInventoryItem(itemId);
    if (!item) return null;
    return item.batchKind || getPillBatchKind(item.templateId);
}

function waitForExploreRequestIdle(timeoutMs) {
    var deadline = Date.now() + (timeoutMs || 5000);
    return new Promise(function(resolve) {
        function tick() {
            if (!_exploreRequestInFlight) {
                resolve(true);
                return;
            }
            if (Date.now() >= deadline) {
                resolve(false);
                return;
            }
            setTimeout(tick, 50);
        }
        tick();
    });
}

async function pauseAutoExploreForSpiritPillUse() {
    var wasAutoExploreRunning = !!_autoExploreRunning;
    if (wasAutoExploreRunning) {
        stopAutoExplore('服用神识丹药', false);
        if (_exploreRequestInFlight) {
            showToast('已停止自动探索，等待本次探索结算后服用神识丹药');
        }
    }
    if (!_exploreRequestInFlight) return true;
    var settled = await waitForExploreRequestIdle(5000);
    if (!settled) {
        showToast('本次探索仍在结算中，请稍后再服用神识丹药');
        return false;
    }
    return true;
}

async function useItem(itemId, force, quantity, useKind) {
    var pillKind = useKind || getCachedPillBatchKind(itemId);
    if (pillKind === 'heal_spirit') {
        var canUseSpiritPill = await pauseAutoExploreForSpiritPillUse();
        if (!canUseSpiritPill) return;
    }
    var reqData = { itemId: itemId };
    if (force) reqData.force = true;
    if (quantity && quantity > 1) reqData.quantity = quantity;
    var res = await api.post('/api/game/use-item', reqData);
    if (res.code === 200) {
        // 藏宝图触发 Boss 战斗时，返回 encounter 数据
        var isTreasureEncounter = res.data && (res.data.type === 'encounter' || res.data.status === 'encounter');
        var isProjectionStory = res.data && res.data.type === 'projection_story';
        if (isTreasureEncounter) {
            showToast('宝藏守卫: ' + res.data.treasureLevelName);
            _panelBeforeEncounter = (typeof currentPanel !== 'undefined') ? currentPanel : null;
            closeEncounterBlockingModals();
            if (_panelBeforeEncounter && typeof closePanel === 'function') {
                closePanel();
            }
            try {
                showEncounterPanel(
                    res.data.monsterName,
                    res.data.monsterRealmName,
                    res.data.monsterHp,
                    res.data.monsterAtk,
                    res.data.monsterDef,
                    res.data.areaName,
                    res.data.fleeChance,
                    res.data.spiritRootName,
                    res.data.spiritRootColor,
                    res.data.monsterId,
                    res.data.monsterRealmLevel,
                    null,
                    null,
                    res.data.monsterPower,
                    res.data.playerPower,
                    res.data.monsterAffixLabel,
                    res.data.monsterAffixName,
                    res.data.monsterAffixDesc,
                    res.data.playerStage,
                    res.data.rewardMultiplier
                );
                setTimeout(function() {
                    if (!_encounterActive) checkPendingEncounter();
                }, 200);
            } catch (e) {
                console.error('show treasure encounter failed:', e);
                checkPendingEncounter();
            }
        } else if (isProjectionStory) {
            showProjectionSoulStoryModal(res.data);
        } else {
            showToast(res.data || '使用成功');
        }
        var usedStealthTalisman = res.data && String(res.data).indexOf('隐匿') >= 0;
        invalidateDailyUsageCache();
        await loadPlayerInfo(true);
        await loadInventory({ preserveScroll: true });
        if (usedStealthTalisman && typeof loadMap === 'function') loadMap();
        loadGameLogs();
    } else {
        if (res.message && res.message.startsWith('force_required|')) {
            gameConfirm(res.message.split('|')[1], function() {
                useItem(itemId, true, quantity, pillKind);
            });
            return;
        }
        if (res.message && res.message.indexOf('未处理的遇敌') >= 0) {
            await checkPendingEncounter();
            return;
        }
        showToast(res.message || '使用失败');
    }
}

function getTalismanBatchKind(tid) {
    if (!tid) return null;
    if (tid.indexOf('talisman_stealth_') === 0) return 'stealth';
    if (tid === 'shenxing_talisman') return null;
    if (!/_\d+$/.test(tid)) return null;
    if (!/^(bp_)?talisman_/.test(tid)) return null;
    return 'combat';
}

function getPillBatchKind(tid) {
    if (!tid) return null;
    if (HEAL_HP_PILL_PREFIXES.some(function(prefix) { return tid.indexOf(prefix) === 0; })) return 'heal_hp';
    if (HEAL_MP_PILL_PREFIXES.some(function(prefix) { return tid.indexOf(prefix) === 0; }) &&
        !HEAL_MP_PILL_EXCLUDES.some(function(prefix) { return tid.indexOf(prefix) === 0; })) return 'heal_mp';
    if (HEAL_SP_PILL_PREFIXES.some(function(prefix) { return tid.indexOf(prefix) === 0; }) ||
        tid.indexOf('bp_pill_soulguard_') === 0) return 'heal_spirit';
    if (tid.indexOf('pill_antidote_') === 0) return 'antidote';
    if (/^pill_(cultivation|foundation|condensation|golden_core|nascent|divine)_\d+$/.test(tid)) return 'cultivation';
    if (/^pill_(tiger|iron_skin|rage|diamond)_\d+$/.test(tid)) return 'combat';
    if (tid.indexOf('bp_pill_void_body_') === 0) return 'void_body';
    if (tid.indexOf('bp_pill_rebirth_') === 0) return 'five_root';
    if (tid.indexOf('pill_meditation_') === 0) return 'meditation';
    if (/^pill_(lure|lure_mid|lure_high|repel|repel_mid|repel_high)_\d+$/.test(tid)) return 'encounter';
    if (/^pill_(yanshou|wanshou_guiyuan|taishang_life)_\d+$/.test(tid)) return 'lifespan';
    return null;
}

function getPillBatchHint(kind) {
    if (kind === 'heal_hp') return '按当前气血缺口自动停用，避免满血继续消耗';
    if (kind === 'heal_mp') return '按当前灵力缺口自动停用，避免满灵继续消耗';
    if (kind === 'heal_spirit') return '按当前神识缺口和每日 5 次上限自动停用';
    if (kind === 'antidote') return '按当前丹毒值自动停用，解清后不再消耗';
    if (kind === 'cultivation') return '受每日修为丹药 5 次上限限制';
    if (kind === 'combat') return '依次进入接下来 N 场战斗的增益队列';
    if (kind === 'void_body') return '虚空淬体丹按药力总时长排队，最多保留约 10 天';
    if (kind === 'meditation') return '清心丹会进入冥想次数队列，队列最多 50 次';
    if (kind === 'five_root') return '五行通灵药力会按时长排队，属性不重复叠加';
    if (kind === 'encounter') return '探索遇妖权重按药力次数叠加，同方向并入队列，反方向互相替换';
    if (kind === 'lifespan') return '按当前折损寿元自动停用，补满后不再继续消耗';
    return '按后端规则自动结算';
}

function getPillBatchLimit(kind, maxQty) {
    var BATCH_USE_CAP = 50;
    if (kind === 'void_body') return maxQty;
    if (kind === 'meditation' || kind === 'encounter' || kind === 'lifespan') return Math.min(maxQty, BATCH_USE_CAP);
    return Math.min(maxQty, 10);
}

function usePillBatch(itemId, maxQty, name, kind) {
    if (!maxQty || maxQty <= 1) { useItem(itemId); return; }
    if (!kind) { useItem(itemId); return; }
    var BATCH_USE_CAP = 50;
    var cap = getPillBatchLimit(kind, maxQty);
    var unit = kind === 'encounter' ? '件' : '颗';
    var actionLabel = kind === 'encounter' ? '批量使用' : '批量服用';
    var limitText = kind === 'void_body'
        ? '药力最多保留约 10 天，超出会自动停用'
        : (kind === 'meditation' ? '单次最多 ' + BATCH_USE_CAP + ' 颗，队列最多 50 次' :
            (kind === 'encounter' ? '单次最多 ' + BATCH_USE_CAP + ' 件' :
                (kind === 'lifespan' ? '单次最多 ' + BATCH_USE_CAP + ' 颗，补满寿元即停' : '单次最多 10 颗')));
    var msg = actionLabel + '【' + name + '】\n当前拥有: ' + maxQty + ' ' + unit + '（' + limitText + '）\n' +
        getPillBatchHint(kind) + '。\n请输入要使用的数量：';
    gamePrompt(msg, '1', function(val) {
        var qty = parseInt((val || '').replace(/[^0-9]/g, ''), 10);
        if (!qty || qty <= 0) { showToast('数量无效'); return; }
        if (qty > cap) qty = cap;
        useItem(itemId, false, qty, kind);
    }, null, false, dialogIntegerInputOptions(1, cap));
}

function useTreasureMapBatch(itemId, maxQty, name) {
    if (!maxQty || maxQty <= 1) { useItem(itemId); return; }
    var BATCH_USE_CAP = 50;
    var hasSpiritInfo = !!window._lastPlayerData;
    var spirit = hasSpiritInfo ? (Number(window._lastPlayerData.spirit) || 0) : 0;
    var spiritCost = hasSpiritInfo ? Math.max(1, Number(window._lastPlayerData.spiritCost) || 1) : 1;
    if (hasSpiritInfo && spirit < spiritCost) {
        showToast('神识不足，无法解读藏宝图（需' + spiritCost + '点）');
        return;
    }
    var spiritCap = hasSpiritInfo ? Math.floor(spirit / spiritCost) : BATCH_USE_CAP;
    var cap = Math.min(maxQty, BATCH_USE_CAP, spiritCap);
    var costText = hasSpiritInfo ? ('当前区域每张消耗 ' + spiritCost + ' 点神识') : '每张按当前区域探索神识消耗结算';
    var msg = '批量使用【' + name + '】\n当前拥有: ' + maxQty + ' 张（单次最多 ' + BATCH_USE_CAP + ' 张）\n' + costText + '，若中途惊动宝藏守卫会停止继续解图。\n请输入要使用的数量：';
    gamePrompt(msg, String(cap), function(val) {
        var qty = parseInt((val || '').replace(/[^0-9]/g, ''), 10);
        if (!qty || qty <= 0) { showToast('数量无效'); return; }
        if (qty > cap) qty = cap;
        useItem(itemId, false, qty);
    }, null, false, dialogIntegerInputOptions(1, cap));
}

function useEmperorJadeBatch(itemId, maxQty, name) {
    if (!maxQty || maxQty <= 1) { useItem(itemId); return; }
    var BATCH_USE_CAP = 50;
    var cap = Math.min(maxQty, BATCH_USE_CAP);
    var msg = '批量参悟【' + name + '】\n当前拥有: ' + maxQty + ' 卷（单次最多 ' + BATCH_USE_CAP + ' 卷）\n' +
        '会先领悟尚未掌握的灵渊高阶图纸，图纸尽悟后转化为灵渊材料。\n请输入要使用的数量：';
    gamePrompt(msg, String(cap), function(val) {
        var qty = parseInt((val || '').replace(/[^0-9]/g, ''), 10);
        if (!qty || qty <= 0) { showToast('数量无效'); return; }
        if (qty > cap) qty = cap;
        useItem(itemId, false, qty);
    }, null, false, dialogIntegerInputOptions(1, cap));
}

async function unequipIncarnationFromBag(slot) {
    // 白名单与后端 IncarnationService.slotColumn 同步，避免未来 type=ring 等扩展静默失败
    if (['weapon', 'armor', 'accessory'].indexOf(slot) < 0) {
        showToast('化身不支持该槽位');
        return;
    }
    var ok = await confirmAsync('确认从化身卸下该装备？卸下后将归回储物。');
    if (!ok) return;
    try {
        var res = await api.post('/api/game/incarnation/unequip', { slot: slot });
        if (res && res.code === 200) {
            showToast((res.data && res.data.message) || '已卸下');
            loadInventory();
            // 如果化身炼造面板还开着，顺手刷新
            var overlay = document.getElementById('alchemyOverlay');
            if (overlay && !overlay.classList.contains('hidden') && typeof openCrafting === 'function' && typeof currentCraftingTab !== 'undefined' && currentCraftingTab) {
                openCrafting(currentCraftingTab);
            }
        } else {
            showToast((res && res.message) || '卸下失败');
        }
    } catch (e) {
        showToast(e && e.message ? e.message : '卸下失败');
    }
}

function useTalismanBatch(itemId, maxQty, name, kind) {
    if (!maxQty || maxQty <= 1) { useItem(itemId); return; }
    // 与后端 UseReq.quantity 上限保持一致（50）
    var BATCH_USE_CAP = 50;
    var cap = Math.min(maxQty, BATCH_USE_CAP);
    var hint = kind === 'combat'
        ? '依次进入下 N 场战斗的增益队列'
        : '隐匿时长可叠加';
    var msg = '使用【' + name + '】\n当前拥有: ' + maxQty + ' 张（单次最多 ' + BATCH_USE_CAP + ' 张）\n' + hint + '，请输入要使用的数量：';
    gamePrompt(msg, '1', function(val) {
        var qty = parseInt((val || '').replace(/[^0-9]/g, ''), 10);
        if (!qty || qty <= 0) { showToast('数量无效'); return; }
        if (qty > cap) qty = cap;
        useItem(itemId, false, qty);
    }, null, false, dialogIntegerInputOptions(1, cap));
}

function calcWearDiscountPrice(sellPrice, wearRate) {
    if (!wearRate || wearRate <= 0) return sellPrice;
    return Math.max(1, Math.floor(sellPrice * (1.0 - (wearRate / 10000) * 0.5)));
}

var INSC_SELL_BONUS = [0, 50, 200, 800, 3000, 10000, 30000, 80000];
function calcInscriptionSellBonus(inscJson) {
    if (!inscJson) return 0;
    var list = parseInventoryInscriptions(inscJson);
    if (!Array.isArray(list)) return 0;
    var bonus = 0;
    for (var i = 0; i < list.length; i++) {
        var q = list[i] && list[i].quality;
        if (q && q > 0 && q < INSC_SELL_BONUS.length) bonus += INSC_SELL_BONUS[q];
    }
    return bonus;
}
function calcFinalSellPrice(sellPrice, wearRate, inscJson) {
    var base = Number(sellPrice) || 0;
    var bonus = calcInscriptionSellBonus(inscJson);
    return Math.max(1, calcWearDiscountPrice(base + bonus, wearRate));
}

function sellItem(itemId, sellPrice, itemName, itemQty, wearRate, itemRarity, itemType, itemTemplateId) {
    // 防止"上一笔出售刚成功-列表刷新-下面装备顶上来-误点"导致的连击误卖
    if (Date.now() < _sellLockUntil) {
        showToast('刚刚有出售操作，请稍候再点');
        return;
    }
    var wr = wearRate || 0;
    var inscJson = '';
    var cached = (_inventoryCache || []).find(function(x){ return x.id === itemId; });
    if (cached) inscJson = cached.inscriptionsJson || '';
    var inscBonus = calcInscriptionSellBonus(inscJson);
    var actualPrice = calcFinalSellPrice(sellPrice, wr, inscJson);
    var wearNote = '';
    if (wr > 0) {
        var wearPct = (wr / 100).toFixed(2);
        wearNote = '\n\n⚠ 装备破损 ' + wearPct + '%，已折损';
    }
    if (inscBonus > 0) {
        wearNote += (wearNote ? '\n' : '\n\n') + '✦ 铭文加价 +' + formatNumber(inscBonus) + ' 灵石';
    }

    // 传说装备防误卖：rarity == 5 走重型确认流程
    var fallbackRarity = parseInt(itemRarity, 10) || 0;
    var fallbackType = itemType || '';
    var fallbackTemplateId = itemTemplateId || '';
    var itemSnapshot = cached || {
        id: itemId,
        name: itemName,
        rarity: fallbackRarity,
        type: fallbackType,
        templateId: fallbackTemplateId,
        sellPrice: sellPrice,
        wearRate: wr,
        inscriptionsJson: inscJson
    };
    var rarity = cached ? (cached.rarity || 0) : fallbackRarity;
    var effectiveType = cached ? (cached.type || '') : fallbackType;
    var isEquipType = effectiveType === 'weapon' || effectiveType === 'armor' || effectiveType === 'accessory' || effectiveType === 'ring';
    var isLegendary = isEquipType && rarity >= 5;
    var tplId = cached ? (cached.templateId || '') : fallbackTemplateId;
    var isHighGradeStone = tplId.indexOf('wash_stone_') === 0 && rarity >= 4;

    if (isLegendary && (!itemQty || itemQty <= 1)) {
        confirmSellHighGradeEquip(itemId, itemName, actualPrice, itemSnapshot, wearNote);
        return;
    }

    // 史诗及以上洗炼石防误卖：额外确认
    if (isHighGradeStone) {
        var stoneRarityName = (typeof getRarityName === 'function') ? getRarityName(rarity) : '';
        if (!itemQty || itemQty <= 1) {
            gameConfirm('⚠ 确定出售 [' + itemName + '] 吗？\n\n这是珍贵材料，出售后不可找回！\n售价: ' + actualPrice + ' 灵石', function () {
                doSellItem(itemId, 1, { expectName: itemName, expectTemplateId: cached && cached.templateId });
            });
            return;
        }
        // 多个高阶洗炼石：先确认再选数量
        gameConfirm('⚠ 即将出售 [' + itemName + ']，这是珍贵材料！\n\n确定继续选择出售数量吗？', function () {
            _proceedSellWithQty(itemId, itemName, itemQty, actualPrice, cached, wearNote);
        });
        return;
    }

    if (!itemQty || itemQty <= 1) {
        var expectTpl = cached && cached.templateId;
        gameConfirm('确定出售 [' + itemName + '] 吗？\n\n出售价格: ' + actualPrice + ' 灵石' + wearNote, function () {
            doSellItem(itemId, 1, { expectName: itemName, expectTemplateId: expectTpl });
        });
        return;
    }
    _proceedSellWithQty(itemId, itemName, itemQty, actualPrice, cached, wearNote);
}

function _proceedSellWithQty(itemId, itemName, itemQty, actualPrice, cached, wearNote) {
    var bodyHtml = '<div class="modal-info-card">' +
        '<div class="modal-info-card__title">✦ 出售数量</div>' +
        '<div style="font-size:12px;color:var(--text-muted);line-height:1.7;">单价: <b style="color:var(--text-gold);">' + formatNumber(actualPrice) + '</b> 灵石 · 持有: ' + formatNumber(itemQty) + (wearNote ? ' · <span style="color:var(--accent-orange)">破损折价</span>' : '') + '</div>' +
        '<div class="absorb-qty-row">' +
        '<button class="modal-btn modal-btn--outline btn-absorb-qty" data-amt="1">1个</button>' +
        (itemQty >= 5 ? '<button class="modal-btn modal-btn--outline btn-absorb-qty" data-amt="5">5个</button>' : '') +
        (itemQty >= 10 ? '<button class="modal-btn modal-btn--outline btn-absorb-qty" data-amt="10">10个</button>' : '') +
        '<button class="modal-btn modal-btn--outline btn-absorb-qty" data-amt="' + itemQty + '">全部(' + itemQty + ')</button>' +
        '</div>' +
        '<div class="absorb-custom-row">' +
        '<input type="number" id="sellCustomAmt" class="absorb-custom-input" min="1" max="' + itemQty + '" placeholder="自定义数量" autocomplete="off">' +
        '<button class="btn-dialog btn-dialog-confirm" id="sellCustomBtn">出售</button>' +
        '</div>' +
        '<div class="absorb-dialog-sub" id="sellPreview" style="margin-top:6px;font-weight:bold">总价: ' + actualPrice + ' 灵石</div>' +
        '</div>';

    var overlay = showDecoratedActionDialog({
        subtitle: '出售 ' + escapeHtml(itemName),
        bodyHtml: bodyHtml,
        actionsHtml: '<button class="modal-btn modal-btn--outline modal-btn--full" id="sellCancelBtn">取消</button>'
    });

    var amtInput = document.getElementById('sellCustomAmt');
    amtInput.addEventListener('input', function () {
        var v = parseInt(amtInput.value) || 0;
        document.getElementById('sellPreview').textContent = '总价: ' + formatNumber(v * actualPrice) + ' 灵石';
    });

    function confirmSell(amt) {
        closeModal();
        gameConfirm('确定出售 ' + amt + ' 个 [' + itemName + '] 吗？\n\n总价: ' + formatNumber(amt * actualPrice) + ' 灵石' + wearNote, function () {
            doSellItem(itemId, amt);
        });
    }
    document.getElementById('sellCancelBtn').onclick = function () { closeModal(); };
    document.getElementById('sellCustomBtn').onclick = function () {
        var val = parseInt(amtInput.value);
        if (!val || val < 1) { showToast('请输入有效数量'); return; }
        if (val > itemQty) { showToast('超出持有数量'); return; }
        confirmSell(val);
    };
    overlay.querySelectorAll('.btn-absorb-qty').forEach(function (btn) {
        btn.onclick = function () {
            confirmSell(parseInt(this.getAttribute('data-amt')));
        };
    });
}

async function doSellItem(itemId, quantity, opts) {
    opts = opts || {};
    if (!checkSellItemFresh(itemId, opts.expectName)) return;
    var payload = { itemId: itemId, quantity: quantity };
    if (opts.confirmedHighGrade) payload.confirmedHighGrade = true;
    if (opts.expectTemplateId) payload.expectTemplateId = opts.expectTemplateId;
    var res = await api.post('/api/game/sell-item', payload);
    if (res.code === 200) {
        // 出售成功后短暂锁定，覆盖列表刷新前后窗口，防止下面装备顶上来被误卖
        _sellLockUntil = Date.now() + 1000;
        showToast(res.data || '出售成功');
        applyLocalInventorySell(itemId, quantity);
        loadPlayerInfo();
    } else {
        var message = res.message || '';
        if (message.indexOf('传说装备出售需经过二次确认') >= 0 && !opts.confirmedHighGrade) {
            var cached = (_inventoryCache || []).find(function(x) { return x.id === itemId; });
            if (cached) {
                confirmSellHighGradeEquip(
                    itemId,
                    cached.name,
                    calcFinalSellPrice(cached.sellPrice || 1, cached.wearRate || 0, cached.inscriptionsJson || ''),
                    cached,
                    ''
                );
                return;
            }
        }
        showToast(res.message || '出售失败');
    }
}

function applyLocalInventorySell(itemId, quantity) {
    var qty = Math.max(1, parseInt(quantity, 10) || 1);
    var changed = false;
    _inventoryCache = (_inventoryCache || []).reduce(function(list, item) {
        if (item.id !== itemId) {
            list.push(item);
            return list;
        }
        changed = true;
        var remain = (parseInt(item.quantity, 10) || 1) - qty;
        if (remain > 0) {
            var nextItem = Object.assign({}, item, { quantity: remain });
            list.push(nextItem);
        }
        return list;
    }, []);
    if (!changed) return;
    var listEl = document.getElementById('inventoryList');
    if (listEl) renderCurrentInventoryFilter({ preserveScroll: true });
}

/** 出售前 stale 检查：要求 itemId 仍在缓存且名字一致；不一致则强制刷新并阻止本次出售 */
function checkSellItemFresh(itemId, expectName) {
    var cached = (_inventoryCache || []).find(function(x) { return x.id === itemId; });
    if (!cached) {
        showToast('储物已变化，已为你刷新列表，请重新确认再出售');
        loadInventory();
        return false;
    }
    if (expectName && cached.name !== expectName) {
        showToast('物品信息已变化（' + expectName + ' → ' + cached.name + '），请重新选择');
        loadInventory();
        return false;
    }
    return true;
}

function getFreshInventoryItemForAction(itemId, expectName, actionName) {
    var cached = (_inventoryCache || []).find(function(x) { return x.id === itemId; });
    if (!cached) {
        showToast('储物已变化，已为你刷新列表，请重新确认再' + actionName);
        loadInventory();
        return null;
    }
    if (expectName && cached.name !== expectName) {
        showToast('物品信息已变化（' + expectName + ' → ' + cached.name + '），请重新选择');
        loadInventory();
        return null;
    }
    return cached;
}

function applyLocalInventoryDiscard(itemId, quantity) {
    var qty = Math.max(1, parseInt(quantity, 10) || 1);
    var changed = false;
    _inventoryCache = (_inventoryCache || []).reduce(function(list, item) {
        if (item.id !== itemId) {
            list.push(item);
            return list;
        }
        changed = true;
        var remain = (parseInt(item.quantity, 10) || 1) - qty;
        if (remain > 0) list.push(Object.assign({}, item, { quantity: remain }));
        return list;
    }, []);
    if (!changed) return;
    var listEl = document.getElementById('inventoryList');
    if (listEl) renderCurrentInventoryFilter({ preserveScroll: true });
}

function discardItem(itemId, itemName, itemQty, templateId) {
    var cached = getFreshInventoryItemForAction(itemId, itemName, '丢弃');
    if (!cached) return;
    if (!isDiscardableInventoryItem(cached)) {
        showToast('该物品当前不可丢弃');
        loadInventory();
        return;
    }
    var maxQty = Math.max(1, parseInt(cached.quantity || itemQty || 1, 10) || 1);
    var safeName = cached.name || itemName || '物品';
    var safeTemplateId = cached.templateId || templateId || '';

    function submitDiscard(qty) {
        qty = Math.max(1, Math.min(maxQty, parseInt(qty, 10) || 1));
        var confirmHtml =
            '<p>确定丢弃 <strong style="color:var(--text-gold);">' + escapeHtml(safeName) + ' x' + qty + '</strong>？</p>' +
            '<p style="font-size:12px;color:var(--text-muted);line-height:1.7;">丢弃后不会返还灵石或材料，也无法找回。已锁定、穿戴、冻结或本命物品不会被允许丢弃。</p>';
        gameConfirm(confirmHtml, async function() {
            var res = await api.post('/api/game/discard-item', {
                itemId: itemId,
                quantity: qty,
                expectTemplateId: safeTemplateId
            });
            if (res && res.code === 200 && res.data) {
                var discardedQty = parseInt(res.data.quantity || qty, 10) || qty;
                showToast('已丢弃 ' + (res.data.name || safeName) + ' x' + discardedQty);
                applyLocalInventoryDiscard(itemId, discardedQty);
                loadPlayerInfo();
            } else {
                showToast((res && res.message) || '丢弃失败');
                loadInventory();
            }
        }, null, true);
    }

    if (maxQty > 1) {
        gamePrompt(
            '丢弃【' + safeName + '】\n当前拥有: ' + maxQty + '\n请输入要丢弃的数量：',
            String(maxQty),
            function(val) {
                var qty = parseInt((val || '').replace(/[^0-9]/g, ''), 10);
                if (!qty || qty <= 0) { showToast('数量无效'); return; }
                submitDiscard(qty);
            },
            null,
            false,
            dialogIntegerInputOptions(1, maxQty)
        );
    } else {
        submitDiscard(1);
    }
}

/** 高级装备出售：强警示弹窗，确认后带 confirmedHighGrade 标记 */
function confirmSellHighGradeEquip(itemId, itemName, actualPrice, cached, wearNote) {
    var refineLabel = (cached && cached.refineLevel > 0) ? ' +' + cached.refineLevel : '';
    var natalLabel = (cached && cached.isNatal) ? ' [本命]' : '';
    var rarityName = (typeof getRarityName === 'function') ? getRarityName(cached ? cached.rarity : 0) : '';
    var rarityColor = (typeof getRarityColor === 'function') ? getRarityColor(cached ? cached.rarity : 0) : '#fff';
    var confirmName = itemName + refineLabel + natalLabel;

    var bodyHtml =
        '<div class="modal-info-card modal-info-card--danger">' +
            '<div class="modal-info-card__title modal-info-card__title--danger">✦ 传说装备出售确认</div>' +
            '<div style="font-size:12px;color:var(--text-secondary);">为防止误卖，请仔细核对：</div>' +
            '<div style="margin-top:6px;color:' + rarityColor + ';font-size:14px;font-weight:bold;">' +
                escapeHtml(confirmName) +
            '</div>' +
            '<div style="margin-top:3px;color:var(--text-secondary);font-size:12px;">品质：' + escapeHtml(rarityName || '高阶') + '</div>' +
            '<div style="margin-top:4px;color:var(--text-warning);">售价: ' + actualPrice + ' 灵石' + (wearNote ? wearNote.replace(/\n/g, '<br>') : '') + '</div>' +
        '</div>' +
        '<label style="display:flex;align-items:center;gap:8px;font-size:12px;color:var(--text-secondary);margin-top:12px;">' +
            '<input type="checkbox" id="sellHighGradeConfirmCheck">' +
            '<span>确认出售这件传说装备</span>' +
        '</label>';

    showDecoratedActionDialog({
        subtitle: '高阶装备出售',
        bodyHtml: bodyHtml,
        actionsHtml:
            '<button class="modal-btn modal-btn--outline" id="sellHighGradeCancelBtn">取消</button>' +
            '<button class="modal-btn modal-btn--danger" id="sellHighGradeConfirmBtn" disabled>确认出售</button>'
    });
    setTimeout(function() {
        var check = document.getElementById('sellHighGradeConfirmCheck');
        if (check) check.focus();
    }, 50);

    document.getElementById('sellHighGradeCancelBtn').onclick = function() { closeModal(); };
    var confirmCheck = document.getElementById('sellHighGradeConfirmCheck');
    var confirmBtn = document.getElementById('sellHighGradeConfirmBtn');
    if (confirmCheck && confirmBtn) {
        confirmCheck.onchange = function() {
            confirmBtn.disabled = !confirmCheck.checked;
        };
    }
    document.getElementById('sellHighGradeConfirmBtn').onclick = async function() {
        if (!confirmCheck || !confirmCheck.checked) {
            showToast('请先勾选确认出售');
            return;
        }
        closeModal();
        // 再次强制 loadInventory 后跑 stale 检查，确认无误才发请求
        try { await loadInventory(); } catch (e) {}
        doSellItem(itemId, 1, {
            confirmedHighGrade: true,
            expectName: itemName,
            expectTemplateId: cached && cached.templateId
        });
    };
}

function toggleInvBatchMenu() {
    var dd = document.getElementById('invBatchDropdown');
    if (dd) dd.classList.toggle('open');
}

function closeInvBatchMenu() {
    var dd = document.getElementById('invBatchDropdown');
    if (dd) dd.classList.remove('open');
}

document.addEventListener('click', function(e) {
    var menu = document.getElementById('invBatchMenu');
    if (menu && !menu.contains(e.target)) {
        closeInvBatchMenu();
    }
});

function showBatchLockDialog() {
    var rarityNames = ['', '普通', '优良', '稀有', '史诗', '传说'];
    var rarityColors = ['', 'var(--rarity-1)', 'var(--rarity-2)', 'var(--rarity-3)', 'var(--rarity-4)', 'var(--rarity-5)'];
    var counts = [0, 0, 0, 0, 0, 0];
    var unlockedCounts = [0, 0, 0, 0, 0, 0];

    if (_inventoryCache) {
        _inventoryCache.forEach(function(item) {
            if (item.type === 'weapon' || item.type === 'armor' || item.type === 'accessory' || item.type === 'ring' || item.type === 'talisman') {
                if (!item.isEquipped && !item.isIncarnationEquipped && item.rarity >= 1 && item.rarity <= 5) {
                    counts[item.rarity]++;
                    if (!item.isLocked) unlockedCounts[item.rarity]++;
                }
            }
        });
    }

    var html = '<div class="modal-info-card modal-info-card--jade" style="margin-top:0;">' +
        '<div class="modal-info-card__title modal-info-card__title--jade">✦ 锁定范围</div>' +
        '<div style="font-size:12px;color:var(--text-muted);line-height:1.7;text-align:center;margin-bottom:12px;">选择品质，将锁定该品质及以上的所有<b>未装备、未锁定</b>装备</div>' +
        '<div class="modal-action-list">';

    var options = [
        { rarity: 4, label: '史诗及以上' },
        { rarity: 5, label: '传说' }
    ];

    options.forEach(function(opt) {
        var cumCount = 0;
        for (var r = opt.rarity; r <= 5; r++) cumCount += unlockedCounts[r];
        var disabled = cumCount === 0;
        html += '<button class="modal-action-btn modal-action-btn--gold" style="' +
            (disabled ? 'opacity:0.4;cursor:not-allowed;' : '') + '" ' +
            (disabled ? 'disabled' : 'onclick="executeBatchLock(' + opt.rarity + ')"') + '>' +
            '<span>锁定 <b style="color:' + rarityColors[opt.rarity] + ';">' + opt.label + '</b></span>' +
            '<span style="font-size:12px;color:var(--text-muted);">' + cumCount + ' 件</span>' +
            '</button>';
    });

    html += '</div>' +
        '<div style="font-size:11px;color:var(--text-muted);text-align:center;margin-top:10px;">※ 已装备的装备不会被锁定</div>' +
        '</div>';
    showDecoratedActionDialog({
        subtitle: '一键加锁',
        descHtml: '批量保护高品质装备，避免误售或误分解。',
        bodyHtml: html,
        actionsHtml: '<button class="modal-btn modal-btn--outline" onclick="closeModal()">取消</button>'
    });
}

async function executeBatchLock(minRarity) {
    closeModal();
    var rarityNames = ['', '普通', '优良', '稀有', '史诗', '传说'];
    var label = minRarity === 5 ? '传说' : '史诗及以上';
    gameConfirm('确定批量锁定所有 [' + label + '] 品质的未装备、未锁定装备吗？', async function() {
        showToast('批量加锁中...');
        try {
            var res = await api.post('/api/game/lock-batch', { minRarity: minRarity });
            if (res.code === 200 && res.data) {
                showToast('成功锁定 ' + res.data.count + ' 件装备!');
                loadInventory();
            } else {
                showToast(res.message || '批量加锁失败');
            }
        } catch(e) {
            showToast('批量加锁请求异常');
        }
    });
}

async function toggleItemLock(itemId) {
    try {
        var res = await api.post('/api/game/toggle-item-lock', { itemId: itemId });
        if (res.code === 200) {
            showToast(res.data ? '物品已锁定' : '物品已解锁');
            loadInventory();
        } else {
            showToast(res.message || '操作失败');
        }
    } catch (e) {
        showToast('网络错误');
    }
}

// ===== 装备修复系统 =====
async function showRepairPanel(itemId) {
    var res = await api.get('/api/game/equipment/wear-info?itemId=' + itemId);
    if (res.code !== 200 || !res.data) {
        showToast(res.message || '无法获取破损信息');
        return;
    }
    var info = res.data;

    var wearColor = info.wearPercent >= 50 ? 'var(--text-red)' : info.wearPercent >= 25 ? 'var(--accent-orange)' : 'var(--accent-gold)';
    var statLoss = ((1.0 - info.statMultiplier) * 100).toFixed(2);

    var html = '<div class="modal-header-deco">' +
        '<div class="modal-header-deco__subtitle">装备破损感知</div>' +
        '<div class="modal-header-deco__value" style="margin-bottom: 4px;">' +
        '<span class="modal-header-deco__num" style="color:' + wearColor + ';">' + info.wearPercent.toFixed(2) + '%</span>' +
        '<span class="modal-header-deco__unit" style="font-size:18px;">/</span>' +
        '<span class="modal-header-deco__num modal-header-deco__num--muted" style="font-size:24px;">100%</span>' +
        '</div>' +
        '<div style="font-size:12px; color:var(--text-muted);">' + escapeHtml(info.itemName) + ' 磨损程度，修复后可恢复全部属性。</div>' +
        '</div>' +

        '<div class="modal-body-padded">' +
        '<div class="modal-info-card modal-info-card--jade">' +
        '<div class="modal-info-card__title modal-info-card__title--jade">✦ 磨损详情</div>' +
        '<div class="modal-feat-list" style="margin-left: 4px;">' +
        '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--orange">◈</span><span>破损程度: <b style="color:' + wearColor + ';">' + info.wearPercent.toFixed(2) + '%</b></span></div>' +
        '<div class="modal-feat-row"><span class="modal-feat-icon" style="color:var(--text-red)">◈</span><span>属性衰减: <b style="color:var(--text-red)">-' + statLoss + '%</b></span></div>' +
        '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--jade">◈</span><span>修复费用: <b style="color:var(--accent-gold)">' + info.repairCost + ' 灵石</b></span></div>' +
        '</div>' +
        '</div>' +

        '<div class="modal-info-card" style="margin-top: 16px;">' +
        '<div class="modal-info-card__title">✦ 灵石修复</div>' +
        '<div class="modal-action-list">' +
        '<button class="modal-action-btn modal-action-btn--orange" id="doRepairBtn" style="height:40px; padding:0 16px; display:flex; justify-content:center;">' +
        '<span style="text-align:center; font-weight:bold; color:var(--accent-orange);">消耗 ' + info.repairCost + ' 灵石修复</span>' +
        '</button>' +
        '</div>' +
        '</div>' +
        '</div>';

    showModal(html, 'modal-overlay--top ui-scrollable-modal');

    document.getElementById('doRepairBtn').onclick = async function() {
        this.disabled = true;
        this.innerHTML = '<span style="text-align:center; font-weight:bold; color:var(--text-secondary);">修复中...</span>';
        try {
            var rr = await api.post('/api/game/equipment/repair', { playerItemId: itemId });
            if (rr.code === 200 && rr.data && rr.data.success) {
                showToast(rr.data.message || '修复成功');
                closeModal();
                loadEquipGridSummary(true);
                loadInventory();
            } else {
                showToast((rr.data && rr.data.message) || rr.message || '修复失败');
                this.disabled = false;
                this.innerHTML = '<span style="text-align:center; font-weight:bold; color:var(--accent-orange);">消耗 ' + info.repairCost + ' 灵石修复</span>';
            }
        } catch (e) {
            showToast('网络错误');
            this.disabled = false;
            this.innerHTML = '<span style="text-align:center; font-weight:bold; color:var(--accent-orange);">消耗 ' + info.repairCost + ' 灵石修复</span>';
        }
    };
}

// ===== 祭炼系统 =====
async function showRefinePanel(itemId) {
    var res = await api.get('/api/game/refine/info?itemId=' + itemId);
    if (res.code !== 200 || !res.data) {
        showToast(res.message || '无法获取祭炼信息');
        return;
    }
    var info = res.data;
    try {
        await refreshInventoryCache();
    } catch (e) { /* 使用现有缓存兜底 */ }

    var progressPct = 0;
    var expText = info.refineExp + '';
    if (info.nextLevelExp > 0) {
        progressPct = Math.min(100, (info.refineExp / info.nextLevelExp * 100)).toFixed(1);
        expText = info.refineExp + ' / ' + info.nextLevelExp;
    } else {
        progressPct = 100;
        expText = '已满级';
    }

    var natalHtml = info.isNatal ? '<div class="refine-natal-tag">[本命法宝]</div>' : '';
    var failureBonus = Number(info.failureBonusPercent || 0);
    var failureBonusHtml = failureBonus > 0
        ? ' <span style="color:var(--text-gold);">含失败补偿+' + failureBonus + '%</span>'
        : '';
    var bindHtml = info.bindState === 'natal' ? '本命' : info.bindState === 'bound' ? '已认主' : '未认主';
    var unbindNatalActionHtml = info.isNatal
        ? '<button class="modal-btn modal-btn--danger" id="refineUnbindNatalBtn">解除本命</button>'
        : '';

    var bodyHtml = '<div class="modal-info-card modal-info-card--jade">' +
        '<div class="refine-panel">' +
        '<div class="refine-title">' + escapeHtml(info.itemName) + ' ' + natalHtml + '</div>' +
        '<div class="refine-level">祭炼等级: <strong>' + info.refineLevel + '</strong> / ' + info.maxRefineLevel + ' 级</div>' +
        '<div class="refine-bonus">属性加成: <strong>+' + info.bonusPercent.toFixed(1) + '%</strong></div>' +
        (info.isNatal ? '<div class="refine-bonus">本命共鸣: <strong>+' + info.natalBonusPercent.toFixed(2) + '%</strong> (经验 ' + info.natalExp + ' / 50000)</div>' : '') +
        '<div class="refine-rate">成功率: <strong' + (info.successRate < 100 ? ' class="refine-rate-warn"' : '') + '>' + info.successRate + '%</strong>' + failureBonusHtml + (info.successRate < 100 ? ' (失败仅保留30%经验，下次+20%)' : '') + '</div>' +
        '<div class="refine-cost">消耗: <span>修为 ' + info.costCultivation + '</span> | <span>灵力 ' + info.costMp + '</span> | <span>神识 ' + info.costSpirit + '</span></div>' +
        '<div class="refine-exp-bar" style="display:flex;">' +
        '<div class="refine-exp-fill" style="width:' + progressPct + '%; border-radius: 4px 0 0 4px;"></div>' +
        '<div id="refineExpPreview" class="refine-exp-preview" style="width:0%;"></div>' +
        '</div>' +
        '<div class="refine-exp-text" id="refineExpText">' + expText + '</div>' +
        '<div class="refine-bind">状态: ' + bindHtml + '</div>' +
        '<div class="refine-feed-section">' +
        '<div class="refine-feed-title" style="display:flex; justify-content:space-between; align-items:center;">' +
        '<span>选择投喂材料 (装备/妖核/天精矿)</span>' +
        '<button class="btn-primary" style="padding: 2px 8px; font-size: 12px; height: auto; border-radius: 4px;" id="refineSelectAllBtn">一键选择</button>' +
        '</div>' +
        '<div id="refineFeedList" class="refine-feed-list"></div>' +
        '<div id="refineFeedSummary" class="refine-feed-summary" style="display:none;"></div>' +
        '</div>' +
        '</div>' +
        '</div>';

    showDecoratedActionDialog({
        subtitle: '装备祭炼',
        bodyHtml: bodyHtml,
        actionsHtml:
            '<button class="modal-btn modal-btn--outline" id="refineCancelBtn">关闭</button>' +
            unbindNatalActionHtml +
            '<button class="modal-btn modal-btn--gold" id="doRefineBtn">祭炼</button>'
    });

    // 经验值映射(与后端 RefineConfig.FEED_EXP 一致)
    var REFINE_FEED_EXP_EQUIP = { 1: 50, 2: 100, 3: 250, 4: 600, 5: 1500 };
    var REFINE_FEED_EXP_MAT = { beast_core_low: 30, beast_core_mid: 80, beast_core_high: 200, ore_tianjing: 300 };
    // 旧装备祭炼经验继承比例(与后端 RefineConfig.FEED_EQUIP_CARRYOVER_RATIO 一致)
    var REFINE_FEED_CARRYOVER_RATIO = 0.50;

    function getFeedCarryover(f) {
        var isEquipType = f.type === 'weapon' || f.type === 'armor' || f.type === 'accessory' || f.type === 'ring';
        if (!isEquipType) return 0;
        var old = f.refineExp || 0;
        return Math.floor(old * REFINE_FEED_CARRYOVER_RATIO);
    }

    function getFeedExp(f) {
        var isEquipType = f.type === 'weapon' || f.type === 'armor' || f.type === 'accessory' || f.type === 'ring';
        if (isEquipType) return (REFINE_FEED_EXP_EQUIP[f.rarity] || 50) * f.quantity + getFeedCarryover(f);
        return (REFINE_FEED_EXP_MAT[f.templateId] || 0) * f.quantity;
    }

    function getFeedExpPerUnit(f) {
        var isEquipType = f.type === 'weapon' || f.type === 'armor' || f.type === 'accessory' || f.type === 'ring';
        if (isEquipType) return (REFINE_FEED_EXP_EQUIP[f.rarity] || 50) + getFeedCarryover(f);
        return REFINE_FEED_EXP_MAT[f.templateId] || 0;
    }

    // 渲染可投喂物品列表
    var feedList = document.getElementById('refineFeedList');
    var feedSummary = document.getElementById('refineFeedSummary');
    var feedables = (_inventoryCache || []).filter(function(i) {
        if (i.id === itemId) return false; // 不能吃自己
        if (i.isNatal) return false; // 本命不可投喂
        if (i.isEquipped) return false;
        if (i.isLocked) return false; // 已锁定不可投喂
        var isEquipType = i.type === 'weapon' || i.type === 'armor' || i.type === 'accessory' || i.type === 'ring';
        if (isEquipType && i.tradeCooldown && i.tradeCooldown > Date.now()) return false;
        var isFeedMat = i.templateId === 'beast_core_low' || i.templateId === 'beast_core_mid' ||
            i.templateId === 'beast_core_high' || i.templateId === 'ore_tianjing';
        return isEquipType || isFeedMat;
    });

    if (feedables.length === 0) {
        feedList.innerHTML = '<div class="refine-empty">储物中没有可投喂的材料</div>';
    } else {
        feedList.innerHTML = feedables.map(function(f) {
            var perUnit = getFeedExpPerUnit(f);
            var carryover = getFeedCarryover(f);
            var numInputHtml = f.quantity > 1 ? '<input type="number" class="refine-feed-num" id="feedNum_' + f.id + '" max="' + f.quantity + '" min="1" value="1" data-per-unit="' + perUnit + '" style="display:none;width:40px;margin:0 5px;background:var(--bg-lighter);color:var(--text-primary);border:1px solid var(--border-color);border-radius:2px">' : '';
            var expLabel = '+' + perUnit + ' exp' + (carryover > 0 ? ' <span style="color:#8fcf8f;font-size:11px;" title="旧装备已累积祭炼经验按50%继承">(内含+' + carryover + '继承)</span>' : '');
            
            return '<label class="refine-feed-item">' +
                '<input type="checkbox" value="' + f.id + '" class="refine-feed-cb" data-feed-exp="' + perUnit + '" data-rarity="' + f.rarity + '">' +
                '<span style="color:' + getRarityColor(f.rarity) + '">' + escapeHtml(f.name) + '</span>' +
                '<span class="refine-feed-qty">(持有:x' + f.quantity + ')</span>' +
                numInputHtml +
                '<span class="refine-feed-exp" id="feedExp_' + f.id + '">' + expLabel + '</span>' +
                '</label>';
        }).join('');

        function updateTotal() {
            var total = 0;
            feedList.querySelectorAll('.refine-feed-cb:checked').forEach(function(cb) {
                total += parseInt(cb.getAttribute('data-feed-exp')) || 0;
            });
            if (total > 0) {
                feedSummary.style.display = '';
                var capExp = info.maxLevelExp || info.nextLevelExp || 0;
                var remainingRoom = Math.max(0, capExp - (info.refineExp || 0));
                var discardExp = remainingRoom > 0 ? Math.max(0, total - remainingRoom) : 0;
                var discardText = discardExp > 0
                    ? ' <span style="color:var(--text-red);">超出当前境界祭炼上限的 ' + discardExp + ' exp 将被舍弃</span>'
                    : '';
                feedSummary.innerHTML = '已选材料合计: <strong style="color:var(--text-gold)">+' + total + ' exp</strong>' + discardText;
            } else {
                feedSummary.style.display = 'none';
            }
            
            // 更新进度条预览
            var maxExp = info.nextLevelExp || 1;
            var currentExp = info.refineExp || 0;
            if (info.nextLevelExp > 0) {
                var previewAddPct = Math.min(100 - progressPct, (total / maxExp * 100)).toFixed(1);
                var previewEl = document.getElementById('refineExpPreview');
                var textEl = document.getElementById('refineExpText');
                if (previewEl) {
                    previewEl.style.width = previewAddPct + '%';
                }
                if (textEl) {
                    if (total > 0) {
                        textEl.innerHTML = currentExp + ' <span style="color:#8fcf8f">+' + total + '</span> / ' + maxExp;
                    } else {
                        textEl.innerHTML = expText;
                    }
                }
            }
        }

        // 勾选变动时更新经验汇总
        feedList.addEventListener('change', function(e) {
            if (e.target.classList.contains('refine-feed-cb')) {
                 var label = e.target.closest('label');
                 var input = label ? label.querySelector('.refine-feed-num') : null;
                 if (input) {
                     input.style.display = e.target.checked ? 'inline-block' : 'none';
                 }
                 updateTotal();
            }
        });
        
        feedList.addEventListener('input', function(e) {
            if (e.target.classList.contains('refine-feed-num')) {
                var val = parseInt(e.target.value) || 1;
                var max = parseInt(e.target.getAttribute('max')) || 1;
                if (val > max) { val = max; e.target.value = max; }
                if (val < 1) { val = 1; e.target.value = 1; }
                var perUnit = parseInt(e.target.getAttribute('data-per-unit')) || 0;
                var totalExp = perUnit * val;
                
                var label = e.target.closest('label');
                var cb = label.querySelector('.refine-feed-cb');
                var expSpan = label.querySelector('.refine-feed-exp');
                
                cb.setAttribute('data-feed-exp', totalExp);
                expSpan.innerHTML = '+' + totalExp + ' exp';
                
                updateTotal();
            }
        });
    }

    document.getElementById('refineCancelBtn').onclick = function() {
        closeModal();
    };

    var refineUnbindNatalBtn = document.getElementById('refineUnbindNatalBtn');
    if (refineUnbindNatalBtn) {
        refineUnbindNatalBtn.onclick = function () {
            unbindNatal();
        };
    }
    
    var selectAllBtn = document.getElementById('refineSelectAllBtn');
    if (selectAllBtn) {
        selectAllBtn.onclick = function() {
            var anyChanged = false;
            // 1. 设置数量为最大值（跳过传说品质）
            if (feedList) {
                feedList.querySelectorAll('.refine-feed-num').forEach(function(input) {
                    var label = input.closest('label');
                    var cb = label ? label.querySelector('.refine-feed-cb') : null;
                    if (cb && parseInt(cb.getAttribute('data-rarity')) >= 5) return;
                    var max = parseInt(input.getAttribute('max')) || 1;
                    if (parseInt(input.value) !== max) {
                        input.value = max;
                        anyChanged = true;
                        var perUnit = parseInt(input.getAttribute('data-per-unit')) || 0;
                        var totalExp = perUnit * max;
                        if (label) {
                            var expSpan = label.querySelector('.refine-feed-exp');
                            if (cb && expSpan) {
                                cb.setAttribute('data-feed-exp', totalExp);
                                expSpan.innerHTML = '+' + totalExp + ' exp';
                            }
                        }
                    }
                });
                // 2. 勾选所有复选框（跳过传说品质）
                feedList.querySelectorAll('.refine-feed-cb').forEach(function(cb) {
                    if (parseInt(cb.getAttribute('data-rarity')) >= 5) return;
                    if (!cb.checked) {
                        cb.checked = true;
                        anyChanged = true;
                        var label = cb.closest('label');
                        var input = label ? label.querySelector('.refine-feed-num') : null;
                        if (input) input.style.display = 'inline-block';
                    }
                });
                if (anyChanged && typeof updateTotal === 'function') updateTotal();
            }
        };
    }
    document.getElementById('doRefineBtn').onclick = function() {
        var materials = [];
        var selectedExp = 0;
        feedList.querySelectorAll('.refine-feed-cb:checked').forEach(function(cb) {
            var id = parseInt(cb.value);
            var numInput = document.getElementById('feedNum_' + id);
            var qty = numInput ? (parseInt(numInput.value) || 1) : 1;
            selectedExp += parseInt(cb.getAttribute('data-feed-exp')) || 0;
            materials.push({ itemId: id, quantity: qty });
        });
        if (materials.length === 0) { showToast('请选择投喂材料'); return; }
        var capExp = info.maxLevelExp || info.nextLevelExp || 0;
        var remainingRoom = Math.max(0, capExp - (info.refineExp || 0));
        var discardExp = remainingRoom > 0 ? Math.max(0, selectedExp - remainingRoom) : 0;
        var submit = function() { doRefineFeed(itemId, materials); };
        if (discardExp > 0) {
            var msg = '<p>本次祭炼会超过当前境界祭炼上限。</p>' +
                '<p style="font-size:12px;color:var(--text-muted);">超出的 <b style="color:var(--text-red);">' + discardExp + ' exp</b> 将被舍弃，材料仍会正常消耗。</p>';
            if (typeof gameConfirm === 'function') {
                gameConfirm(msg, submit, null, true);
            } else if (window.confirm('本次祭炼将舍弃超出当前境界祭炼上限的 ' + discardExp + ' exp，是否继续？')) {
                submit();
            }
            return;
        }
        submit();
    };
}

async function doRefineFeed(targetItemId, materials) {
    var res = await api.post('/api/game/refine/feed', { targetItemId: targetItemId, materials: materials });
    if (res.code === 200 && res.data) {
        showToast(res.data.message || '祭炼完成');
        await loadInventory();
        loadPlayerInfo();
        if (targetItemId === -9000001 && typeof loadNatalArtifactSlot === 'function') {
            loadNatalArtifactSlot();
        }
        if (typeof refreshIncarnationStatusPanel === 'function') refreshIncarnationStatusPanel();
        
        // 重新打开祭炼面板显示最新状态
        showRefinePanel(targetItemId);
    } else {
        showToast(res.message || '祭炼失败');
    }
}

// ===== 本命法宝 =====
async function loadNatalArtifactSlot() {
    var el = document.getElementById('craftNatalArtifactSlot');
    if (!el && !document.getElementById('equipGridContainer') && !document.getElementById('craftAspectPanel')) return;
    if (_natalArtifactPending) return _natalArtifactPending;
    _natalArtifactPending = api.get('/api/game/natal/artifact').then(function (res) {
        if (res.code === 200 && res.data) {
            _natalArtifactCache = res.data;
            renderNatalArtifactSlot(res.data);
            renderEquipGrid();
            loadEquipGridSummary(true);
            if (typeof renderCraftAspectPanel === 'function') renderCraftAspectPanel();
            return res.data;
        }
        return _natalArtifactCache;
    }).catch(function () {
        if (el) el.innerHTML = '';
        return _natalArtifactCache;
    }).finally(function () {
        _natalArtifactPending = null;
    });
    return _natalArtifactPending;
}

function ensureNatalArtifactSlotLoaded() {
    var el = document.getElementById('craftNatalArtifactSlot');
    if (!el && !document.getElementById('equipGridContainer') && !document.getElementById('craftAspectPanel')) {
        return Promise.resolve(_natalArtifactCache);
    }
    if (_natalArtifactCache) {
        if (typeof renderNatalArtifactSlot === 'function') renderNatalArtifactSlot(_natalArtifactCache);
        return Promise.resolve(_natalArtifactCache);
    }
    return loadNatalArtifactSlot();
}

function getNatalSlotName(slot) {
    if (slot === 'armor') return '服饰';
    if (slot === 'accessory') return '法器';
    return '武器';
}

function formatNatalPercent(value) {
    var num = Number(value || 0);
    if (!isFinite(num) || num <= 0) return '0';
    var text = num >= 10 ? num.toFixed(1) : num.toFixed(2);
    return text.replace(/\.0+$/, '').replace(/(\.\d*?)0+$/, '$1').replace(/\.$/, '');
}

function getNatalDriveSpiritCost(info) {
    var p = window._lastPlayerData || {};
    var maxSpirit = Math.max(0, Number(p.maxSpirit || 0));
    var costPercent = Math.max(0, Number((info && info.driveCostPercent) || 0));
    if (!isFinite(maxSpirit) || maxSpirit <= 0 || !isFinite(costPercent) || costPercent <= 0) return 0;
    return Math.max(1, Math.ceil(maxSpirit * costPercent / 100));
}

function formatNatalDriveCostText(info) {
    var percentText = formatNatalPercent(info && info.driveCostPercent);
    var cost = getNatalDriveSpiritCost(info);
    if (cost <= 0) return '最大神识 ' + percentText + '%';
    var costText = typeof formatNumber === 'function' ? formatNumber(cost) : String(cost);
    return '最大神识 ' + percentText + '%（' + costText + ' 点）';
}

function ensureNatalDriveCostContext() {
    var p = window._lastPlayerData || {};
    if (Number(p.maxSpirit || 0) > 0 || typeof loadPlayerInfo !== 'function') {
        return Promise.resolve();
    }
    return loadPlayerInfo(true).catch(function () {});
}

async function ensureNatalArtifactInfo() {
    if (_natalArtifactCache) return _natalArtifactCache;
    return await loadNatalArtifactSlot();
}

function openNatalArtifactModal() {
    Promise.all([ensureNatalArtifactInfo(), ensureNatalDriveCostContext()]).then(function (values) {
        var info = values[0];
        if (!info || !info.exists) {
            createNatalArtifact();
            return;
        }
        var driveCostText = formatNatalDriveCostText(info);
        var driveRuleText = info.driveCostPercent > 0
            ? '当前攻击或生命成长池已超过传说装备数值上限，每场战斗需要消耗' + driveCostText + '催动超限属性。'
            : '当前攻击与生命成长池未超过传说装备数值上限，无需额外神识催动。';
        var natalDesc = (info.description || '').trim();
        var html = '<div class="modal-header-deco">'
            + '<div class="modal-header-deco__subtitle">本命法宝</div>'
            + '<div class="modal-header-deco__value" style="margin-bottom:4px;">'
            + '<span class="modal-header-deco__num" style="color:var(--text-gold);font-size:24px;">' + escapeHtml(info.name) + '</span>'
            + '</div>'
            + '<div style="font-size:12px;color:var(--text-muted);">' + escapeHtml(info.slotName || getNatalSlotName(info.slot)) + ' · ' + (info.isEquipped ? '已装备' : '储物中') + ' · 已吞噬 ' + (info.devourCount || 0) + ' 次</div>'
            + '</div>'
            + '<div class="modal-body-padded">'
            + '<div class="modal-info-card modal-info-card--jade">'
            + '<div class="modal-info-card__title modal-info-card__title--jade">✦ 法宝小字</div>'
            + '<div style="font-size:12px;color:var(--text-muted);line-height:1.7;">' + (natalDesc ? escapeHtml(natalDesc) : '<span style="opacity:.65;font-style:italic;">尚无解说，可让 AI 按名称与养炼状态填词。</span>') + '</div>'
            + '<div class="modal-btn-row" style="padding:0;margin-top:10px;">'
            + '<button class="modal-btn modal-btn--outline" onclick="showEditNatalArtifactDesc()">填词</button>'
            + '</div>'
            + '</div>'
            + '<div class="modal-info-card" style="margin-top:12px;">'
            + '<div class="modal-info-card__title">✦ 法宝说明</div>'
            + '<div style="font-size:12px;color:var(--text-muted);line-height:1.7;">本命法宝会放入储物袋，需手动装备到对应法相槽位后才生效；武器入主手、服饰入服饰、法器入法器，装备后会替换同槽普通装备。成长池记录吞噬累计属性；当前常驻属性按当前境界可用的同槽位传说锻造与秘传锻造装备逐项封顶，再叠加祭炼与共鸣。铭文加成单独生效，不参与成长池封顶、超限属性判定或消耗比例计算。攻击/生命成长池超出上限后可在战斗中消耗神识催动（超限属性），溢出的攻击和生命同时生效。攻击或生命最高溢出每超过上限 1%，每场战斗消耗 0.1% 最大神识。' + escapeHtml(driveRuleText) + '</div>'
            + '</div>'
            + '<div class="modal-info-card modal-info-card--jade" style="margin-top:12px;">'
            + '<div class="modal-info-card__title modal-info-card__title--jade">✦ 本命属性</div>'
            + '<div class="modal-feat-list">'
            + '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--jade">◈</span><span>成长池（吞噬累计）：<b>' + natalStatsText(info.baseStats) + '</b></span></div>'
            + '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--blue">◈</span><span>当前常驻（不含铭文）：<b>' + natalStatsText(info.cappedStats) + '</b></span></div>'
            + (natalStatsHasValue(info.inscriptionStats) ? '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--purple">◈</span><span>铭文加成：<b>' + natalStatsText(info.inscriptionStats) + '</b></span></div>' : '')
            + '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--orange">◈</span><span>当前封顶（境界上限）：<b>' + natalStatsText(info.capStats) + '</b></span></div>'
            + (info.driveCostPercent > 0 ? '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--orange">◈</span><span>超限属性：<b>攻+' + ((info.overflowStats && info.overflowStats.attack) || 0) + '</b>' + ((info.overflowStats && info.overflowStats.hp > 0) ? '，生命上限+' + info.overflowStats.hp : '') + '，每场战斗消耗' + escapeHtml(driveCostText) + '</span></div>' : '')
            + '<div style="font-size:11px;color:var(--text-muted);line-height:1.6;margin-top:4px;">某项吞噬后没有立刻提升，通常是本次材料不加该项，或该项已达到当前境界封顶。未生效的成长池仍会保留，后续境界封顶提高后再转为常驻。铭文只作为独立加成展示和生效，不会把本命法宝推入超限。</div>'
            + '</div></div>'
            + '<div class="modal-info-card" style="margin-top:12px;">'
            + '<div class="modal-info-card__title">✦ 吞噬材料</div>'
            + '<div style="font-size:12px;color:var(--text-muted);margin-bottom:8px;line-height:1.7;">吞噬一套' + escapeHtml(info.devourRecipeName || '当前境界同类型锻造') + '材料，可直接获得参照装备普通品质 <b style="color:var(--text-gold);">100%</b> 基础数值加成，无上限。吞噬需投入灵力，投入最大灵力 N% 则成功率 N%，100% 投入必定成功；失败只消耗灵力，不损失材料或装备。</div>'
            + renderNatalMaterials(info.devourMaterials)
            + '<div style="font-size:12px;color:var(--text-muted);margin-top:10px;line-height:1.7;">也可直接吞噬储物袋中的同类型装备，获得该装备模板的基础数值；祭炼、铭文、破损等后天状态不会计入。</div>'
            + '</div>'
            + '<div class="modal-btn-row" style="padding:0;margin-top:16px;">'
            + '<button class="modal-btn modal-btn--outline" onclick="renameNatalArtifact(' + jsAttr(info.name) + ')">改名</button>'
            + (info.isEquipped
                ? '<button class="modal-btn modal-btn--outline" onclick="closeModal();unequipNatalArtifact()">卸下</button>'
                : '<button class="modal-btn modal-btn--gold" onclick="closeModal();equipNatalArtifact()">装备</button>')
            + '<button class="modal-btn modal-btn--gold" onclick="closeModal();showRefinePanel(-9000001)">祭炼</button>'
            + '<button class="modal-btn modal-btn--gold" onclick="closeModal();showInscriptionPanel(-9000001)">铭文</button>'
            + '<button class="modal-btn modal-btn--gold" onclick="closeModal();devourNatalArtifact()">吞噬材料</button>'
            + '<button class="modal-btn modal-btn--gold" onclick="closeModal();openNatalDevourEquipmentPicker()">吞噬装备</button>'
            + '<button class="modal-btn modal-btn--danger" onclick="destroyNatalArtifact()">融毁</button>'
            + '</div></div>';
        showModal(html, 'modal-overlay--top ui-scrollable-modal');
    });
}

function natalStatsText(stats) {
    stats = stats || {};
    return '攻+' + (stats.attack || 0) + ' 防+' + (stats.defense || 0) + ' 血+' + (stats.hp || 0) + ' 神+' + (stats.spirit || 0);
}

function natalStatsHasValue(stats) {
    stats = stats || {};
    return !!((stats.attack || 0) || (stats.defense || 0) || (stats.hp || 0) || (stats.spirit || 0));
}

function renderNatalStatLine(title, stats) {
    stats = stats || {};
    return '<div class="natal-artifact-stats-line">'
        + '<span>' + escapeHtml(title) + '</span>'
        + '<b>攻+' + (stats.attack || 0)
        + ' 防+' + (stats.defense || 0)
        + ' 血+' + (stats.hp || 0)
        + ' 神+' + (stats.spirit || 0) + '</b>'
        + '</div>';
}

function renderNatalMaterials(materials) {
    if (!materials || materials.length === 0) return '';
    return '<div class="natal-artifact-materials">'
        + materials.map(function (m) {
            var ok = (m.have || 0) >= (m.need || 0);
            return '<span class="' + (ok ? 'ok' : 'lack') + '">' + escapeHtml(m.name) + ' ' + (m.have || 0) + '/' + (m.need || 0) + '</span>';
        }).join('')
        + '</div>';
}

function renderNatalOverdriveControl(info) {
    var enabled = window._lastPlayerData?.natalOverdriveEnabled === true;
    var hasOverdrive = info && info.driveCostPercent > 0;
    var hint = hasOverdrive
        ? '开启后战斗中可消耗神识催动超限属性；关闭后只保留常驻封顶属性。'
        : '当前攻击/生命未超过软上限；开启后若日后超限，会自动消耗神识催动超限属性。';
    return '<div class="natal-overdrive-row">'
        + '<div class="natal-overdrive-copy">'
        + '<b>本命法宝超限催动</b>'
        + '<span id="natalOverdriveStatusText">' + (enabled ? '已开启' : '已关闭') + ' · ' + escapeHtml(hint) + '</span>'
        + '</div>'
        + '<label class="toggle-switch natal-overdrive-switch" title="关闭后本命法宝仍提供常驻封顶属性，但不会消耗神识激发超出封顶的攻击/生命">'
        + '<input type="checkbox" id="natalOverdriveAspectToggle" onchange="toggleNatalOverdrive(this.checked)" ' + (enabled ? 'checked' : '') + '>'
        + '<span class="toggle-slider"></span>'
        + '</label>'
        + '</div>';
}

function renderNatalArtifactSlot(info) {
    var el = document.getElementById('craftNatalArtifactSlot');
    if (!el) return;
    var locked = (info.playerStage || 0) < (info.unlockStage || 3);
    if (!info.exists) {
        el.innerHTML = '<div class="equip-slot empty natal-artifact-card natal-artifact-card--empty">'
            + '<div class="natal-artifact-head">'
            + '<span class="equip-name-text empty-text">' + (locked ? '金丹期解锁' : '未凝练') + '</span>'
            + '<button class="panel-title-action natal-artifact-btn" ' + (locked ? 'disabled' : 'onclick="createNatalArtifact()"') + '>凝练</button>'
            + '</div>'
            + '<div class="natal-artifact-desc">' + (locked ? '境界不足' : '凝练后进入储物袋，需手动装备') + '</div>'
            + '</div>';
        return;
    }

    var driveText = info.driveCostPercent > 0
        ? '超限 ' + (info.overLimitPercent || 0) + '%，每场战斗消耗' + formatNatalDriveCostText(info) + '催动超限属性'
        : '未超出当前境界传说/秘传' + (info.slotName || getNatalSlotName(info.slot)) + '软上限';
    var statusText = (info.slotName || getNatalSlotName(info.slot)) + ' · ' + (info.isEquipped ? '已装备' : '储物中')
        + ' · 已吞噬 ' + (info.devourCount || 0) + ' 次 · ' + (info.stageName || '');
    var natalDesc = (info.description || '').trim();
    el.innerHTML = '<div class="equip-slot has-item rarity-5 natal-artifact-card">'
        + '<div class="natal-artifact-head">'
        + '<span class="equip-name-text" style="color:var(--rarity-5)">' + escapeHtml(info.name) + '</span>'
        + '<div class="natal-artifact-actions">'
        + '<button class="panel-title-action natal-artifact-btn" onclick="renameNatalArtifact(' + jsAttr(info.name) + ')">改名</button>'
        + '<button class="panel-title-action natal-artifact-btn" onclick="showEditNatalArtifactDesc()">填词</button>'
        + (info.isEquipped
            ? '<button class="panel-title-action natal-artifact-btn" onclick="unequipNatalArtifact()">卸下</button>'
            : '<button class="panel-title-action natal-artifact-btn" onclick="equipNatalArtifact()">装备</button>')
        + '<button class="panel-title-action panel-title-action--repair natal-artifact-btn" onclick="showRefinePanel(-9000001)">祭炼</button>'
        + '<button class="panel-title-action panel-title-action--repair natal-artifact-btn" onclick="showInscriptionPanel(-9000001)">铭文</button>'
        + '<button class="panel-title-action panel-title-action--repair natal-artifact-btn" onclick="devourNatalArtifact()">吞材料</button>'
        + '<button class="panel-title-action panel-title-action--repair natal-artifact-btn" onclick="openNatalDevourEquipmentPicker()">吞装备</button>'
        + '<button class="panel-title-action panel-title-action--danger natal-artifact-btn" onclick="destroyNatalArtifact()">融毁</button>'
        + '</div></div>'
        + '<div class="natal-artifact-desc">' + escapeHtml(statusText) + ' · ' + escapeHtml(driveText) + '</div>'
        + (natalDesc ? '<div class="natal-artifact-desc" style="color:var(--text-secondary);font-style:italic;">' + escapeHtml(natalDesc) + '</div>' : '')
        + '</div>'
        + '<div class="natal-artifact-detail">'
        + renderNatalOverdriveControl(info)
        + renderNatalStatLine('成长池', info.baseStats)
        + renderNatalStatLine('当前常驻', info.cappedStats)
        + (natalStatsHasValue(info.inscriptionStats) ? renderNatalStatLine('铭文加成', info.inscriptionStats) : '')
        + renderNatalStatLine('当前封顶', info.capStats)
        + (info.driveCostPercent > 0 ? renderNatalStatLine('超限属性', { attack: (info.overflowStats && info.overflowStats.attack) || 0, hp: (info.overflowStats && info.overflowStats.hp) || 0 }) : '')
        + '<div class="natal-artifact-cost-title">吞噬一套' + escapeHtml(info.devourRecipeName || '当前境界同类型锻造') + '材料，获得参照装备普通品质100%基础数值，无上限</div>'
        + '<div class="natal-artifact-cost-title">投入最大灵力 N% 即 N% 成功率，100% 投入必定成功；失败只扣灵力</div>'
        + '<div class="natal-artifact-cost-title">也可吞噬储物袋同类型装备，获得该装备模板基础数值</div>'
        + renderNatalMaterials(info.devourMaterials)
        + '</div>';
}

function createNatalArtifact() {
    _natalCreateSlot = 'weapon';
    var typeBtn = function (slot, label, desc) {
        return '<button class="modal-action-btn natal-type-btn" data-slot="' + slot + '" onclick="selectNatalCreateSlot(' + jsAttr(slot) + ')">'
            + '<span class="modal-action-btn__text"><b>' + label + '</b><small>' + desc + '</small></span></button>';
    };
    var html = '<div class="modal-header-deco">'
        + '<div class="modal-header-deco__subtitle">凝练本命法宝</div>'
        + '<div class="modal-header-deco__value" style="margin-bottom:4px;"><span class="modal-header-deco__num" style="color:var(--text-gold);font-size:24px;">择定器胚</span></div>'
        + '<div style="font-size:12px;color:var(--text-muted);">本命法宝凝练后进入储物袋，需手动装备进主手、服饰或法器槽。</div>'
        + '</div>'
        + '<div class="modal-body-padded">'
        + '<div class="modal-info-card">'
        + '<div class="modal-info-card__title">✦ 凝练说明</div>'
        + '<div style="font-size:12px;color:var(--text-muted);line-height:1.7;">选择类型后将决定可装备的法相槽位、后续吞噬材料与成长方向；凝练完成后会进入储物袋，需手动装备后才生效，装备时会替换同槽普通装备。每次吞噬当前境界可用的同槽位最强锻造材料，可获得参照装备普通品质100%基础数值加成；也可吞噬储物袋同类型装备，获得该装备模板基础数值加成，均无上限。吞噬按投入灵力计算成功率，投入最大灵力 N% 即 N% 成功率，100% 投入必定成功。攻击超过当前境界可用的同槽位最强传说装备数值上限后，每超出 1% 每场战斗消耗 0.1% 最大神识催动；铭文加成不计入封顶或超限判断。法宝名不可包含已有掉落或锻造装备名称。</div>'
        + '</div>'
        + '<div class="modal-info-card modal-info-card--jade" style="margin-top:12px;">'
        + '<div class="modal-info-card__title modal-info-card__title--jade">✦ 法宝类型</div>'
        + '<div class="modal-action-list natal-type-list">'
        + typeBtn('weapon', '武器', '吞噬当前境界最强武器材料')
        + typeBtn('armor', '服饰', '吞噬当前境界最强服饰材料')
        + typeBtn('accessory', '法器', '吞噬当前境界最强法器材料')
        + '</div></div>'
        + '<div class="modal-info-card" style="margin-top:12px;">'
        + '<div class="modal-info-card__title">✦ 法宝名</div>'
        + '<input id="natalCreateNameInput" class="modal-input" maxlength="12" value="本命法宝" style="width:100%;box-sizing:border-box;">'
        + '</div>'
        + '<div class="modal-btn-row" style="padding:0;margin-top:16px;">'
        + '<button class="modal-btn modal-btn--outline" onclick="closeModal()">取消</button>'
        + '<button class="modal-btn modal-btn--gold" onclick="submitCreateNatalArtifact()">凝练</button>'
        + '</div></div>';
    showModal(html, 'modal-overlay--top ui-scrollable-modal');
    selectNatalCreateSlot('weapon');
}

function selectNatalCreateSlot(slot) {
    _natalCreateSlot = slot || 'weapon';
    document.querySelectorAll('.natal-type-btn').forEach(function (btn) {
        btn.dataset.active = btn.dataset.slot === _natalCreateSlot ? '1' : '0';
    });
}

async function submitCreateNatalArtifact() {
    var input = document.getElementById('natalCreateNameInput');
    var name = input ? input.value.trim() : '';
    if (!name) {
        showToast('请输入本命法宝名');
        return;
    }
    var res = await api.post('/api/game/natal/artifact/create', { name: name, slot: _natalCreateSlot || 'weapon' });
        if (res.code === 200) {
            showToast(res.data || '本命法宝凝练成功');
            closeModal();
            _natalArtifactCache = null;
            loadNatalArtifactSlot();
            loadInventory();
            loadPlayerInfo();
        } else {
            showToast(res.message || '凝练失败');
        }
}

function renameNatalArtifact(currentName) {
    gamePrompt('输入新的本命法宝名（1~12字）：', currentName || '', async function (name) {
        if (!name || !name.trim()) return;
        var res = await api.post('/api/game/natal/artifact/rename', { name: name.trim() });
        if (res.code === 200) {
            showToast(res.data || '已改名');
            _natalArtifactCache = null;
            loadNatalArtifactSlot();
            loadInventory();
        } else {
            showToast(res.message || '改名失败');
        }
    });
}

async function showEditNatalArtifactDesc() {
    var info = await ensureNatalArtifactInfo();
    if (!info || !info.exists) {
        showToast('请先凝练本命法宝');
        return;
    }
    var bodyHtml =
        '<div class="modal-info-card modal-info-card--jade" style="margin-top:0;">' +
        '<div class="modal-info-card__title modal-info-card__title--jade">✦ 法宝小字</div>' +
        '<div style="font-size:12px;color:var(--text-muted);line-height:1.7;margin-bottom:10px;">最多 120 字。可让 AI 根据法宝名、器型、吞噬与祭炼状态重写，也可自己填写。</div>' +
        '<textarea id="natalDescInput" class="app-input" maxlength="120" rows="3" style="width:100%;box-sizing:border-box;resize:vertical;" placeholder="留空保存即可清除小字">' + escapeHtml(info.description || '') + '</textarea>' +
        '<div style="font-size:12px;color:var(--text-muted);line-height:1.7;margin:10px 0 6px;">AI 提示词（可选，最多 80 字）</div>' +
        '<input id="natalDescPromptInput" class="app-input" maxlength="80" style="width:100%;box-sizing:border-box;" placeholder="例：像上古残器、偏雷法、冷峻一点">' +
        '</div>';
    showDecoratedActionDialog({
        subtitle: '编辑本命法宝描述',
        bodyHtml: bodyHtml,
        actionsHtml:
            '<button class="modal-btn modal-btn--outline" onclick="closeModal()">取消</button>' +
            '<button class="modal-btn modal-btn--orange" id="natalDescRegenBtn" onclick="doRegenNatalArtifactDesc()">AI 重写</button>' +
            '<button class="modal-btn modal-btn--gold" onclick="doSaveNatalArtifactDesc()">保存</button>'
    });
}

function refreshNatalArtifactAfterDescChange() {
    _natalArtifactCache = null;
    loadNatalArtifactSlot();
    loadInventory();
}

function doRegenNatalArtifactDesc() {
    var ta = document.getElementById('natalDescInput');
    var promptEl = document.getElementById('natalDescPromptInput');
    var btn = document.getElementById('natalDescRegenBtn');
    if (btn && btn.disabled) return;
    var oldValue = ta ? ta.value : '';
    var prompt = promptEl ? (promptEl.value || '').trim() : '';
    if (prompt.length > 80) {
        showToast('提示词最多80字');
        return;
    }
    if (ta) { ta.disabled = true; ta.value = '法宝灵纹流转中…'; }
    if (promptEl) { promptEl.disabled = true; }
    if (btn) { btn.disabled = true; }
    api.post('/api/game/natal/artifact/regen-description', { prompt: prompt }).then(function (res) {
        if (ta) { ta.disabled = false; }
        if (promptEl) { promptEl.disabled = false; }
        if (btn) { btn.disabled = false; }
        if (res.code === 200 && res.data && res.data.description) {
            if (ta) ta.value = res.data.description;
            showToast('AI 已重写法宝小字');
            refreshNatalArtifactAfterDescChange();
        } else {
            if (ta) ta.value = oldValue;
            showToast(res.message || 'AI 灵感枯竭，稍后再试');
        }
    }).catch(function () {
        if (ta) { ta.disabled = false; ta.value = oldValue; }
        if (promptEl) { promptEl.disabled = false; }
        if (btn) { btn.disabled = false; }
        showToast('AI 重写失败');
    });
}

function doSaveNatalArtifactDesc() {
    var ta = document.getElementById('natalDescInput');
    var val = ta ? (ta.value || '').trim() : '';
    api.post('/api/game/natal/artifact/set-description', { description: val }).then(function (res) {
        if (res.code === 200) {
            showToast(val ? '已保存法宝小字' : '已清空法宝小字');
            closeModal();
            refreshNatalArtifactAfterDescChange();
        } else {
            showToast(res.message || '保存失败');
        }
    });
}

function destroyNatalArtifact() {
    var html = '<div style="font-size:13px;line-height:1.8;color:var(--text-secondary);">'
        + '<p style="margin:0 0 8px;color:var(--text-danger);font-weight:700;">确定融毁当前本命法宝吗？</p>'
        + '<p style="margin:0 0 8px;">融毁后将直接清除本命法宝，可重新凝练其他类型。</p>'
        + '<p style="margin:0;">已吞噬材料、已吞噬装备、祭炼经验、铭文与所有成长属性都不会返还，此操作不可恢复。</p>'
        + '</div>';
    gameConfirm(html, async function () {
        var res = await api.post('/api/game/natal/artifact/destroy', {});
        if (res.code === 200) {
            showToast(res.data || '本命法宝已融毁');
            closeModal();
            _natalArtifactCache = null;
            loadPlayerInfo();
            loadInventory();
            loadEquipGridSummary(true);
            loadNatalArtifactSlot();
            if (typeof renderCraftAspectPanel === 'function') renderCraftAspectPanel();
        } else {
            showToast(res.message || '融毁失败');
        }
    }, null, true);
}

function getNatalDevourMpPercent() {
    var input = document.getElementById('natalDevourMpPercent');
    var value = input ? parseInt(input.value, 10) : 100;
    if (!isFinite(value)) value = 100;
    return Math.max(1, Math.min(100, value));
}

function getNatalDevourMpRefillState() {
    var p = window._lastPlayerData || {};
    var maxMp = Math.max(0, Number(p.maxMp || 0));
    var currentMp = Math.max(0, Number(p.mp || 0));
    var lowerStone = Math.max(0, Number(p.lowerStone || 0));
    var deficit = Math.max(0, maxMp - currentMp);
    var absorbBonus = p.spiritRootName === '天灵根' ? 0.25 : 0;
    var perStone = 10 * (1 + absorbBonus);
    var neededStone = deficit > 0 ? Math.max(1, Math.ceil(deficit / perStone)) : 0;
    return {
        maxMp: maxMp,
        currentMp: currentMp,
        lowerStone: lowerStone,
        deficit: deficit,
        neededStone: neededStone,
        canRefill: maxMp > 0 && deficit > 0 && lowerStone >= neededStone
    };
}

function renderNatalDevourMpRefillRow() {
    var state = getNatalDevourMpRefillState();
    var fmt = typeof formatNumber === 'function' ? formatNumber : function (v) { return String(v); };
    var disabled = state.canRefill ? '' : ' disabled';
    var hint = '';
    var color = 'var(--text-muted)';
    if (state.maxMp <= 0) {
        hint = '当前境界尚无灵力';
    } else if (state.deficit <= 0) {
        hint = '灵力已满';
    } else if (state.lowerStone < state.neededStone) {
        hint = '灵石不足，需约 ' + fmt(state.neededStone) + ' 颗 · 持有 ' + fmt(state.lowerStone);
        color = 'var(--text-red)';
    } else {
        hint = '需约 ' + fmt(state.neededStone) + ' 颗灵石 · 持有 ' + fmt(state.lowerStone);
    }
    return '<div class="natal-devour-mp-refill-row" style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-top:8px;">'
        + '<button type="button" id="natalDevourMpRefillBtn" class="modal-btn modal-btn--outline" style="height:32px;padding:0 12px;font-size:12px;" onclick="refillNatalDevourMp(this)"' + disabled + '>一键补满灵力</button>'
        + '<span id="natalDevourMpRefillHint" style="font-size:12px;color:' + color + ';">' + escapeHtml(hint) + '</span>'
        + '</div>';
}

function updateNatalDevourMpRefillState(isPending) {
    var btn = document.getElementById('natalDevourMpRefillBtn');
    var hintEl = document.getElementById('natalDevourMpRefillHint');
    if (!btn && !hintEl) return;
    var state = getNatalDevourMpRefillState();
    var fmt = typeof formatNumber === 'function' ? formatNumber : function (v) { return String(v); };
    var hint = '';
    var color = 'var(--text-muted)';
    if (isPending) {
        hint = '正在吸收灵石...';
    } else if (state.maxMp <= 0) {
        hint = '当前境界尚无灵力';
    } else if (state.deficit <= 0) {
        hint = '灵力已满';
    } else if (state.lowerStone < state.neededStone) {
        hint = '灵石不足，需约 ' + fmt(state.neededStone) + ' 颗 · 持有 ' + fmt(state.lowerStone);
        color = 'var(--text-red)';
    } else {
        hint = '需约 ' + fmt(state.neededStone) + ' 颗灵石 · 持有 ' + fmt(state.lowerStone);
    }
    if (btn) {
        btn.disabled = !!isPending || !state.canRefill;
        btn.textContent = isPending ? '补灵中...' : '一键补满灵力';
    }
    if (hintEl) {
        hintEl.textContent = hint;
        hintEl.style.color = color;
    }
}

async function refillNatalDevourMp(btn) {
    if (window._natalDevourMpRefillPending) return;
    var state = getNatalDevourMpRefillState();
    if (state.maxMp <= 0) {
        showToast('当前境界尚无灵力');
        return;
    }
    if (state.deficit <= 0) {
        showToast('灵力已满');
        return;
    }
    if (!state.canRefill) {
        showToast('灵石不足，无法补满灵力');
        updateNatalDevourMpRefillState(false);
        return;
    }
    window._natalDevourMpRefillPending = true;
    updateNatalDevourMpRefillState(true);
    if (btn) btn.disabled = true;
    try {
        var res = await api.post('/api/game/absorb-stone', { stoneType: 'stone_lower', amount: -1 });
        if (res.code === 200) {
            showToast(res.data || '灵力已补满');
            if (typeof loadPlayerInfo === 'function') await loadPlayerInfo(true);
            if (typeof loadInventory === 'function') loadInventory();
            updateNatalDevourMpPreview();
        } else {
            showToast(res.message || '补灵失败');
        }
    } catch (e) {
        showToast('补灵失败');
    } finally {
        window._natalDevourMpRefillPending = false;
        updateNatalDevourMpRefillState(false);
    }
}

function renderNatalDevourMpControl(defaultPercent) {
    var p = window._lastPlayerData || {};
    var maxMp = Math.max(0, Number(p.maxMp || 0));
    var currentMp = Math.max(0, Number(p.mp || 0));
    var pct = Math.max(1, Math.min(100, Number(defaultPercent || 100)));
    var cost = maxMp > 0 ? Math.max(1, Math.ceil(maxMp * pct / 100)) : 0;
    var enough = maxMp > 0 && currentMp >= cost;
    return '<div style="margin-top:12px;padding-top:12px;border-top:1px solid rgba(255,255,255,0.08);">'
        + '<div style="font-weight:700;color:var(--text-gold);margin-bottom:6px;">✦ 投入灵力</div>'
        + '<div style="font-size:12px;color:var(--text-muted);line-height:1.7;margin-bottom:8px;">投入最大灵力的 N%，成功率就是 N%；100% 投入必定成功。失败只消耗灵力，不损失材料或装备。</div>'
        + '<div style="display:flex;align-items:center;gap:8px;">'
        + '<input id="natalDevourMpPercent" type="range" min="1" max="100" value="' + pct + '" oninput="updateNatalDevourMpPreview()" style="flex:1;">'
        + '<input id="natalDevourMpPercentNumber" type="number" min="1" max="100" value="' + pct + '" oninput="updateNatalDevourMpFromNumber()" style="width:64px;text-align:center;">'
        + '<span style="color:var(--text-muted);font-size:12px;">%</span>'
        + '</div>'
        + '<div id="natalDevourMpPreview" style="margin-top:8px;font-size:12px;color:' + (enough ? 'var(--accent-jade)' : 'var(--text-red)') + ';">'
        + '成功率 ' + pct + '% · 消耗 ' + (typeof formatNumber === 'function' ? formatNumber(cost) : cost) + ' 灵力 · 当前 ' + (typeof formatNumber === 'function' ? formatNumber(currentMp) : currentMp) + '/' + (typeof formatNumber === 'function' ? formatNumber(maxMp) : maxMp)
        + (enough ? '' : ' · 灵力不足')
        + '</div>'
        + renderNatalDevourMpRefillRow()
        + '</div>';
}

function updateNatalDevourMpFromNumber() {
    var range = document.getElementById('natalDevourMpPercent');
    var number = document.getElementById('natalDevourMpPercentNumber');
    if (range && number) range.value = number.value;
    updateNatalDevourMpPreview();
}

function updateNatalDevourMpPreview() {
    var range = document.getElementById('natalDevourMpPercent');
    var number = document.getElementById('natalDevourMpPercentNumber');
    var preview = document.getElementById('natalDevourMpPreview');
    if (!preview) return;
    var pct = getNatalDevourMpPercent();
    if (range && String(range.value) !== String(pct)) range.value = pct;
    if (number && String(number.value) !== String(pct)) number.value = pct;
    var p = window._lastPlayerData || {};
    var maxMp = Math.max(0, Number(p.maxMp || 0));
    var currentMp = Math.max(0, Number(p.mp || 0));
    var cost = maxMp > 0 ? Math.max(1, Math.ceil(maxMp * pct / 100)) : 0;
    var enough = maxMp > 0 && currentMp >= cost;
    preview.style.color = enough ? 'var(--accent-jade)' : 'var(--text-red)';
    preview.textContent = '成功率 ' + pct + '% · 消耗 ' + (typeof formatNumber === 'function' ? formatNumber(cost) : cost) + ' 灵力 · 当前 ' + (typeof formatNumber === 'function' ? formatNumber(currentMp) : currentMp) + '/' + (typeof formatNumber === 'function' ? formatNumber(maxMp) : maxMp) + (enough ? '' : ' · 灵力不足');
    updateNatalDevourMpRefillState(false);
}

function devourNatalArtifact() {
    var p = window._lastPlayerData || {};
    var maxMp = Math.max(0, Number(p.maxMp || 0));
    var currentMp = Math.max(0, Number(p.mp || 0));
    var defaultPct = maxMp > 0 ? Math.max(1, Math.min(100, Math.floor(currentMp * 100 / maxMp))) : 100;
    var html = '<div style="font-size:13px;line-height:1.7;color:var(--text-secondary);">确定吞噬一套当前境界可用的同类型最强锻造材料，提升一次本命法宝基础属性吗？</div>'
        + renderNatalDevourMpControl(defaultPct);
    gameConfirm(html, async function () {
        var investPercent = getNatalDevourMpPercent();
        var res = await api.post('/api/game/natal/artifact/devour', { investPercent: investPercent });
        if (res.code === 200) {
            showToast(res.data || '吞噬成功');
            _natalArtifactCache = null;
            loadInventory();
            loadPlayerInfo();
            loadNatalArtifactSlot();
        } else {
            showToast(res.message || '吞噬失败');
        }
    }, null, true);
    setTimeout(updateNatalDevourMpPreview, 0);
}

function getNatalDevourEquipmentCandidates(info) {
    info = info || _natalArtifactCache || {};
    var slot = info.slot || 'weapon';
    return (_inventoryCache || []).filter(function (item) {
        if (!item || item.isNatalArtifact || item.isNatal || item.isLocked || item.isEquipped || item.isIncarnationEquipped) return false;
        if (item.tradeCooldown && item.tradeCooldown > Date.now()) return false;
        if (item.type !== slot) return false;
        return (item.attackBonus || item.defenseBonus || item.hpBonus || item.spiritBonus);
    });
}

async function openNatalDevourEquipmentPicker() {
    var info = await ensureNatalArtifactInfo();
    if (!info || !info.exists) {
        showToast('请先凝练本命法宝');
        return;
    }
    if (!_inventoryCache || _inventoryCache.length === 0) {
        try { await refreshInventoryCache(); } catch (e) {}
    }
    var candidates = getNatalDevourEquipmentCandidates(info);
    var slotName = info.slotName || getNatalSlotName(info.slot);
    var html = '<div class="modal-header-deco">'
        + '<div class="modal-header-deco__subtitle">吞噬装备</div>'
        + '<div class="modal-header-deco__value" style="margin-bottom:4px;">'
        + '<span class="modal-header-deco__num" style="color:var(--text-gold);font-size:22px;">' + escapeHtml(slotName) + '养炼</span>'
        + '</div>'
        + '<div style="font-size:12px;color:var(--text-muted);">选择储物袋中的同类型装备，吞噬后获得其模板基础数值。</div>'
        + '</div>'
        + '<div class="modal-body-padded">'
        + '<div class="modal-info-card modal-info-card--jade" style="margin-bottom:12px;">'
        + '<div class="modal-info-card__title modal-info-card__title--jade">✦ 灵力</div>'
        + '<div style="font-size:12px;color:var(--text-muted);line-height:1.7;">吞噬装备会消耗投入灵力，可在此处直接用灵石补满。</div>'
        + renderNatalDevourMpRefillRow()
        + '</div>'
        + '<div class="modal-info-card">'
        + '<div class="modal-info-card__title">✦ 可吞噬装备 (' + candidates.length + ')</div>';
    if (candidates.length === 0) {
        html += '<p style="color:var(--text-muted);font-size:13px;text-align:center;padding:10px 0;">储物袋中没有可吞噬的同类型装备。</p>';
    } else {
        html += '<div class="equip-swap-list">';
        candidates.forEach(function (item) {
            html += '<div class="equip-swap-item" onclick="closeModal();devourNatalEquipment(' + item.id + ',' + jsAttr(item.name) + ')">';
            html += '<div class="item-details">';
            html += '<strong style="color:var(--rarity-' + item.rarity + ');font-size:14px;">' + escapeHtml(item.name);
            if (item.refineLevel > 0) html += ' +' + item.refineLevel;
            html += '</strong><br>';
            var stats = [];
            if (item.attackBonus) stats.push('攻+' + item.attackBonus);
            if (item.defenseBonus) stats.push('防+' + item.defenseBonus);
            if (item.hpBonus) stats.push('血+' + item.hpBonus);
            if (item.spiritBonus) stats.push('神+' + item.spiritBonus);
            html += '<span style="color:var(--text-muted);font-size:11px;">' + stats.join(' | ') + '</span>';
            html += '</div>';
            html += '<span style="color:var(--accent-gold);font-size:12px;padding:4px 8px;border:1px solid rgba(200,160,80,0.3);border-radius:4px;">吞噬</span>';
            html += '</div>';
        });
        html += '</div>';
    }
    html += '</div>'
        + '<div style="font-size:11px;color:var(--text-muted);line-height:1.6;margin-top:10px;text-align:center;">吞噬会永久消耗该装备，仅继承模板基础数值，不继承祭炼、铭文、破损或其他后天状态。</div>'
        + '<button class="modal-btn modal-btn--outline modal-btn--full" style="margin-top:10px;" onclick="openNatalArtifactModal()">返回</button>'
        + '</div>';
    showModal(html, 'modal-overlay--top ui-scrollable-modal');
}

