function handleXuanChouInviteWs(msg) {
    var content = msg.content;
    if (typeof content === 'string') {
        try { content = JSON.parse(content); } catch(e) { return; }
    }
    var existing = document.getElementById('xcInviteOverlay');
    if (existing) existing.remove();

    var overlay = document.createElement('div');
    overlay.id = 'xcInviteOverlay';
    overlay.className = 'dungeon-invite-overlay';
    overlay.innerHTML =
        '<div class="dungeon-invite-modal">' +
            '<div class="dungeon-invite-modal-header">-- 玄筹邀请 --</div>' +
            '<p class="dungeon-invite-modal-text">' + escapeHtml(content.leaderName || '修士') + '邀请你加入玄筹「' + escapeHtml(content.gameName || '对局') + '」，押注 ' + formatNumber(content.stake || 0) + ' 灵石</p>' +
            '<div class="dungeon-invite-modal-actions">' +
                '<button class="btn-action btn-dungeon-accept" id="xcInviteAcceptBtn">加入</button>' +
                '<button class="btn-action btn-dungeon-decline" id="xcInviteDeclineBtn">婉拒</button>' +
            '</div>' +
            '<p class="dungeon-invite-modal-hint">30秒后自动关闭</p>' +
        '</div>';
    document.body.appendChild(overlay);

    var autoClose = setTimeout(function() { if (overlay.parentNode) overlay.remove(); }, 30000);

    document.getElementById('xcInviteAcceptBtn').onclick = function() {
        clearTimeout(autoClose);
        overlay.remove();
        doXuanChouJoinRoom(content.roomId);
    };
    document.getElementById('xcInviteDeclineBtn').onclick = function() {
        clearTimeout(autoClose);
        overlay.remove();
    };
}

