// ===== 造化秘匣 =====
var _mysteryBoxData = null;

async function loadMysteryBox() {
    var infoEl = document.getElementById('mysteryBoxInfo');
    var weightsEl = document.getElementById('mysteryBoxWeights');
    var btnEl = document.getElementById('mysteryBoxBtn');
    var resultEl = document.getElementById('mysteryBoxResult');
    if (!infoEl) return;

    _mysteryBoxData = null;

    if (resultEl) resultEl.classList.add('hidden');

    var res = await api.get('/api/game/mystery-box');
    if (res.code !== 200 || !res.data || !res.data.tier) {
        infoEl.innerHTML = '<div class="mystery-box-empty">暂无可用秘匣</div>';
        if (weightsEl) weightsEl.innerHTML = '';
        if (btnEl) { btnEl.disabled = true; btnEl.textContent = '暂不可用'; }
        return;
    }

    _mysteryBoxData = res.data;
    var tier = res.data.tier;
    var opened = res.data.openedToday;
    var remaining = res.data.remainingToday;
    var maxDaily = res.data.maxDaily;

    infoEl.innerHTML =
        '<div class="mystery-box-tier">' +
        '<span class="mystery-box-name">' + escapeHtml(tier.name) + '</span>' +
        '<span class="mystery-box-price">' + formatNumber(tier.price) + ' 灵石/次</span>' +
        '</div>' +
        '<div class="mystery-box-desc">' + escapeHtml(tier.desc) + '</div>' +
        '<div class="mystery-box-count">今日剩余 <b>' + remaining + '</b>/' + maxDaily + ' 次</div>';

    var rarityLabels = ['普通', '优良', '稀有', '史诗', '传说'];
    var rarityColors = ['#aaa', '#4ade80', '#60a5fa', '#c084fc', '#fbbf24'];
    if (weightsEl) {
        weightsEl.innerHTML = '<div class="mystery-box-weight-row">' +
            tier.rarityWeights.map(function(w, i) {
                return '<span style="color:' + rarityColors[i] + '">' + rarityLabels[i] + ' ' + (w * 100).toFixed(0) + '%</span>';
            }).join(' ') +
            '</div>';
    }

    if (btnEl) {
        btnEl.disabled = remaining <= 0;
        btnEl.textContent = remaining > 0 ? '开启秘匣' : '今日次数已用完';
    }
}

async function openMysteryBox() {
    if (!_mysteryBoxData || _mysteryBoxData.remainingToday <= 0) {
        showToast('今日开匣次数已用完');
        return;
    }

    var btnEl = document.getElementById('mysteryBoxBtn');
    if (btnEl) { btnEl.disabled = true; btnEl.textContent = '开启中...'; }

    var res = await api.post('/api/game/mystery-box/open');
    if (res.code !== 200) {
        showToast(res.message || '开匣失败');
        if (btnEl) { btnEl.disabled = false; btnEl.textContent = '开启秘匣'; }
        return;
    }

    var data = res.data;
    if (!data.success) {
        showToast(data.reason || '开匣失败');
        loadMysteryBox();
        return;
    }

    var item = data.item;
    var rarityColors = { 1: '#aaa', 2: '#4ade80', 3: '#60a5fa', 4: '#c084fc', 5: '#fbbf24' };
    var color = rarityColors[item.rarity] || '#aaa';

    var resultEl = document.getElementById('mysteryBoxResult');
    if (resultEl) {
        resultEl.classList.remove('hidden');
        resultEl.innerHTML =
            '<div class="mystery-box-reveal">' +
            '<div class="mystery-box-reveal-name" style="color:' + color + '">' +
            '【' + escapeHtml(item.rarityName) + '】' + escapeHtml(item.name) +
            '</div>' +
            '<div class="mystery-box-reveal-desc">' + escapeHtml(item.description) + '</div>' +
            '</div>';
    }

    showToast('获得 ' + item.rarityName + '物品：' + item.name);

    _mysteryBoxData.openedToday = data.openedToday;
    _mysteryBoxData.remainingToday = data.remainingToday;

    var infoEl = document.getElementById('mysteryBoxInfo');
    var countEl = infoEl ? infoEl.querySelector('.mystery-box-count') : null;
    if (countEl) {
        countEl.innerHTML = '今日剩余 <b>' + data.remainingToday + '</b>/' + _mysteryBoxData.maxDaily + ' 次';
    }

    if (btnEl) {
        btnEl.disabled = data.remainingToday <= 0;
        btnEl.textContent = data.remainingToday > 0 ? '开启秘匣' : '今日次数已用完';
    }

    loadPlayerInfo();
    loadInventory();
}

