function handleCondenseStone() {
    var p = window._lastPlayerData || {};
    var mp = p.mp || 0;
    var maxCount = Math.floor(mp / 20);
    if (maxCount <= 0) { showToast('灵力不足，凝聚一颗需要20灵力'); return; }
    gameConfirm(
        '当前灵力 ' + mp + '，最多可凝聚 <b>' + maxCount + '</b> 颗灵石 (每颗消耗20灵力)。<br>每日限一次，是否全部凝聚？',
        async function() {
            var r = await api.post('/api/game/condense-stone', { amount: -1 });
            if (r.code === 200) {
                showToast(r.data || '凝聚成功');
                loadPlayerInfo(true);
            } else {
                showToast(r.message || '凝聚失败');
            }
        },
        null,
        true
    );
}

// ===== 工具 =====
function escapeHtml(str) {
    if (str === null || str === undefined) return '';
    return String(str)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}

// 把 JS 字符串安全地嵌入到 onclick="fn(...)" 等双引号 HTML 属性中的 JS 参数位置。
// 返回值已包含外层 JS 引号（以 &quot; 表示），形如 &quot;张三\&quot;&quot;。
function jsAttr(str) {
    return JSON.stringify(str == null ? '' : String(str))
        .replace(/&/g, '&amp;')
        .replace(/"/g, '&quot;');
}

/** 白名单 HTML 过滤：仅允许 br/b/span 标签及 style 属性 */
function sanitizeDetailHtml(html) {
    if (!html) return '';
    return String(html).replace(/<\/?([a-zA-Z][a-zA-Z0-9]*)\b([^>]*)>/g, function(match, tag, attrs) {
        var t = tag.toLowerCase();
        if (t !== 'br' && t !== 'b' && t !== 'span') return escapeHtml(match);
        if (t === 'br') return '<br>';
        var safeAttrs = '';
        var styleMatch = attrs.match(/style\s*=\s*"([^"]*)"/);
        if (styleMatch) safeAttrs = ' style="' + styleMatch[1].replace(/[^\w\s:;,()\-#.%]/g, '') + '"';
        return '<' + (match.charAt(1) === '/' ? '/' : '') + t + safeAttrs + '>';
    });
}

// ===== 逮捕弹窗 (宣传截图用) =====
function showArrestOverlay() {
    document.getElementById('arrestOverlay').classList.remove('hidden');
}
function hideArrestOverlay() {
    document.getElementById('arrestOverlay').classList.add('hidden');
}

// ===== 九霄神庭 =====
async function loadCourt() {
    try {
        var res = await api.get('/api/court/info');
        if (res.code === 200 && res.data) {
            var d = res.data;
            document.getElementById('courtTitle').textContent = d.courtTitle;
            document.getElementById('courtSalaryAmount').textContent = d.courtSalary > 0 ? d.courtSalary + ' 灵石/日' : '无';

            var btn = document.getElementById('courtSalaryBtn');
            if (d.isGuest) {
                document.getElementById('courtInfo').classList.add('hidden');
                document.getElementById('courtBindSection').classList.remove('hidden');
                document.getElementById('courtTrialSection').style.display = 'none';
            } else {
                document.getElementById('courtInfo').classList.remove('hidden');
                document.getElementById('courtBindSection').classList.add('hidden');
                if (d.courtLevel <= 0 || d.courtSalary <= 0) {
                    document.getElementById('courtStatus').textContent = '无俸禄';
                    document.getElementById('courtStatus').style.color = 'var(--text-muted)';
                    btn.disabled = true;
                    btn.innerHTML = '无俸禄';
                } else if (d.canClaimSalary) {
                    document.getElementById('courtStatus').textContent = '可领取';
                    document.getElementById('courtStatus').style.color = 'var(--accent-jade)';
                    btn.disabled = false;
                    btn.innerHTML = '领取俸禄';
                } else {
                    var remaining = Math.max(0, d.nextSalaryTime - Date.now());
                    var hours = Math.floor(remaining / 3600000);
                    var mins = Math.floor((remaining % 3600000) / 60000);
                    var timeText = hours > 0 ? hours + '时' + mins + '分' : mins + '分';
                    document.getElementById('courtStatus').textContent = '次日零点可领 (' + timeText + ')';
                    document.getElementById('courtStatus').style.color = 'var(--text-muted)';
                    btn.disabled = true;
                    btn.innerHTML = timeText + '后';
                }
                // 加载试炼信息
                if (d.courtLevel > 0) loadTrialInfo();
            }
        }
    } catch (e) {
        console.error('loadCourt error:', e);
    }
    loadTasks();
    loadStorageItems();
    loadReviveThanks();
    loadDeadPlayers();
}

async function loadTrialInfo() {
    var section = document.getElementById('courtTrialSection');
    try {
        var res = await api.get('/api/court/trial');
        if (res.code === 200 && res.data) {
            var t = res.data;
            if (t.status === 'max_rank') {
                section.style.display = 'block';
                // 隐藏详情，显示提示
                var infoEl = section.querySelector('.trial-info');
                var btnEl = document.getElementById('trialStartBtn');
                var msgEl = document.getElementById('trialStatusMsg');
                if (infoEl) infoEl.style.display = 'none';
                if (btnEl) btnEl.style.display = 'none';
                if (msgEl) {
                    msgEl.textContent = '当前已是最高可晋升官职';
                    msgEl.style.color = 'var(--text-muted)';
                }
                return;
            }
            section.style.display = 'block';
            // 恢复可能被max_rank隐藏的元素
            var infoEl = section.querySelector('.trial-info');
            if (infoEl) infoEl.style.display = '';
            document.getElementById('trialTargetTitle').textContent = t.nextTitle;
            document.getElementById('trialBossRealm').textContent = t.bossRealmName;
            document.getElementById('trialBossHp').textContent = t.bossHp;
            document.getElementById('trialBossAtk').textContent = t.bossAttack;
            document.getElementById('trialBossDef').textContent = t.bossDefense;
            document.getElementById('trialLocation').textContent = t.trialLocationName;

            var btn = document.getElementById('trialStartBtn');
            var msg = document.getElementById('trialStatusMsg');

            if (t.status === 'available') {
                btn.disabled = false;
                btn.style.display = '';
                btn.classList.remove('btn-trial-disabled');
                btn.innerHTML = '发起试炼';
                msg.textContent = '可以发起试炼';
                msg.style.color = 'var(--accent-jade)';
            } else {
                btn.disabled = true;
                btn.style.display = '';
                btn.classList.add('btn-trial-disabled');
                btn.innerHTML = '发起试炼';
                msg.textContent = t.statusMessage;
                msg.style.color = 'var(--text-muted)';
            }
        }
    } catch (e) {
        section.style.display = 'none';
    }
}

async function handleStartTrial() {
    var btn = document.getElementById('trialStartBtn');
    btn.disabled = true;
    btn.textContent = '试炼中...';
    try {
        var res = await api.post('/api/court/trial/start', {});
        if (res.code === 200 && res.data) {
            var result = res.data;
            // 显示战斗日志弹窗
            showTrialResultDialog(result);
            loadPlayerInfo();
            loadCourt();
        } else {
            showToast(res.message || '试炼失败');
            loadCourt();
        }
    } catch (e) {
        showToast('连接仙界失败');
        loadCourt();
    }
}

function showTrialResultDialog(result) {
    var title = result.promoted ? '试炼通过!' : '试炼未通过';
    var titleClass = result.promoted ? 'trial-result-success' : 'trial-result-fail';
    var logsHtml = result.logs.map(function (log) {
        if (log.indexOf('击败') >= 0 || log.indexOf('通过') >= 0) {
            return '<div class="trial-log trial-log-victory">' + escapeHtml(log) + '</div>';
        } else if (log.indexOf('不敌') >= 0 || log.indexOf('未通过') >= 0 || log.indexOf('超时') >= 0) {
            return '<div class="trial-log trial-log-defeat">' + escapeHtml(log) + '</div>';
        } else if (log.indexOf('第') === 0) {
            return '<div class="trial-log trial-log-round">' + escapeHtml(log) + '</div>';
        } else {
            return '<div class="trial-log">' + escapeHtml(log) + '</div>';
        }
    }).join('');

    var headerColor = result.promoted ? 'rgba(46,204,113,0.3)' : 'rgba(231,76,60,0.3)';
    var titleColor = result.promoted ? 'var(--accent-jade)' : 'var(--text-red)';
    var html = '<div class="modal-overlay modal-overlay--top" id="trialResultOverlay" onclick="closeTrialResult(event)">' +
        '<div class="modal-content modal--decorated" onclick="event.stopPropagation()">' +
        '<div class="modal-header-deco" style="border-bottom-color:' + headerColor + ';">' +
        '<div class="modal-header-deco__subtitle" style="color:' + titleColor + ';">✦ ' + title + ' ✦</div>' +
        '</div>' +
        '<div class="modal-body-padded" style="max-height:75vh;overflow-y:auto;">' +
        (result.promoted ? '<p class="trial-promotion-text">晋升为 ' + escapeHtml(result.newTitle) + '，日俸 ' + result.newSalary + ' 灵石</p>' : '') +
        '<div class="trial-log-container">' + logsHtml + '</div>' +
        '<div class="modal-btn-row" style="margin-top:16px;padding:0;">' +
        '<button class="modal-btn modal-btn--gold" style="width:100%;" onclick="closeTrialResult()">确 定</button>' +
        '</div>' +
        '</div></div></div>';

    var container = document.createElement('div');
    container.innerHTML = html;
    document.body.appendChild(container.firstChild);
}

function closeTrialResult(e) {
    if (e && e.target !== e.currentTarget) return;
    var overlay = document.getElementById('trialResultOverlay');
    if (overlay) overlay.remove();
}

var REALM_NAMES = ['锻体期', '练气期', '筑基期', '金丹期', '元婴期', '化神期', '炼虚期', '合道期', '大乘期', '渡劫期', '真仙境', '玄仙境', '上仙境', '天仙境', '仙君境', '仙王境', '仙帝境', '仙尊境', '仙祖境', '圣人境'];
function formatReviveThanksTime(ts) {
    if (!ts) return '';
    var d = new Date(ts);
    if (isNaN(d.getTime())) return '';
    return (d.getMonth() + 1) + '/' + d.getDate() + ' ' + d.getHours() + ':' + (d.getMinutes() < 10 ? '0' : '') + d.getMinutes();
}

function renderReviveThanks(entries) {
    var lists = ['reviveThanksList', 'guardianReviveThanksList']
        .map(function(id) { return document.getElementById(id); })
        .filter(Boolean);
    if (!lists.length) return;

    if (!entries || entries.length === 0) {
        lists.forEach(function(list) {
            list.classList.add('hidden');
            list.innerHTML = '';
        });
        return;
    }

    var html = entries.map(function(t) {
        var helper = escapeHtml(t.helperName || '某位道友');
        var area = t.safeAreaName ? (' · 接引至 ' + escapeHtml(t.safeAreaName)) : '';
        var cost = t.reviveCost > 0 ? ('引渡花费 ' + formatNumber(t.reviveCost) + ' 灵石') : '免费引渡';
        var time = formatReviveThanksTime(t.createdAt);
        return '<div class="revive-thanks-card">' +
            '<div class="revive-thanks-title"><span><b>' + helper + '</b> 曾为你代办引渡</span><span>' + escapeHtml(time) + '</span></div>' +
            '<div class="revive-thanks-meta">' + escapeHtml(cost) + area + '</div>' +
            '<div class="revive-thanks-actions">' +
                '<button class="btn-action" onclick="handleReviveThanksStone(' + t.id + ', ' + jsAttr(t.helperName || '道友') + ')">赠灵石</button>' +
                '<button class="btn-action" onclick="openReviveThanksMaterialDialog(' + t.id + ', ' + jsAttr(t.helperName || '道友') + ')">赠材料</button>' +
                '<button class="btn-action btn-action--ghost" onclick="dismissReviveThanks(' + t.id + ')">暂不感谢</button>' +
            '</div>' +
        '</div>';
    }).join('');

    lists.forEach(function(list) {
        list.innerHTML = html;
        list.classList.remove('hidden');
    });
}

async function loadReviveThanks() {
    var hasContainer = document.getElementById('reviveThanksList') || document.getElementById('guardianReviveThanksList');
    if (!hasContainer) return;
    try {
        var res = await api.get('/api/game/revive-thanks');
        if (res.code === 200) renderReviveThanks(res.data || []);
    } catch (e) {
        renderReviveThanks([]);
    }
}

async function handleReviveThanksStone(thankId, helperName) {
    var balance = (window._lastPlayerData && window._lastPlayerData.lowerStone) || 0;
    if (balance <= 0) {
        showToast('灵石不足');
        return;
    }
    gamePrompt('赠予 ' + helperName + ' 灵石：\n当前持有 ' + formatNumber(balance), '', async function(val) {
        var amount = parseInt(val, 10) || 0;
        if (amount <= 0) {
            showToast('请输入有效数量');
            return;
        }
        var res = await api.post('/api/game/revive-thanks/stone', { thankId: thankId, amount: amount });
        if (res.code === 200) {
            showToast(res.data || '已送出谢礼');
            await loadPlayerInfo(true);
            loadReviveThanks();
            loadGameLogs();
        } else {
            showToast(res.message || '感谢失败');
        }
    }, null, false, dialogIntegerInputOptions(1, balance));
}

async function openReviveThanksMaterialDialog(thankId, helperName) {
    try {
        var res = await api.get('/api/game/revive-thanks/material-candidates?thankId=' + encodeURIComponent(thankId));
        if (res.code !== 200) {
            showToast(res.message || '加载材料失败');
            return;
        }
        var items = res.data || [];
        if (items.length === 0) {
            showToast('暂无可赠材料');
            return;
        }
        var rows = items.map(function(item) {
            return '<div class="revive-thanks-material-row">' +
                '<span><b>' + escapeHtml(item.name) + '</b><small style="display:block;color:var(--text-muted);font-size:11px;">持有 ' + formatNumber(item.quantity) + '</small></span>' +
                '<button class="btn-action" onclick="confirmReviveThanksMaterial(' + thankId + ', ' + item.playerItemId + ', ' + item.quantity + ', ' + jsAttr(item.name) + ')">赠出</button>' +
            '</div>';
        }).join('');
        showDecoratedActionDialog({
            subtitle: '引渡谢礼',
            descHtml: '赠予 ' + escapeHtml(helperName),
            bodyHtml: '<div class="modal-info-card"><div class="revive-thanks-material-list">' + rows + '</div></div>',
            actionsHtml: '<button class="modal-btn modal-btn--outline" onclick="closeDecoratedActionDialog()">取消</button>',
            extraClass: 'modal-overlay--top ui-scrollable-modal'
        });
    } catch (e) {
        showToast('加载材料失败');
    }
}

function confirmReviveThanksMaterial(thankId, playerItemId, maxQty, itemName) {
    gamePrompt('赠出 [' + itemName + '] 数量：\n当前持有 ' + formatNumber(maxQty), '1', async function(val) {
        var quantity = parseInt(val, 10) || 0;
        if (quantity <= 0 || quantity > maxQty) {
            showToast('请输入有效数量');
            return;
        }
        var res = await api.post('/api/game/revive-thanks/material', { thankId: thankId, playerItemId: playerItemId, quantity: quantity });
        if (res.code === 200) {
            closeDecoratedActionDialog();
            showToast(res.data || '已送出谢礼');
            loadReviveThanks();
            loadStorageItems();
            loadGameLogs();
        } else {
            showToast(res.message || '感谢失败');
        }
    }, null, false, dialogIntegerInputOptions(1, maxQty));
}

async function dismissReviveThanks(thankId) {
    var res = await api.post('/api/game/revive-thanks/dismiss', { thankId: thankId });
    if (res.code === 200) {
        showToast(res.data || '已收起');
        loadReviveThanks();
    } else {
        showToast(res.message || '操作失败');
    }
}

async function loadDeadPlayers() {
    var lists = ['deadPlayerList', 'guardianDeadPlayerList']
        .map(function(id) { return document.getElementById(id); })
        .filter(Boolean);
    if (!lists.length) return;
    function renderDeadPlayers(html) {
        lists.forEach(function(list) { list.innerHTML = html; });
    }
    try {
        var res = await api.get('/api/game/dead-players');
        if (res.code === 200 && res.data) {
            if (res.data.length === 0) {
                renderDeadPlayers('<p class="court-card-hint">当前无陨落修士</p>');
            } else {
                renderDeadPlayers(res.data.map(function (p) {
                    var reviveText = p.reviveCost > 0 ? (p.reviveCost + '灵石引渡') : '免费引渡';
                    return '<div class="dead-player-row">' +
                        '<span class="dead-player-name">' + escapeHtml(p.name) +
                        ' <small>(' + (REALM_NAMES[p.realmStage] || '未知') + ')</small></span>' +
                        '<button class="btn-action btn-revive-other" onclick="handleReviveOther(' + p.playerId + ', ' + p.reviveCost + ')">' +
                        reviveText + '</button>' +
                        '</div>';
                }).join(''));
            }
        }
    } catch (e) {
        renderDeadPlayers('<p class="court-card-hint">加载失败</p>');
    }
}

async function handleReviveOther(targetPlayerId, cost) {
    gameConfirm('确认花费 ' + cost + ' 灵石为该修士引渡归来?', async function () {
        var res = await api.post('/api/game/revive-other', { targetPlayerId: targetPlayerId });
        if (res.code === 200) {
            showToast(res.data || '引渡成功');
            loadPlayerInfo();
            loadDeadPlayers();
        } else {
            showToast(res.message || '引渡失败');
        }
    });
}

async function handleClaimSalary() {
    var btn = document.getElementById('courtSalaryBtn');
    btn.disabled = true;
    btn.textContent = '领取中...';
    try {
        var res = await api.post('/api/court/salary', {});
        if (res.code === 200 && res.data) {
            showToast(res.data.message || '俸禄已领取');
            loadPlayerInfo();
            loadCourt();
        } else {
            showToast(res.message || '领取失败');
            loadCourt();
        }
    } catch (e) {
        showToast('连接仙界失败');
        loadCourt();
    }
}

function showPlayerNameMenu(event) {
    if (typeof showCourtRenameModal === 'function') showCourtRenameModal();
}

function showSelfPlayerProfile(event) {
    if (event && event.stopPropagation) event.stopPropagation();
    var playerId = window._lastPlayerData && window._lastPlayerData.id;
    if (!playerId) {
        var storedId = parseInt(localStorage.getItem('playerId') || '0', 10);
        if (storedId > 0) playerId = storedId;
    }
    if (!playerId) {
        showToast('角色信息尚未加载');
        return;
    }
    showPlayerProfile(playerId);
}

function openProfileRenameDialog() {
    closePlayerProfile();
    showPlayerNameMenu();
}

function genderLabel(gender) {
    if (gender === 'male') return '男修';
    if (gender === 'female') return '女修';
    if (gender === 'other') return '不拘';
    return '未设置';
}

function isGenderConfigured(gender) {
    return gender === 'male' || gender === 'female' || gender === 'other';
}

function isDaoGenderCompatible(a, b) {
    if (!isGenderConfigured(a) || !isGenderConfigured(b)) return false;
    if (a === 'other' || b === 'other') return true;
    return a !== b;
}

function openGenderDialog(afterSet) {
    var p = window._lastPlayerData || {};
    var current = p.gender || 'unknown';
    window._pendingGenderAfterSet = typeof afterSet === 'function' ? afterSet : null;
    var locked = isGenderConfigured(current);
    var changeCost = p.genderChangeCost || 1;
    var cooldownUntil = p.genderChangeCooldownUntil || 0;
    var cooldownLeft = Math.max(0, cooldownUntil - Date.now());
    function fmtGenderCooldown(ms) {
        if (ms <= 0) return '';
        var hours = Math.max(1, Math.ceil(ms / 3600000));
        var days = Math.floor(hours / 24);
        var restHours = hours % 24;
        if (days > 0 && restHours > 0) return days + '天' + restHours + '小时';
        if (days > 0) return days + '天';
        return restHours + '小时';
    }
    var options = [
        { id: 'male', label: '男修' },
        { id: 'female', label: '女修' },
        { id: 'other', label: '不拘' }
    ];
    var optionHtml = options.map(function(opt) {
        var active = current === opt.id ? ' modal-action-btn--jade' : '';
        var isCurrent = current === opt.id;
        var canReshape = locked && !isCurrent && cooldownLeft <= 0;
        var disabled = (isCurrent || (locked && !canReshape)) ? ' disabled' : '';
        var click = !locked ? ' onclick="setPlayerGender(' + jsAttr(opt.id) + ')"' :
            (canReshape ? ' onclick="setPlayerGender(' + jsAttr(opt.id) + ', null, true)"' : '');
        var costText = isCurrent ? '已登记' : (!locked ? '选择' : (cooldownLeft > 0 ? '冷却中' : changeCost + '仙缘重塑'));
        return '<button class="modal-action-btn' + active + '"' + click + disabled + '>' +
            '<span class="modal-action-btn__text">' + opt.label + '</span>' +
            '<span class="modal-action-btn__cost">' + costText + '</span>' +
            '</button>';
    }).join('');
    var desc = locked
        ? ('已登记性别。可消耗 ' + changeCost + ' 点仙缘重塑道体' + (cooldownLeft > 0 ? '，冷却剩余 ' + fmtGenderCooldown(cooldownLeft) : '，会校验道侣关系与待处理道帖') + '。')
        : '道侣同修前需先登记性别，首次登记免费。';
    var html = '<div class="modal-header-deco">' +
        '<div class="modal-header-deco__subtitle" style="color:var(--accent-jade);">✦ 道 体 登 记 ✦</div>' +
        '<div class="modal-header-deco__value" style="margin-bottom:4px;">' +
        '<span class="modal-header-deco__num" style="color:var(--accent-jade);font-size:22px;">' + escapeHtml(genderLabel(current)) + '</span>' +
        '</div>' +
        '<div style="font-size:12px;color:var(--text-muted);">' + escapeHtml(desc) + '</div>' +
        '</div>' +
        '<div class="modal-body-padded">' +
        '<div class="modal-info-card modal-info-card--jade">' +
        '<div class="modal-info-card__title modal-info-card__title--jade">✦ 选择性别</div>' +
        '<div class="modal-action-list">' + optionHtml + '</div>' +
        '</div>' +
        '<div class="modal-btn-row" style="margin-top:16px;">' +
        '<button class="modal-btn modal-btn--outline modal-btn--full" onclick="closeModal()">关闭</button>' +
        '</div>' +
        '</div>';
    showModal(html, 'modal-overlay--top');
}

async function setPlayerGender(gender, afterSet, useAdPoints) {
    async function run() {
        try {
            var res = await api.post('/api/player/gender', { gender: gender, useAdPoints: !!useAdPoints });
            if (res.code === 200) {
                var callback = typeof afterSet === 'function' ? afterSet : window._pendingGenderAfterSet;
                window._pendingGenderAfterSet = null;
                showToast(res.data || (useAdPoints ? '道体已重塑' : '性别已设置'));
                if (window._lastPlayerData) {
                    window._lastPlayerData.gender = gender;
                    window._lastPlayerData.genderLabel = genderLabel(gender);
                    if (useAdPoints) {
                        window._lastPlayerData.adPoints = Math.max(0, (window._lastPlayerData.adPoints || 0) - (window._lastPlayerData.genderChangeCost || 1));
                        window._lastPlayerData.genderChangeCooldownUntil = Date.now() + 7 * 24 * 3600 * 1000;
                    }
                }
                closeModal();
                await loadPlayerInfo(true);
                if (typeof CaveModule !== 'undefined' && CaveModule.load) CaveModule.load();
                if (typeof callback === 'function') callback();
            } else {
                showToast(res.message || '设置失败');
            }
        } catch (e) {
            showToast((e && e.message) || '设置失败');
        }
    }
    if (useAdPoints) {
        var p = window._lastPlayerData || {};
        var cost = p.genderChangeCost || 1;
        var msg = '确认消耗 <b>' + cost + '</b> 点仙缘，将道体性别重塑为 <b>' + escapeHtml(genderLabel(gender)) + '</b> 吗？<br><span style="color:var(--text-muted);font-size:12px;">会校验当前道侣关系与待处理同修道帖，成功后 7 天内不可再次重塑。</span>';
        if (typeof gameConfirm === 'function') gameConfirm(msg, run, null, true);
        else if (window.confirm('确认消耗 ' + cost + ' 点仙缘重塑道体性别吗？')) run();
        return;
    }
    await run();
}

window.setPlayerGender = setPlayerGender;

function showCourtRenameModal() {
    var p = window._lastPlayerData || {};
    var stone = p.lowerStone || 0;
    var currentName = p.name || '';

    var html = '<div class="modal-header-deco">' +
        '<div class="modal-header-deco__subtitle">神庭更名重塑</div>' +
        '<div class="modal-header-deco__value" style="margin-bottom:4px;">' +
        '<span class="modal-header-deco__num" style="color:var(--text-gold);">10000</span>' +
        '<span class="modal-header-deco__unit" style="font-size:18px;color:var(--text-muted);"> 灵石</span>' +
        '</div>' +
        '<div style="font-size:12px;color:var(--text-muted);">耗灵石重铸姓名，1 天内不可再易。</div>' +
        '</div>' +

        '<div class="modal-body-padded">' +
        '<div class="modal-info-card modal-info-card--jade">' +
        '<div class="modal-info-card__title modal-info-card__title--jade">✦ 命名规则</div>' +
        '<div class="modal-feat-list" style="margin-left:4px;">' +
        '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--jade">◈</span><span>当前姓名: <b style="color:var(--text-primary);">' + escapeHtml(currentName) + '</b></span></div>' +
        '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--orange">◈</span><span>持有灵石: <b style="color:var(--text-gold);">' + formatNumber(stone) + '</b></span></div>' +
        '<div class="modal-feat-row"><span class="modal-feat-icon" style="color:var(--accent-cyan);">◈</span><span>长度限制: <b>2 ~ 8 字</b></span></div>' +
        '</div>' +
        '</div>' +

        '<div class="modal-info-card" style="margin-top:16px;">' +
        '<div class="modal-info-card__title">✦ 新姓名</div>' +
        '<input type="text" id="courtRenameInput" class="app-input" maxlength="8" placeholder="输入新姓名 (2-8字)" style="width:100%;padding:10px 12px;font-size:14px;text-align:center;letter-spacing:2px;" autocomplete="off">' +
        '</div>' +

        '<div class="modal-btn-row" style="margin-top:16px;">' +
        '<button class="modal-btn modal-btn--outline" style="flex:1;" onclick="closeModal()">取消</button>' +
        '<button class="modal-btn modal-btn--gold" style="flex:1;" id="renameConfirmBtn">重塑</button>' +
        '</div>' +
        '</div>';

    showModal(html, 'modal-overlay--top');

    var input = document.getElementById('courtRenameInput');
    var confirmBtn = document.getElementById('renameConfirmBtn');
    if (input) setTimeout(function() { input.focus(); }, 100);
    if (confirmBtn) {
        confirmBtn.onclick = function() {
            var newName = (input.value || '').trim();
            if (!newName) { showToast('姓名不能为空'); return; }
            if (newName.length < 2 || newName.length > 8) { showToast('姓名长度需在2~8个字符内'); return; }
            closeModal();
            doCourtRename(newName);
        };
    }
}

async function doCourtRename(newName) {
    var btn = document.getElementById('courtRenameBtn');
    if (btn) btn.disabled = true;
    try {
        var res = await api.post('/api/court/rename', { newName: newName });
        if (res.code === 200) {
            showToast(res.data || '改名成功');
            try { localStorage.setItem('playerName', newName); } catch (e) {}
            document.getElementById('statName').textContent = newName;
            document.getElementById('headerPlayerName').textContent = newName;
            if (window._lastPlayerData) window._lastPlayerData.name = newName;
            loadPlayerInfo();
            loadCourt();
            if (typeof loadChatMessages === 'function') loadChatMessages();
        } else {
            showToast(res.message || '申请改名失败');
        }
    } catch (e) {
        showToast('连接神庭失败');
        console.error('Rename error:', e);
    } finally {
        if (btn) btn.disabled = false;
    }
}

// ===== 渡劫起号·自封道号（按境界拼接尊号后缀） =====
function renderDivineTitleSuffixRules(rules, currentStage) {
    if (!Array.isArray(rules) || rules.length === 0) return '';
    var rows = rules.map(function(rule) {
        var stage = Number(rule.realmStage || 0);
        var isCurrent = stage === Number(currentStage || 0);
        var bg = isCurrent ? 'background:rgba(255,183,77,0.12);border-color:rgba(255,183,77,0.38);' : '';
        var mark = isCurrent ? '<span style="font-size:11px;color:#ffb74d;margin-left:6px;">当前</span>' : '';
        return '<div style="display:flex;align-items:center;justify-content:space-between;gap:10px;padding:8px 10px;border:1px solid rgba(255,255,255,0.08);border-radius:4px;' + bg + '">' +
            '<span style="font-size:12px;color:var(--text-secondary);">' + escapeHtml(rule.realmName || ('境界' + stage)) + mark + '</span>' +
            '<b style="font-size:13px;color:#ffb74d;white-space:nowrap;">' + escapeHtml(rule.suffix || '') + '</b>' +
            '</div>';
    }).join('');
    return '<div class="modal-info-card" style="margin-top:16px;">' +
        '<div class="modal-info-card__title">✦ 尊号境界</div>' +
        '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(128px,1fr));gap:8px;">' + rows + '</div>' +
        '</div>';
}

