function updateNatalOverdriveUi(enabled) {
    var aspectToggle = document.getElementById('natalOverdriveAspectToggle');
    if (aspectToggle) aspectToggle.checked = !!enabled;
    var encounterToggle = document.getElementById('encounterNatalOverdriveToggle');
    if (encounterToggle) encounterToggle.checked = !!enabled;
    ['natalOverdriveStatusText', 'encounterNatalOverdriveStatus'].forEach(function (statusId) {
        var status = document.getElementById(statusId);
        if (!status) return;
        var text = status.textContent || '';
        var suffixIndex = text.indexOf(' · ');
        var suffix = suffixIndex >= 0 ? text.substring(suffixIndex) : '';
        status.textContent = (enabled ? '已开启' : '已关闭') + suffix;
    });
}


// ===== 设置 - 修改密码 =====
function openResetPwdModal() {
    document.getElementById('resetPwdModal').classList.remove('hidden');
}

function closeResetPwdModal() {
    document.getElementById('resetPwdModal').classList.add('hidden');
}

var settingResetCountdown = 0;
async function handleSettingSendCode() {
    if (settingResetCountdown > 0) return;
    var email = document.getElementById('settingResetEmail').value.trim();
    if (!email) { showToast('邮箱信息异常'); return; }
    var btn = document.getElementById('settingResetCodeBtn');
    btn.disabled = true;
    btn.textContent = '发送中...';
    try {
        var res = await api.post('/api/auth/send-code', { email: email });
        if (res.code === 200) {
            showToast('验证码已发送至邮箱');
            settingResetCountdown = 60;
            var timer = setInterval(function () {
                settingResetCountdown--;
                if (settingResetCountdown <= 0) {
                    clearInterval(timer);
                    btn.disabled = false;
                    btn.textContent = '发送验证码';
                } else {
                    btn.textContent = settingResetCountdown + '秒';
                }
            }, 1000);
        } else {
            showToast(res.message || '发送失败');
            btn.disabled = false;
            btn.textContent = '发送验证码';
        }
    } catch (e) {
        showToast('发送失败');
        btn.disabled = false;
        btn.textContent = '发送验证码';
    }
}

async function handleSettingResetPwd() {
    var email = document.getElementById('settingResetEmail').value.trim();
    var code = document.getElementById('settingResetCode').value.trim();
    var pwd = document.getElementById('settingResetPwd').value;
    if (!code || !pwd) { showToast('请填写验证码和新密码'); return; }
    if (!isEmailVerifyCode(code)) { showToast('请输入8位邮箱验证码'); return; }
    if (pwd.length < 6) { showToast('密码长度不少于6位'); return; }

    try {
        var res = await api.post('/api/auth/reset-password', {
            email: email,
            code: parseInt(code),
            newPassword: pwd
        });
        if (res.code === 200 && res.data) {
            localStorage.setItem('token', res.data.token);
            showToast('密码修改成功');
            document.getElementById('settingResetCode').value = '';
            document.getElementById('settingResetPwd').value = '';
        } else {
            showToast(res.message || '修改失败');
        }
    } catch (e) {
        showToast('修改失败，请稍后再试');
    }
}

