// ===== 主题切换 =====
var DEFAULT_DOCUMENT_TITLE = '灵界 LingVerse - 修仙世界';
var EXCEL_DOCUMENT_TITLE = 'LingVerse.xlsx - Excel';
var DEFAULT_FAVICON_HREF = '/favicon.svg';
var EXCEL_FAVICON_HREF = '/favicon-excel.svg';

function syncThemeDocumentChrome(mode) {
    var isExcelTheme = mode === 'excel';
    document.title = isExcelTheme ? EXCEL_DOCUMENT_TITLE : DEFAULT_DOCUMENT_TITLE;

    var icon = document.getElementById('pageFavicon') || document.querySelector('link[rel="icon"]');
    if (!icon) {
        icon = document.createElement('link');
        icon.id = 'pageFavicon';
        icon.rel = 'icon';
        icon.type = 'image/svg+xml';
        document.head.appendChild(icon);
    }
    icon.href = isExcelTheme ? EXCEL_FAVICON_HREF : DEFAULT_FAVICON_HREF;
}

function switchTheme(mode) {
    var html = document.documentElement;
    html.classList.remove('theme-light', 'theme-dark', 'theme-excel');
    if (mode === 'light') html.classList.add('theme-light');
    else if (mode === 'dark') html.classList.add('theme-dark');
    else if (mode === 'excel') html.classList.add('theme-excel');
    else {
        // system 模式: 检测系统偏好并主动设置 class
        html.classList.add(
            window.matchMedia('(prefers-color-scheme: dark)').matches
                ? 'theme-dark' : 'theme-light'
        );
    }
    localStorage.setItem('lv_theme', mode);
    syncThemeDocumentChrome(mode);
    // 更新按钮状态
    document.querySelectorAll('.theme-btn').forEach(function (btn) {
        btn.classList.toggle('active', btn.getAttribute('data-theme') === mode);
    });
    applyUiPalette();
}

function initTheme() {
    var saved = localStorage.getItem('lv_theme') || 'light';
    var paperMigrated = localStorage.getItem('lv_theme_paper_v1') === '1';
    if (!paperMigrated && saved === 'system') saved = 'light';
    if (!paperMigrated) localStorage.setItem('lv_theme_paper_v1', '1');
    switchTheme(saved);
}
initTheme();

// system 模式: 实时响应系统偏好变更
window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', function() {
    if ((localStorage.getItem('lv_theme') || 'light') === 'system') {
        switchTheme('system');
    }
});

// ===== 悬浮聊天气泡 =====
var chatBubbleTimer = null;
window.__chatBubbleClickTarget = null;
function showChatBubble(name, content, isSystem, clickTarget) {
    window.__chatBubbleClickTarget = null;
    // 聊天面板已打开时不显示
    if (currentPanel === 'chat') return;

    var bubble = document.getElementById('chatBubble');
    var nameEl = document.getElementById('chatBubbleName');
    var textEl = document.getElementById('chatBubbleText');
    if (!bubble) return;
    window.__chatBubbleClickTarget = (typeof clickTarget === 'function') ? clickTarget : null;

    // 截断过长文本
    var displayText = content.length > 35 ? content.substring(0, 35) + '...' : content;

    if (isSystem) {
        nameEl.textContent = '';
        textEl.textContent = displayText;
        textEl.style.color = 'var(--text-gold)';
        textEl.style.fontStyle = 'italic';
    } else {
        nameEl.textContent = name + ': ';
        textEl.textContent = displayText;
        textEl.style.color = '';
        textEl.style.fontStyle = '';
    }

    // 重置动画
    bubble.classList.remove('hidden', 'fade-out');
    bubble.style.animation = 'none';
    bubble.offsetHeight; // 强制 reflow
    bubble.style.animation = '';

    // 清除旧定时器
    if (chatBubbleTimer) clearTimeout(chatBubbleTimer);
    chatBubbleTimer = setTimeout(function () {
        bubble.classList.add('fade-out');
        setTimeout(function () { bubble.classList.add('hidden'); }, 300);
    }, 5000);
}

// ===== 气运系统 =====
// 与后端 RealmConfig.LUCK_REFRESH_STONE_COSTS 保持一致：按大境界递增
var LUCK_REFRESH_STONE_COSTS = [
    1000, 2000, 4000, 8000, 16000, 32000, 64000, 128000, 256000, 500000,
    1000000, 1500000, 2200000, 3300000, 5000000, 7500000, 11000000, 16000000, 24000000, 36000000
];
function getLuckRefreshStoneCost(stage) {
    if (!LUCK_REFRESH_STONE_COSTS.length) return 1000;
    var idx = Math.max(0, Math.min(stage | 0, LUCK_REFRESH_STONE_COSTS.length - 1));
    return LUCK_REFRESH_STONE_COSTS[idx];
}

async function refreshLuck() {
    var p = window._lastPlayerData;
    if (!p) return;
    var stoneCost = getLuckRefreshStoneCost(p.realmStage || 0);

    showDecoratedActionDialog({
        subtitle: '逆天改命',
        valueHtml: '<span class="modal-header-deco__num" style="color:var(--text-gold);">' + p.luck + '</span>',
        descHtml: '当前气运',
        bodyHtml: '<div class="modal-info-card modal-info-card--jade"><div class="modal-info-card__title modal-info-card__title--jade">✦ 气运影响</div><div style="font-size:12px;color:var(--text-muted);line-height:1.7;">影响掉落、暴击、逃跑及副职极品率。境界越高，逆天改命所需灵石也水涨船高。</div></div>',
        actionsHtml:
            '<button class="modal-action-btn modal-action-btn--gold" id="btnLuckStone"><span>消耗 ' + formatNumber(stoneCost) + ' 灵石</span></button>' +
            '<button class="modal-action-btn modal-action-btn--orange" id="btnLuckAd"><span>消耗 1 仙缘</span></button>' +
            '<button class="modal-btn modal-btn--outline modal-btn--full" id="btnLuckCancel">取消</button>',
        actionClass: 'modal-action-list'
    });
    
    async function doRefresh(useAd) {
        closeModal();
        try {
            var res = await api.post('/api/game/refresh-luck', { useAdPoints: useAd });
            if (res.code === 200) {
                showToast("天机扭转，当前气运刷新为: " + res.data.newLuck);
                await typewriterLog('天道流转，你逆天改命，将今日气运刷新为了 ' + res.data.newLuck, 'system', 30);
                loadPlayerInfo();
            } else {
                showToast(res.message || "刷新失败");
            }
        } catch (e) {
            console.error(e);
        }
    }
    
    document.getElementById('btnLuckStone').onclick = function() { doRefresh(false); };
    document.getElementById('btnLuckAd').onclick = function() { doRefresh(true); };
    document.getElementById('btnLuckCancel').onclick = function() { closeModal(); };
}

// ===== 防止手机端密码管理器弹窗 =====
(function() {
    function isNonPasswordInput(el) {
        if (!el || !el.tagName || el.tagName.toLowerCase() !== 'input') return false;
        var type = (el.getAttribute('type') || 'text').toLowerCase();
        return type !== 'password' && type !== 'checkbox' && type !== 'range' && type !== 'hidden';
    }

    function isNumericInput(el) {
        if (!isNonPasswordInput(el)) return false;
        var type = (el.getAttribute('type') || 'text').toLowerCase();
        var inputMode = (el.getAttribute('inputmode') || '').toLowerCase();
        return type === 'number' || inputMode === 'numeric' || inputMode === 'decimal';
    }

    function tagInputAsNonPassword(el) {
        if (!isNonPasswordInput(el)) return;
        el.setAttribute('data-1p-ignore', 'true');
        el.setAttribute('data-lpignore', 'true');
        el.setAttribute('data-form-type', 'other');
        el.setAttribute('autocorrect', 'off');
        el.setAttribute('autocapitalize', 'off');
        el.setAttribute('spellcheck', 'false');
        var autocomplete = (el.getAttribute('autocomplete') || '').toLowerCase();
        if (!autocomplete || autocomplete === 'on' || autocomplete.indexOf('password') >= 0) {
            el.setAttribute('autocomplete', 'off');
        }
        if (isNumericInput(el)) {
            el.setAttribute('data-lv-non-password', 'true');
            el.setAttribute('data-bwignore', 'true');
            el.setAttribute('aria-autocomplete', 'none');
        }
    }

    function tagInputs(root) {
        var scope = root && root.querySelectorAll ? root : document;
        if (scope.matches && scope.matches('input')) {
            tagInputAsNonPassword(scope);
        }
        scope.querySelectorAll('input:not([type="password"]):not([type="checkbox"]):not([type="range"]):not([type="hidden"])').forEach(tagInputAsNonPassword);
    }

    function tagEventTargetInput(target) {
        var input = target && target.closest ? target.closest('input') : target;
        tagInputAsNonPassword(input);
    }

    var _pendingInputTagRoots = [];
    var _inputTaggingScheduled = false;
    var _inputTaggingFullDocument = false;

    function scheduleInputTagging(root) {
        if (!root) return;
        if (root.nodeType && root.nodeType !== 1 && root.nodeType !== 9) return;
        if (!_inputTaggingFullDocument) {
            _pendingInputTagRoots.push(root);
            if (_pendingInputTagRoots.length > 80) {
                _pendingInputTagRoots = [document];
                _inputTaggingFullDocument = true;
            }
        }
        if (_inputTaggingScheduled) return;
        _inputTaggingScheduled = true;
        var run = function() {
            _inputTaggingScheduled = false;
            var roots = _pendingInputTagRoots.splice(0);
            _inputTaggingFullDocument = false;
            roots.forEach(tagInputs);
        };
        if (window.requestIdleCallback) {
            window.requestIdleCallback(run, { timeout: 500 });
        } else {
            setTimeout(run, 0);
        }
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', tagInputs);
    } else {
        tagInputs();
    }
    document.addEventListener('focusin', function(e) { tagEventTargetInput(e.target); }, true);
    document.addEventListener('touchstart', function(e) { tagEventTargetInput(e.target); }, true);
    // MutationObserver: 动态添加的 input 也需要处理
    var inputObserver = new MutationObserver(function(mutations) {
        for (var i = 0; i < mutations.length; i++) {
            for (var j = 0; j < mutations[i].addedNodes.length; j++) {
                scheduleInputTagging(mutations[i].addedNodes[j]);
            }
        }
    });
    if (document.body) {
        inputObserver.observe(document.body, { childList: true, subtree: true });
    } else {
        document.addEventListener('DOMContentLoaded', function() {
            inputObserver.observe(document.body, { childList: true, subtree: true });
        });
    }
}());


// ===== 仙陨暗隙/天烬仙庐 面板加载 =====
async function loadRiftPanel() {
    var wpPanel = document.getElementById('worldBossPanel');
    var npcPanel = document.getElementById('npcPanel');
    try {
        var res = await api.get('/api/world_boss/area_state');
        if (res.code === 200 && res.data) {
            var d = res.data;
            if (d.isFirstKillCompleted && !d.isBossActive) {
                // 首杀完成且Boss未激活 → 显示NPC面板
                if (wpPanel) wpPanel.classList.add('hidden');
                if (npcPanel) npcPanel.classList.remove('hidden');
                loadWbLastResult();
            } else {
                // Boss激活或首杀未完成 → 显示Boss面板
                if (npcPanel) npcPanel.classList.add('hidden');
                if (wpPanel) {
                    wpPanel.classList.remove('hidden');
                    fetchWorldBossStatus();
                }
            }
        }
    } catch (e) {
        // 降级：显示Boss面板
        if (wpPanel) wpPanel.classList.remove('hidden');
        fetchWorldBossStatus();
    }
}

function toggleWbLastResult() {
    var wrap = document.getElementById('wbLastResult');
    if (!wrap) return;
    wrap.classList.toggle('wb-last-result--collapsed');
}

async function loadWbLastResult() {
    var wrap = document.getElementById('wbLastResult');
    var list = document.getElementById('wbLastResultList');
    var meta = document.getElementById('wbLastResultMeta');
    if (!wrap || !list) return;
    try {
        var res = await api.get('/api/world_boss/last_result');
        if (res.code !== 200 || !res.data || !res.data.hasResult) {
            wrap.classList.add('hidden');
            return;
        }
        var d = res.data;
        wrap.classList.remove('hidden');
        if (meta) {
            var dt = d.killTime ? new Date(d.killTime) : null;
            var dateStr = dt ? (dt.getFullYear() + '-' + String(dt.getMonth() + 1).padStart(2, '0') + '-' + String(dt.getDate()).padStart(2, '0')) : d.instanceId;
            meta.textContent = dateStr + ' · 尾刀：' + (d.killerName || '—');
        }
        var html = '';
        (d.topRanks || []).forEach(function (r) {
            var cls = 'wb-rank-row';
            if (r.rank === 1) cls += ' wb-rank-top1';
            else if (r.rank <= 3) cls += ' wb-rank-top3';
            html += '<div class="' + cls + '">' +
                '<div class="wb-rank-num">' + r.rank + '</div>' +
                '<div class="wb-rank-name">' + escapeHtml(r.name) +
                    (r.isKiller ? '<span class="wb-rank-killer-tag">尾刀</span>' : '') +
                '</div>' +
                '<div class="wb-rank-dmg">' + (r.damage || 0).toLocaleString() + '</div>' +
                (r.rewardText ? '<div class="wb-rank-reward">' + escapeHtml(r.rewardText) + '</div>' : '') +
                '</div>';
        });
        list.innerHTML = html || '<div class="wb-rank-reward">暂无战报数据</div>';
    } catch (e) {
        console.error('load wb last result error', e);
        wrap.classList.add('hidden');
    }
}

function toggleNpcExchange() {
    var list = document.getElementById('npcExchangeList');
    if (!list) return;
    if (list.classList.contains('hidden')) {
        list.classList.remove('hidden');
        loadNpcExchange();
    } else {
        list.classList.add('hidden');
    }
}

async function loadNpcExchange() {
    var container = document.getElementById('npcExchangeList');
    if (!container) return;
    try {
        var res = await api.get('/api/world_boss/exchange');
        if (res.code === 200 && res.data) {
            var exchangeData = normalizeWorldBossExchangeData(res.data);
            var html = renderWorldBossExchangeBalance(exchangeData.tokenCount);
            exchangeData.items.forEach(function(item) {
                    var disabled = exchangeData.tokenCount !== null && exchangeData.tokenCount < item.cost ? ' disabled title="背包印记不足"' : '';
                    html += '<div class="wb-exchange-item">' +
                    '<div class="wb-exchange-info">' +
                    '<div class="wb-exchange-name">' + escapeHtml(item.name) + '</div>' +
                    '<div class="wb-exchange-desc">' + escapeHtml(item.description) + ' (' + item.cost + '枚印记)</div>' +
                    '</div>' +
                    '<button class="wb-exchange-btn" onclick="doNpcExchange(\'' + item.id + '\')"' + disabled + '>兑换</button>' +
                    '</div>';
            });
            container.innerHTML = html || '<div style="text-align:center;color:#666;padding:10px;">暂无兑换商品</div>';
        }
    } catch (e) { console.error('load npc exchange error', e); }
}

async function doNpcExchange(exchangeId) {
    try {
        var res = await api.post('/api/world_boss/exchange', { exchangeId: exchangeId });
        if (res.code === 200 && res.data) {
            showToast(res.data.message);
            loadNpcExchange();
        } else {
            showToast(res.message || '兑换失败');
        }
    } catch (e) {
        showToast('兑换请求异常');
    }
}


