/* ===== 黑名单管理 ===== */
var BL_FLAG_TRADE = 1;
var BL_FLAG_PROTECTOR = 2;

function openBlacklistModal() {
    var modal = document.getElementById('blacklistModal');
    if (!modal) return;
    modal.classList.remove('hidden');
    var input = document.getElementById('blacklistAddName');
    if (input) input.value = '';
    loadBlacklistEntries();
}

function closeBlacklistModal() {
    var modal = document.getElementById('blacklistModal');
    if (modal) modal.classList.add('hidden');
}

async function loadBlacklistEntries() {
    var container = document.getElementById('blacklistListContainer');
    var countText = document.getElementById('blacklistCountText');
    if (!container) return;
    container.innerHTML = '<div class="blacklist-empty">加载中...</div>';
    try {
        var res = await api.get('/api/game/blacklist');
        if (res.code !== 200) {
            container.innerHTML = '<div class="blacklist-empty">加载失败</div>';
            return;
        }
        var items = res.data || [];
        if (countText) countText.textContent = '共 ' + items.length + ' / 50 人';
        if (items.length === 0) {
            container.innerHTML = '<div class="blacklist-empty">暂无黑名单成员</div>';
            return;
        }
        var html = '';
        items.forEach(function(it) {
            var dateStr = new Date(it.createdAt).toLocaleDateString();
            var hasTrade = (it.flags & BL_FLAG_TRADE) !== 0;
            var hasProtector = (it.flags & BL_FLAG_PROTECTOR) !== 0;
            var safeName = jsAttr(it.name);
            html += '<div class="blacklist-row" data-target-id="' + it.id + '" data-flags="' + it.flags + '">'
                + '<div class="blacklist-row__info">'
                + '<div class="blacklist-row__name">' + escapeHtml(it.name) + '</div>'
                + '<div class="blacklist-row__date">拉黑于 ' + dateStr + '</div>'
                + '</div>'
                + '<div class="blacklist-row__actions">'
                + '<div class="blacklist-row__flags">'
                + '<label class="blacklist-flag blacklist-flag--trade">'
                + '<input type="checkbox" ' + (hasTrade ? 'checked' : '') + ' onchange="toggleBlacklistFlag(' + it.id + ', ' + BL_FLAG_TRADE + ', this)">'
                + '<span>交易</span>'
                + '</label>'
                + '<label class="blacklist-flag blacklist-flag--protector">'
                + '<input type="checkbox" ' + (hasProtector ? 'checked' : '') + ' onchange="toggleBlacklistFlag(' + it.id + ', ' + BL_FLAG_PROTECTOR + ', this)">'
                + '<span>护道</span>'
                + '</label>'
                + '</div>'
                + '<button class="blacklist-remove-btn" onclick="removeBlacklistEntry(' + it.id + ', ' + safeName + ')">移除</button>'
                + '</div>'
                + '</div>';
        });
        container.innerHTML = html;
    } catch (e) {
        container.innerHTML = '<div class="blacklist-empty">加载异常</div>';
    }
}

async function addBlacklistEntry() {
    var input = document.getElementById('blacklistAddName');
    if (!input) return;
    var name = (input.value || '').trim();
    if (!name) { showToast('请输入玩家昵称'); return; }
    var res = await api.post('/api/game/blacklist/add', { targetName: name, flags: 3 });
    if (res.code === 200) {
        showToast(res.message || '已加入黑名单');
        input.value = '';
        loadBlacklistEntries();
    } else {
        showToast(res.message || '加入失败');
    }
}

async function toggleBlacklistFlag(targetId, flag, checkbox) {
    var enabled = !!(checkbox && checkbox.checked);
    var rowEl = checkbox && checkbox.closest ? checkbox.closest('.blacklist-row') : null;
    if (!rowEl) {
        showToast('未找到记录');
        loadBlacklistEntries();
        return;
    }
    var oldFlags = parseInt(rowEl.dataset.flags || '0', 10) || 0;
    var newFlags = enabled ? (oldFlags | flag) : (oldFlags & ~flag);
    if (newFlags === 0) {
        showToast('至少保留一项，取消全部请点移除');
        checkbox.checked = (oldFlags & flag) !== 0;
        return;
    }
    if (newFlags === oldFlags) return;

    var seq = (parseInt(rowEl.dataset.flagSeq || '0', 10) || 0) + 1;
    rowEl.dataset.flagSeq = String(seq);
    rowEl.dataset.flags = String(newFlags);
    try {
        var upd = await api.post('/api/game/blacklist/update', { targetId: targetId, flags: newFlags });
        if (upd.code === 200) {
            showToast('权限已更新');
        } else {
            showToast(upd.message || '更新失败');
            if (rowEl.dataset.flagSeq === String(seq)) {
                rowEl.dataset.flags = String(oldFlags);
                checkbox.checked = (oldFlags & flag) !== 0;
            }
        }
    } catch (e) {
        showToast('操作失败');
        if (rowEl.dataset.flagSeq === String(seq)) {
            rowEl.dataset.flags = String(oldFlags);
            checkbox.checked = (oldFlags & flag) !== 0;
        }
    }
}

async function removeBlacklistEntry(targetId, name) {
    gameConfirm('确定将「' + name + '」移出黑名单？', async function() {
        var res = await api.post('/api/game/blacklist/remove', { targetId: targetId });
        if (res.code === 200) {
            showToast('已移出黑名单');
            loadBlacklistEntries();
        } else {
            showToast(res.message || '移出失败');
        }
    });
}

/* ===== 全局跑马灯公告逻辑 ===== */
var _marqueeQueue = [];
var _marqueeActive = false;
var _marqueeTimeout = null;
var _marqueeEnabled = localStorage.getItem('lv_marquee') !== 'off';

function toggleMarquee(on) {
    _marqueeEnabled = !!on;
    localStorage.setItem('lv_marquee', on ? 'on' : 'off');
    if (!on) {
        _marqueeQueue.length = 0;
        _marqueeActive = false;
        var bc = document.getElementById('marqueeBannerContent');
        if (bc) bc.classList.add('hidden');
        if (typeof checkGlobalBannerVisibility === 'function') checkGlobalBannerVisibility();
    }
    // 多终端同步: 持久化到服务端
    window._marqueePending = true;
    api.post('/api/player/toggle-marquee', { enabled: !!on }).finally(function() {
        window._marqueePending = false;
    });
}

function initMarqueeToggle() {
    var cb = document.getElementById('marqueeToggle');
    if (cb) cb.checked = _marqueeEnabled;
}

function enqueueMarquee(msg) {
    if (!_marqueeEnabled) return;
    _marqueeQueue.push(msg);
    if (!_marqueeActive) {
        showNextMarquee();
    }
}

function showNextMarquee() {
    var bannerContent = document.getElementById('marqueeBannerContent');
    if (!bannerContent) return;
    
    if (_marqueeQueue.length === 0) {
        _marqueeActive = false;
        bannerContent.classList.add('hidden');
        if (typeof checkGlobalBannerVisibility === 'function') checkGlobalBannerVisibility();
        return;
    }
    
    _marqueeActive = true;
    var msg = _marqueeQueue.shift();
    var textEl = document.getElementById('marqueeTextContent');
    
    // Reset animation
    textEl.style.animation = 'none';
    textEl.offsetHeight; // trigger reflow
    
    var playerName = msg.name || '神秘道友';
    if (playerName === '系统广播' || playerName === '护道打赏' || !msg.trialTitle) {
        textEl.textContent = msg.content;
    } else {
        var location = msg.content || '未知区域';
        var itemName = msg.trialTitle || '奇珍异宝';
        textEl.textContent = "气运夺天！恭喜道友 " + playerName + " 在 " + location + " 意外寻得 " + itemName + "！";
    }
    
    if (typeof getItemColor === 'function') {
        var c = getItemColor(msg.channel || '4');
        if (playerName === '护道打赏' && (!msg.channel || msg.channel === '')) {
            c = '#FFD700'; // 黄金色
        }
        textEl.style.color = c;
        textEl.style.textShadow = '0 0 5px ' + c + '80';
    }
    
    bannerContent.classList.remove('hidden');
    var container = document.getElementById('globalBannerContainer');
    if (container) container.style.display = 'block';
    
    textEl.style.animation = 'marquee-scroll 20s linear forwards';
    
    // 使用 onanimationend 监听替代 setTimeout 以完美兼容网页后台休眠
    textEl.onanimationend = function() {
        if (_marqueeActive) {
            showNextMarquee();
        }
    };
}

// ===== 遭遇中使用符篆 =====
function showEncounterTalismanDialog() {
    cancelEncounterAutoHireRetry();
    document.getElementById('encounterTalismanDialog').classList.remove('hidden');
    loadEncounterTalismans();
}

function hideEncounterTalismanDialog() {
    document.getElementById('encounterTalismanDialog').classList.add('hidden');
}

var _useTalismanInFlight = false;
var _encounterTalismanUseDelayMs = 560;

function encounterTalismanDelay(ms) {
    return new Promise(function(resolve) {
        setTimeout(resolve, ms);
    });
}

function clampEncounterTalismanQuantity(input) {
    if (!input) return 1;
    var max = parseInt(input.getAttribute('max'), 10) || 1;
    var value = parseInt(input.value, 10);
    if (!isFinite(value) || value < 1) value = 1;
    if (value > max) value = max;
    input.value = String(value);
    return value;
}

function getSelectedEncounterTalismans() {
    var selected = [];
    document.querySelectorAll('#encounterTalismanList .encounter-talisman-checkbox:checked').forEach(function(cb) {
        var row = cb.closest('[data-encounter-talisman-row]');
        if (!row) return;
        var qtyInput = row.querySelector('.encounter-talisman-qty');
        selected.push({
            itemId: Number(cb.getAttribute('data-item-id')),
            name: cb.getAttribute('data-item-name') || '',
            quantity: clampEncounterTalismanQuantity(qtyInput)
        });
    });
    return selected.filter(function(entry) {
        return entry.itemId > 0 && entry.quantity > 0;
    });
}

function updateEncounterTalismanBatchSummary() {
    var selected = getSelectedEncounterTalismans();
    var totalQty = selected.reduce(function(sum, entry) { return sum + entry.quantity; }, 0);
    var summary = document.getElementById('encounterTalismanBatchSummary');
    var useBtn = document.getElementById('encounterTalismanBatchUseBtn');
    var clearBtn = document.getElementById('encounterTalismanBatchClearBtn');
    if (summary) {
        summary.textContent = selected.length > 0
            ? '已选 ' + selected.length + ' 种 / ' + totalQty + ' 张'
            : '未选择符箓';
    }
    if (useBtn) useBtn.disabled = selected.length === 0 || _useTalismanInFlight;
    if (clearBtn) clearBtn.disabled = selected.length === 0 || _useTalismanInFlight;
    document.querySelectorAll('#encounterTalismanList [data-encounter-talisman-row]').forEach(function(row) {
        var checked = !!row.querySelector('.encounter-talisman-checkbox:checked');
        row.style.borderColor = checked ? 'var(--text-gold)' : 'var(--border-color)';
        row.style.background = checked ? 'rgba(212,175,55,0.12)' : 'rgba(0,0,0,0.2)';
    });
}

function clearEncounterTalismanSelection() {
    document.querySelectorAll('#encounterTalismanList .encounter-talisman-checkbox').forEach(function(cb) {
        cb.checked = false;
    });
    document.querySelectorAll('#encounterTalismanList .encounter-talisman-qty').forEach(function(input) {
        input.value = '1';
    });
    updateEncounterTalismanBatchSummary();
}

function getSelectedAutoProcessTalismanBaseIds() {
    var selected = [];
    document.querySelectorAll('#autoProcessTalismanOptions .auto-process-talisman-checkbox:checked').forEach(function(cb) {
        var baseId = cb.getAttribute('data-base-id') || '';
        if (baseId) selected.push(baseId);
    });
    var maxSelected = _autoProcessTalismanSettings && _autoProcessTalismanSettings.maxSelected
        ? _autoProcessTalismanSettings.maxSelected
        : 3;
    return selected.slice(0, maxSelected);
}

function updateAutoProcessTalismanSummary(changedCheckbox) {
    var settings = _autoProcessTalismanSettings || { maxSelected: 3 };
    var maxSelected = settings.maxSelected || 3;
    var selected = [];
    document.querySelectorAll('#autoProcessTalismanOptions .auto-process-talisman-checkbox:checked').forEach(function(cb) {
        selected.push(cb);
    });
    if (selected.length > maxSelected && changedCheckbox) {
        changedCheckbox.checked = false;
        showToast('自动符篆最多选择 ' + maxSelected + ' 类');
        selected = selected.filter(function(cb) { return cb !== changedCheckbox; });
    }
    var enabled = !!(document.getElementById('autoProcessTalismanEnabledInput') || {}).checked;
    var summary = document.getElementById('autoProcessTalismanSummary');
    if (summary) {
        if (!enabled) summary.textContent = '未启用';
        else if (selected.length === 0) summary.textContent = '未选择符篆';
        else summary.textContent = '已选 ' + selected.length + '/' + maxSelected + ' 类';
    }
    document.querySelectorAll('#autoProcessTalismanOptions [data-auto-talisman-option]').forEach(function(label) {
        var checked = !!label.querySelector('.auto-process-talisman-checkbox:checked');
        label.classList.toggle('is-selected', checked);
    });
}

async function loadEncounterTalismans() {
    var list = document.getElementById('encounterTalismanList');
    list.innerHTML = '<div style="text-align:center;padding:20px;color:var(--text-gray)">加载中...</div>';
    updateEncounterTalismanBatchSummary();
    try {
        var res = await api.get('/api/game/inventory');
        if (res.code === 200) {
            var talismans = res.data.filter(function(it) {
                return it.templateId && it.templateId.indexOf('talisman_stealth_') !== 0 && (/^(bp_)?talisman_/.test(it.templateId)) && /_\d$/.test(it.templateId) && (it.type === 'misc' || it.type === 'talisman');
            });
            if (talismans.length === 0) {
                list.innerHTML = '<div style="text-align:center;padding:20px;color:var(--text-gray)">储物中暂无可用的<b style="color:var(--text-gold)">战斗符箓</b>。<br><span style="font-size:12px;color:var(--text-muted);">(神行符、传送符、替死符等非战时符箓不在此显示)</span></div>';
                return;
            }
            var gradeColors = ['#a0a0a0', '#60c0e0', '#e0a040', '#d050e0', '#ff6040'];
            list.innerHTML = '';
            talismans.forEach(function(item) {
                var gradeMatch = item.templateId.match(/_(\d)$/);
                var grade = gradeMatch ? parseInt(gradeMatch[1]) : (item.rarity || 1);
                var color = gradeColors[grade - 1] || '#ccc';
                var safeName = escapeHtml(item.name);
                var safeDesc = escapeHtml(item.description || '');

                var row = document.createElement('div');
                row.setAttribute('data-encounter-talisman-row', '1');
                row.style.cssText = 'border: 1px solid var(--border-color); border-radius: 8px; padding: 12px; display: flex; gap:10px; justify-content: space-between; align-items: center; background: rgba(0,0,0,0.2); cursor:pointer;';

                var checkbox = document.createElement('input');
                checkbox.type = 'checkbox';
                checkbox.className = 'encounter-talisman-checkbox';
                checkbox.setAttribute('data-item-id', String(item.id));
                checkbox.setAttribute('data-item-name', item.name || '');
                checkbox.setAttribute('aria-label', '选择' + (item.name || '符箓'));
                checkbox.style.cssText = 'width:18px;height:18px;flex-shrink:0;accent-color:var(--text-gold);';
                checkbox.addEventListener('change', updateEncounterTalismanBatchSummary);

                var info = document.createElement('div');
                info.style.cssText = 'flex:1; min-width:0; padding-right:8px;';
                info.innerHTML = '<div style="font-weight:bold; font-size:14px; color:' + color + ';">' + safeName + ' <span style="font-size:12px;color:var(--text-gray);font-weight:normal;">×' + item.quantity + '</span></div>'
                    + '<div style="font-size:12px; color:var(--text-gray); margin-top:4px; line-height:1.4;">' + safeDesc + '</div>';

                var qty = document.createElement('input');
                qty.type = 'number';
                qty.inputMode = 'numeric';
                qty.min = '1';
                qty.max = String(item.quantity || 1);
                qty.value = '1';
                qty.className = 'encounter-talisman-qty';
                qty.setAttribute('autocomplete', 'off');
                qty.setAttribute('aria-label', '使用数量');
                qty.style.cssText = 'width:58px;min-width:58px;padding:6px 4px;border-radius:6px;border:1px solid var(--border-color);background:rgba(0,0,0,0.22);color:var(--text-primary);text-align:center;';
                if ((item.quantity || 0) <= 1) qty.disabled = true;
                qty.addEventListener('input', updateEncounterTalismanBatchSummary);
                qty.addEventListener('change', updateEncounterTalismanBatchSummary);

                row.appendChild(checkbox);
                row.appendChild(info);
                row.appendChild(qty);
                row.addEventListener('click', function(e) {
                    var tag = e.target && e.target.tagName ? e.target.tagName.toLowerCase() : '';
                    if (tag === 'input' || tag === 'button') return;
                    checkbox.checked = !checkbox.checked;
                    updateEncounterTalismanBatchSummary();
                });

                list.appendChild(row);
            });
            updateEncounterTalismanBatchSummary();
        } else {
            list.innerHTML = '<div style="text-align:center;padding:20px;color:var(--text-gray)">' + escapeHtml(res.message || '加载失败') + '</div>';
            updateEncounterTalismanBatchSummary();
        }
    } catch (e) {
        console.error('loadEncounterTalismans error:', e);
        list.innerHTML = '<div style="text-align:center;padding:20px;color:var(--text-gray)">加载失败，请关闭后重试</div>';
        updateEncounterTalismanBatchSummary();
    }
}

async function postEncounterTalismanUse(itemId, quantity) {
    var payload = { itemId: itemId, quantity: quantity || 1 };
    var res = await api.post('/api/game/use-item', payload);
    var message = res && (res.message || res.data || '');
    if (res && res.code !== 200 && (message.indexOf('操作太快') >= 0 || message.indexOf('过于频繁') >= 0)) {
        await encounterTalismanDelay(_encounterTalismanUseDelayMs);
        res = await api.post('/api/game/use-item', payload);
    }
    return res;
}

async function useSelectedEncounterTalismans() {
    if (_useTalismanInFlight) return;
    var selected = getSelectedEncounterTalismans();
    if (selected.length === 0) {
        showToast('请先勾选要使用的战斗符箓');
        return;
    }
    _useTalismanInFlight = true;
    updateEncounterTalismanBatchSummary();
    var usedCount = 0;
    var usedQty = 0;
    var failedMessage = '';
    try {
        for (var i = 0; i < selected.length; i++) {
            var entry = selected[i];
            var payload = { itemId: entry.itemId, quantity: entry.quantity };
            var res = await postEncounterTalismanUse(payload.itemId, payload.quantity);
            if (res.code !== 200) {
                failedMessage = res.message || (entry.name ? entry.name + ' 使用失败' : '使用失败');
                break;
            }
            usedCount += 1;
            usedQty += entry.quantity;
            if (i < selected.length - 1) {
                await encounterTalismanDelay(_encounterTalismanUseDelayMs);
            }
        }
        if (usedCount > 0) {
            showToast(failedMessage
                ? '已使用 ' + usedCount + ' 种 / ' + usedQty + ' 张；' + failedMessage
                : '已使用 ' + usedCount + ' 种 / ' + usedQty + ' 张战斗符箓');
            loadPlayerInfo();
            loadEncounterTalismans();
        } else {
            showToast(failedMessage || '使用失败');
        }
    } catch (e) {
        console.error('useSelectedEncounterTalismans error:', e);
        showToast('使用失败，请重试');
    } finally {
        _useTalismanInFlight = false;
        updateEncounterTalismanBatchSummary();
    }
}

async function useEncounterTalisman(itemId, name) {
    if (_useTalismanInFlight) return;
    _useTalismanInFlight = true;
    updateEncounterTalismanBatchSummary();
    try {
        var res = await postEncounterTalismanUse(itemId, 1);
        if (res.code === 200) {
            showToast(res.data || name + ' 已激活');
            loadPlayerInfo();
        } else {
            showToast(res.message || '使用失败');
        }
    } catch (e) {
        console.error('useEncounterTalisman error:', e);
        showToast('使用失败，请重试');
    } finally {
        _useTalismanInFlight = false;
        updateEncounterTalismanBatchSummary();
    }
}

// ===== Encounter Protector Hiring =====
async function showEncounterProtectorDialog() {
    if (_hireProtectorInFlight) return;
    var autoFlowActive = _autoExploreRunning || _autoResumeExplorePending || _autoCombatInFlight || !!_encounterAutoHireRetryTimer;
    cancelEncounterAutoHireRetry();
    try {
        var res = await api.get('/api/game/check-encounter');
        if (res && res.code === 200 && res.data && res.data.hasEncounter) {
            var d = res.data;
            if (d.rescueCost > 0) {
                await checkPendingEncounter();
                return;
            }
            showEncounterPanel(
                d.monsterName, d.monsterRealmName,
                d.monsterHp, d.monsterAtk, d.monsterDef,
                d.areaName, d.fleeChance,
                d.spiritRootName, d.spiritRootColor,
                d.monsterId,
                d.monsterRealmLevel,
                d.assistPending,
                d.rescueCooldownSec,
                d.monsterPower,
                d.playerPower,
                d.monsterAffixLabel,
                d.monsterAffixName,
                d.monsterAffixDesc,
                d.playerStage,
                d.rewardMultiplier
            );
        } else {
            hideEncounterPanel();
            if (autoFlowActive) {
                await loadPlayerInfo(true);
                refreshInventoryAfterCombatSettlement();
                return;
            }
            showToast('当前遭遇已结束，请重新探索');
            return;
        }
    } catch (e) {
        console.error('check encounter before hire failed:', e);
        showToast('遭遇状态确认失败，请稍后再试');
        return;
    }
    document.getElementById('encounterProtectorDialog').classList.remove('hidden');
    loadEncounterProtectors();
}

function hideEncounterProtectorDialog() {
    var dialog = document.getElementById('encounterProtectorDialog');
    if (dialog) dialog.classList.add('hidden');
}

function isDisabledMasterProtector(p) {
    if (typeof p.quotaRemaining === 'number' && p.quotaRemaining <= 0) return true;
    if (p.role === 'masterIncarnation') return p.isAvailable === false || p.hp <= 0;
    if (p.role === 'masterBody') return p.isAvailable === false || p.isDead || p.isMeditating;
    return false;
}

function renderEncounterFriendProtectors(list) {
    if (!Array.isArray(list) || list.length === 0) return '';
    var html = '';
    list.forEach(function(p) {
        var escapedName = escapeHtml(p.helperName || '道友');
        var jsSafeName = escapedName.replace(/'/g, "\\'");
        var mode = p.mode === 'alone' ? 'alone' : 'together';
        var modeText = mode === 'alone' ? '单独代战' : '同行护道';
        var remainMin = Math.max(1, Math.ceil(((Number(p.expiresAt) || Date.now()) - Date.now()) / 60000));
        html += `
            <div class="protector-card protector-card--friend">
                <div class="prot-head prot-head--friend">
                    <div style="min-width:0;flex:1;">
                        <span class="prot-master-tag prot-master-tag--friend">道 友</span>
                        <span class="prot-name" style="margin-left:6px;">${escapedName}</span>
                        <span class="prot-realm" style="margin-left:4px;">· ${escapeHtml(p.helperRealmName || '')}</span>
                    </div>
                    <span class="prot-free">已 就 位</span>
                </div>
                <div class="prot-master-desc">好友护道　${escapeHtml(modeText)}　剩余约 <b>${remainMin}</b> 分钟　地点 ${escapeHtml(p.areaName || '')}</div>
                <button class="prot-btn-master prot-btn-master--friend" onclick="hireEncounterFriendProtector(${p.helperId}, '${mode}', '${jsSafeName}')">好 友 护 道</button>
            </div>
        `;
    });
    return html;
}

async function loadEncounterProtectors() {
    const list = document.getElementById('encounterProtectorList');
    list.innerHTML = '<div style="text-align:center;padding:20px;color:var(--text-gray)">加载中...</div>';
    try {
        const results = await Promise.all([
            api.get('/api/dungeon/protectors?' + buildEncounterProtectorQuery()),
            api.get('/api/friend/protect/active')
        ]);
        const res = results[0];
        const friendRes = results[1];
        const activeFriends = (friendRes && friendRes.code === 200 && Array.isArray(friendRes.data)) ? friendRes.data : [];
        if (res.code === 200) {
            const data = Array.isArray(res.data) ? res.data : [];
            let html = renderEncounterFriendProtectors(activeFriends);
            if (data.length === 0) {
                if (html) {
                    list.innerHTML = html;
                    return;
                }
                list.innerHTML = '<div style="text-align:center;padding:20px;color:var(--text-gray)">当前暂无空闲的护道者。<br>道友可以自己去挂牌哦！</div>';
                return;
            }
            const filtered = data.slice();
            if (filtered.length === 0) {
                if (html) {
                    list.innerHTML = html;
                    return;
                }
                list.innerHTML = '<div style="text-align:center;padding:20px;color:var(--text-gray)">当前暂无空闲的护道者。<br>道友可以自己去挂牌哦！</div>';
                return;
            }
            filtered.sort(function(a, b) {
                const aMaster = a.role === 'masterBody' || a.role === 'masterIncarnation';
                const bMaster = b.role === 'masterBody' || b.role === 'masterIncarnation';
                if (aMaster !== bMaster) {
                    return aMaster ? -1 : 1;
                }
                const aDisabledMaster = isDisabledMasterProtector(a);
                const bDisabledMaster = isDisabledMasterProtector(b);
                if (aDisabledMaster !== bDisabledMaster) {
                    return aDisabledMaster ? 1 : -1;
                }
                const aUnavailable = !a.isAvailable || a.isMeditating || a.isDead || a.hp <= 0;
                const bUnavailable = !b.isAvailable || b.isMeditating || b.isDead || b.hp <= 0;
                if (aUnavailable !== bUnavailable) {
                    return aUnavailable ? 1 : -1;
                }
                return Math.min(a.feeTogether, a.feeAlone) - Math.min(b.feeTogether, b.feeAlone);
            });
            filtered.forEach(p => {
                const escapedName = escapeHtml(p.name);
                const jsSafeName = escapedName.replace(/'/g, "\\'");
                const isDead = p.isDead || p.hp <= 0;
                const hpPct = p.maxHp > 0 ? Math.round(p.hp * 100 / p.maxHp) : 0;
                const hpColor = hpPct >= 80 ? 'var(--accent-jade)' : hpPct >= 50 ? 'var(--accent-gold)' : hpPct >= 20 ? '#ff9a47' : 'var(--text-danger)';

                // 师徒·师父本体 / 化身护道卡
                if (p.role === 'masterBody' || p.role === 'masterIncarnation') {
                    const isInc = p.role === 'masterIncarnation';
                    const disabled = isDisabledMasterProtector(p);
                    const label = isInc ? '化 身 护 道' : '本 体 护 道';
                    const quotaRem = (typeof p.quotaRemaining === 'number') ? p.quotaRemaining : null;
                    const quotaExhausted = quotaRem !== null && quotaRem <= 0;
                    let disabledReason = '';
                    let disabledLabel = '';
                    if (quotaExhausted) {
                        disabledReason = '今日次数已用尽';
                        disabledLabel = '次 数 用 尽';
                    } else if (isInc && p.hp <= 0) {
                        disabledReason = '化身重伤难行';
                        disabledLabel = '化 身 重 伤';
                    } else if (!isInc && p.isDead) {
                        disabledReason = '师父已陨落';
                        disabledLabel = '已 陨 落';
                    } else if (!isInc && p.isMeditating) {
                        disabledReason = '闭关冥想中';
                        disabledLabel = '闭 关 冥 想';
                    } else if (p.isAvailable === false) {
                        disabledReason = isInc ? '化身正在护道' : '师父正在护道';
                        disabledLabel = '正 在 护 道';
                    }
                    if (disabled && !disabledReason) {
                        disabledReason = '暂不可雇佣';
                        disabledLabel = '暂 不 可 用';
                    }
                    const quotaTag = quotaRem === null ? '' : (quotaExhausted
                        ? `　<span style="color:var(--text-danger);">今日次数已用尽</span>`
                        : `　今日剩余 <b style="color:var(--text-gold);">${quotaRem}</b> 次`);
                    const bodyStateTail = quotaExhausted
                        ? ''
                        : (p.isDead ? ` <span style="color:var(--text-danger);">· 已陨落</span>`
                            : p.isMeditating ? ` <span style="color:var(--text-danger);">· 闭关冥想</span>` : '');
                    const incStateTail = quotaExhausted ? '' : (p.hp <= 0 ? ' <span style="color:var(--text-danger);">· 重伤难行</span>' : '');
                    const stateDesc = isInc
                        ? `化身气血 <b style="color:${hpColor};">${p.hp}/${p.maxHp}</b>　攻 <b>${p.attack}</b>　防 <b>${p.defense}</b>${incStateTail}${quotaTag}`
                        : `本体亲临，免雇佣费，无视地图${bodyStateTail}${quotaTag}`;
                    const masterBlockedNotice = !isInc && p.isMeditating
                        ? '<div class="prot-master-blocked">闭关冥想中，暂不可本体护道</div>'
                        : '';
                    const fn = isInc ? 'hireEncounterMasterIncarnation' : 'hireEncounterMasterBody';
                    html += `
                        <div class="protector-card protector-card--master${disabled ? ' protector-card--mute' : ''}">
                            <div class="prot-head prot-head--master">
                                <div style="min-width:0;flex:1;">
                                    <span class="prot-master-tag">师 父</span>
                                    <span class="prot-name" style="margin-left:6px;">${escapedName}</span>
                                    <span class="prot-realm" style="margin-left:4px;">· ${escapeHtml(p.realmName)}</span>
                                    ${disabledReason ? `<span class="prot-master-status">${escapeHtml(disabledReason)}</span>` : ''}
                                </div>
                                <span class="prot-free">免 费</span>
                            </div>
                            <div class="prot-master-desc">${stateDesc}</div>
                            ${masterBlockedNotice}
                            ${p.note && isInc ? `<div class="prot-note">${escapeHtml(p.note)}</div>` : ''}
                            <button class="prot-btn-master${disabledReason ? ' prot-btn-master--blocked' : ''}" onclick="${fn}(${p.playerId}, '${jsSafeName}')" ${disabled ? 'disabled' : ''} ${disabledReason ? `title="${escapeHtml(disabledReason)}"` : ''}>${disabledLabel || label}</button>
                        </div>
                    `;
                    return;
                }

                // 普通护道者卡
                const unavailable = (!p.isAvailable || p.isMeditating || isDead);
                const statusBadge = unavailable
                    ? `<span class="prot-badge prot-badge--busy">${isDead ? '重 伤' : p.isMeditating ? '冥 想' : '忙 碌'}</span>`
                    : `<span class="prot-badge prot-badge--ok">可 接 单</span>`;

                const actionRow = unavailable
                    ? `<div class="prot-empty">暂 不 可 雇 佣</div>`
                    : `<div class="prot-btn-row">
                        <button class="prot-btn" title="你与护道者并肩作战，双方按比例承担伤害" onclick="hireEncounterProtectorDirect(${p.playerId}, 'together', '${jsSafeName}', ${Number(p.feeTogether) || 0})">
                            <span>协 同</span>
                            <span class="prot-btn__price">${formatNumber(p.feeTogether)}</span>
                        </button>
                        <button class="prot-btn prot-btn--solo" title="你隐匿旁观，护道者替你承担所有攻击，陨落为真实死亡" onclick="hireEncounterProtectorDirect(${p.playerId}, 'alone', '${jsSafeName}', ${Number(p.feeAlone) || 0})">
                            <span>单 独</span>
                            <span class="prot-btn__price">${formatNumber(p.feeAlone)}</span>
                        </button>
                    </div>`;

                html += `
                    <div class="protector-card${unavailable ? ' protector-card--mute' : ''}">
                        <button class="prot-banish" data-pid="${p.playerId}" data-pname="${escapedName}" onclick="encounterBlacklist(+this.dataset.pid, this.dataset.pname)" title="加入护道黑名单">✕</button>
                        <div class="prot-head">
                            <span class="prot-name">${escapedName}</span>
                            <span class="prot-realm">· ${escapeHtml(p.realmName)}</span>
                            ${statusBadge}
                        </div>
                        <div class="prot-stats">
                            <span>血 <b style="color:${hpColor};">${p.hp}/${p.maxHp}</b></span>
                            <span>攻 <b>${p.attack}</b></span>
                            <span>防 <b>${p.defense}</b></span>
                            <span class="prot-loc">◉ ${escapeHtml(p.mapName || '未知')}</span>
                        </div>
                        ${p.note ? `<div class="prot-note">${escapeHtml(p.note)}</div>` : ''}
                        ${actionRow}
                    </div>
                `;
            });
            list.innerHTML = html;
        } else {
            list.innerHTML = '<div style="text-align:center;padding:20px;color:var(--text-gray)">' + (res.message || '加载失败') + '<br><button class="btn-action" style="margin-top:10px;padding:6px 16px;" onclick="loadEncounterProtectors()">重试</button></div>';
        }
    } catch (e) {
        console.error('loadEncounterProtectors error:', e);
        list.innerHTML = '<div style="text-align:center;padding:20px;color:var(--text-gray)">加载失败，请关闭后重试<br><button class="btn-action" style="margin-top:10px;padding:6px 16px;" onclick="loadEncounterProtectors()">重试</button></div>';
    }
}

async function encounterBlacklist(targetId, name) {
    gameConfirm('<p>确认将 <strong>' + escapeHtml(name) + '</strong> 加入护道黑名单？</p><p style="font-size:12px;color:var(--text-muted);">双方将无法互相雇佣护道。</p>', async function() {
        try {
            var res = await api.post('/api/game/blacklist/add', { targetId: targetId, flags: 2 });
            if (res.code === 200) {
                showToast('已将 ' + name + ' 加入黑名单');
                loadEncounterProtectors();
            } else {
                showToast(res.message || '操作失败');
            }
        } catch (e) { showToast('操作失败'); }
    }, null, true);
}

var _hireProtectorInFlight = false;
var HIGH_PROTECTOR_FEE_CONFIRM_THRESHOLD = 500000;

async function hireEncounterMasterIncarnation(masterId, name) {
    if (_hireProtectorInFlight) return;
    gameConfirm(`<p>请师父 <strong>${escapeHtml(name)}</strong> 的身外化身护道？</p><p style="font-size:13px;color:var(--text-gray);margin-top:8px;">化身替你吃下这一战的伤害，免雇佣费。化身气血耗尽仍未阻截致命一击则徒弟仍会陨落。</p>`, async () => {
        if (_hireProtectorInFlight) return;
        _hireProtectorInFlight = true;
        hideEncounterProtectorDialog();
        showToast('化身降临中...');
        try {
            const res = await api.post('/api/game/encounter-hire-protector', {
                protectorId: masterId,
                mode: 'alone',
                role: 'masterIncarnation'
            });
            if (res.code === 200) {
                var d = res.data;
                _encounterActive = false;
                hideEncounterPanel();
                closePanel();
                if (d && d.logs && d.logs.length > 0) {
                    saveEncounterCombatLog(d);
                    var speed = d.logs.length > 15 ? 15 : 30;
                    if (isSkipCombat()) appendCompactBattleSettlement(d.logs, 'battle');
                    else await typewriterLogs(d.logs, 'battle', speed);
                }
                if (d && d.status === 'death') {
                    playerDead = true;
                    try { showDeathOverlay(true, d.reviveCost || 0, d.adPoints || 0, d.lastBattle); } catch (_) {}
                }
                _tryResumeAutoExploreAfterMerchant();
            } else {
                showToast(res.message || '召化身失败');
                // 失败路径：以服务端真实 encounter 状态为准，避免后端已清空但前端误判仍在遭遇
                await checkPendingEncounter();
            }
        } catch (e) {
            showToast('召化身失败');
            await checkPendingEncounter();
        } finally {
            _hireProtectorInFlight = false;
        }
    }, null, true);
}

