async function hireEncounterProtectorDirect(protectorId, mode, name, fee) {
    if (_hireProtectorInFlight) return;
    var hireFee = Math.max(0, parseInt(fee, 10) || 0);
    var confirmedFee = null;

    var doHire = async function() {
        if (_hireProtectorInFlight) return;
        _hireProtectorInFlight = true;
        hideEncounterProtectorDialog();
        showToast("雇佣信符传输中...");

        try {
            var payload = {
                protectorId: protectorId,
                mode: mode
            };
            if (confirmedFee !== null) payload.confirmedFee = confirmedFee;
            const res = await api.post('/api/game/encounter-hire-protector', payload);
            if (res.code === 200) {
                var d = res.data;
                _encounterActive = false;
                hideEncounterPanel();
                closePanel(); // Close side panel to view logs

                if (d && d.logs && d.logs.length > 0) {
                    saveEncounterCombatLog(d);
                    var logType = 'battle';
                    var hasDrops = d.logs.some(function(l) {
                        return l.indexOf('获得 [') !== -1 || l.indexOf('掉落 [') !== -1 || l.indexOf('掉落了 [') !== -1 || l.indexOf('发现了一枚【') !== -1;
                    });
                    if (isSkipCombat()) {
                        appendCompactBattleSettlement(d.logs, logType);
                    } else {
                        var speed = d.logs.length > 15 ? 15 : 30;
                        await typewriterLogs(d.logs, logType, speed);
                    }

                    if (d.status === 'victory' && hasDrops) {
                        var dropItems = [];
                        d.logs.forEach(function(l) {
                            var m = l.match(/\[([^\]]+)\]\s*x?\d*/g);
                            if (m && (l.indexOf('掉落') !== -1 || l.indexOf('获得 [') !== -1 || l.indexOf('发现了一枚【') !== -1)) {
                                m.forEach(function(item) {
                                    var name2 = item.replace(/[\[\]]/g, '').replace(/\s*x?\d+$/, '').trim();
                                    if (name2) dropItems.push(name2);
                                });
                            }
                            var m2 = l.match(/发现了一枚【([^】]+)】/);
                            if (m2 && m2[1]) dropItems.push(m2[1]);
                        });
                        setTimeout(function() {
                            showTipProtectorDialog(protectorId, name, dropItems);
                        }, 800);
                    }
                }

                if (d && d.status === 'death') {
                    playerDead = true;
                    showDeathOverlay(
                        playerCanSelfRevive,
                        window._lastPlayerData ? window._lastPlayerData.reviveCost : 0,
                        window._lastPlayerData ? window._lastPlayerData.adPoints : 0,
                        d.lastBattle
                    );
                }

                loadPlayerInfo();
                if (isSkipCombat()) {
                    loadGameLogs();
                }
                _tryResumeAutoExploreAfterMerchant();
            } else {
                showToast(res.message || "雇佣失败");
                await checkPendingEncounter();
            }
        } catch (e) {
            console.error("Hire Protector Error:", e);
            showToast("网络异常");
            await checkPendingEncounter();
        } finally {
            _hireProtectorInFlight = false;
        }
    };

    if (hireFee > HIGH_PROTECTOR_FEE_CONFIRM_THRESHOLD) {
        var modeText = mode === 'alone' ? '单独护道' : '协同护道';
        var confirmHtml = '<p>确认雇佣 <strong>' + escapeHtml(name) + '</strong> 进行' + modeText + '？</p>' +
            '<p style="font-size:13px;color:var(--text-gray);margin-top:8px;">本次护道费为 <b style="color:var(--text-gold);">' + formatNumber(hireFee) + '</b> 灵石，超过五十万。确认后将立即扣除，战斗成败均不退款。</p>';
        gameConfirm(confirmHtml, async function() {
            confirmedFee = hireFee;
            await doHire();
        }, null, true);
        return;
    }

    await doHire();
}

window.showTipProtectorDialog = function(protectorId, name, dropItems) {
    var dropsHtml = '';
    if (dropItems && dropItems.length > 0) {
        dropsHtml = '<div style="margin-bottom:10px; padding:8px 10px; background:rgba(201,153,58,0.08); border:1px solid rgba(201,153,58,0.2); border-radius:6px;">' +
            '<div style="font-size:12px; color:var(--text-gold); margin-bottom:4px; font-weight:600;">本次掉落</div>' +
            '<div style="font-size:13px; color:var(--text-color); line-height:1.6;">' + 
            dropItems.map(function(item) { return '- ' + escapeHtml(item); }).join('<br>') +
            '</div></div>';
    }
    var html = '<div style="margin-bottom:10px;">护道成功，你获得了丰厚的战利品！</div>' +
               dropsHtml +
               '<div style="font-size:13px; color:var(--text-gray); margin-bottom:10px;">给护道者【' + escapeHtml(name) + '】打赏一点心意吧：</div>' +
               '<input type="number" id="tipAmountInput" value="100" min="1" step="1" style="width:100%; padding:8px; background:var(--bg-black); border:1px solid var(--border-color); color:var(--text-color); border-radius:4px; margin-bottom:10px;">' +
               '<div style="font-size:11px; color:var(--text-gray); text-align:right;">(选填，也可直接取消)</div>';
               
    gameConfirm(html, async function() {
        var input = document.getElementById('tipAmountInput');
        var amtStr = input ? input.value : '';
        if (!/^\d+$/.test(amtStr)) {
            showToast("请输入有效正整数");
            showTipProtectorDialog(protectorId, name, dropItems);
            return;
        }
        var amt = parseInt(amtStr, 10);
        if (!amt || amt <= 0 || amt > 1000000000) {
            showToast("金额无效或超出限制(10亿以内)");
            showTipProtectorDialog(protectorId, name, dropItems);
            return;
        }
        try {
            var res = await api.post('/api/game/protector/tip', { protectorId: protectorId, amount: amt });
            if (res.code === 200) {
                showToast("打赏成功！");
                loadPlayerInfo();
            } else {
                showToast(res.message || "打赏失败");
            }
        } catch (e) {
            console.error("Tip Protector Error:", e);
            showToast("网络异常");
        }
    }, null, true);
}

window.showLoreModal = function() {
    var overlay = document.getElementById('loreOverlay');
    if (overlay) overlay.classList.remove('hidden');
};

window.closeLoreModal = function() {
    var overlay = document.getElementById('loreOverlay');
    if (overlay) overlay.classList.add('hidden');
};


// ===== 典当房功能 =====

function openPawnModal() {
    var modal = document.getElementById('pawnModalUI');
    if (modal) {
        modal.classList.remove('hidden');
        loadPawnItems();
    } else {
        showToast('灵宝司维护中');
    }
}

async function loadPawnItems() {
    var container = document.getElementById('pawnListContainer');
    if (!container) return;
    container.innerHTML = '<div class="loading-state">账单结算中...</div>';
    
    try {
        var res = await api.get('/api/game/pawn/list');
        if (res.code === 200) {
            renderPawnList(res.data);
        } else {
            container.innerHTML = '<div class="empty-state">获取典当记录失败: ' + escapeHtml(res.message || '未知错误') + '</div>';
        }
    } catch (err) {
        console.error(err);
        container.innerHTML = '<div class="empty-state">网络错误</div>';
    }
}

function renderPawnList(list) {
    var container = document.getElementById('pawnListContainer');
    if (!list || list.length === 0) {
        container.innerHTML = '<div class="empty-state" style="padding:20px;text-align:center;color:var(--text-secondary)">当前账面清白，毫无典当借贷。</div>';
        return;
    }
    
    var html = '';
    list.forEach(item => {
        var rarityClass = 'rarity-' + item.rarity;
        var extHtml = '';
        if (item.extension && item.extension !== 'null') {
            try {
                var extJson = JSON.parse(item.extension);
                if (extJson && extJson.affix && extJson.affix.name) {
                    extHtml = '<div class="item-desc-effect">【先天·' + escapeHtml(extJson.affix.name) + '】' + escapeHtml(extJson.affix.desc || '') + '</div>';
                }
            } catch(e){}
        }
        
        var refineHtml = item.refineLevel > 0 ? ' <span class="refine-badge">+' + item.refineLevel + '</span>' : '';
        var nameDisplay = '<span class="' + rarityClass + '">' + escapeHtml(item.name) + refineHtml + '</span>';
        var qtyDisplay = item.quantity > 1 ? ' x' + item.quantity : '';
        
        html += '<div class="market-list-item" style="display:flex; justify-content:space-between; align-items:center; border:1px solid var(--border-color); margin-bottom:8px; padding:10px; border-radius:4px;">' +
            '<div>' + 
                '<div style="font-weight:bold">' + nameDisplay + qtyDisplay + '</div>' +
                extHtml +
                '<div style="font-size:12px; color:var(--text-secondary); margin-top:4px;">需付赎金: <span style="color:#f39c12">' + item.redeemPrice + '</span> 灵石 | 赎回期限: ' + (item.expireHours || 0) + ' 小时</div>' + 
            '</div>' +
            '<button class="modal-btn modal-btn--gold" data-pawn-id="' + item.id + '" onclick="redeemPawn(' + item.id + ',' + item.redeemPrice + ')">赎回</button>' +
        '</div>';
    });
    container.innerHTML = html;
}

function redeemPawn(pawnId, redeemPrice) {
    gameConfirm('赎回该物品将花费 ' + redeemPrice + ' 灵石，确定赎回吗？', async function() {
        var btn = document.querySelector('[data-pawn-id="' + pawnId + '"]');
        if (btn) btn.disabled = true;
        try {
            var res = await api.post('/api/game/pawn/redeem', { pawnId: pawnId });
            if (res.code === 200) {
                showToast('赎回成功！');
                loadPawnItems();
                loadInventory();
                loadPlayerInfo();
            } else {
                showToast('赎回失败: ' + (res.message || '系统错误'));
            }
        } catch (err) {
            showToast('网络错乱，赎回失败');
        } finally {
            if (btn) btn.disabled = false;
        }
    });
}

var _pawnItemLock = false;
function pawnItem(itemId, sellPrice, itemName, wearRate) {
    if (_pawnItemLock) return;
    var wr = wearRate || 0;
    var inscJson = '';
    var cached = (_inventoryCache || []).find(function(x){ return x.id === itemId; });
    if (cached) inscJson = cached.inscriptionsJson || '';
    var inscBonus = calcInscriptionSellBonus(inscJson);
    var actualPrice = calcFinalSellPrice(sellPrice, wr, inscJson);
    var wearNote = '';
    if (wr > 0) {
        var wearPct = (wr / 100).toFixed(2);
        wearNote = '\n\n⚠ 装备破损 ' + wearPct + '%，已折损';
    }
    if (inscBonus > 0) {
        wearNote += (wearNote ? '\n' : '\n\n') + '✦ 铭文加价 +' + formatNumber(inscBonus) + ' 灵石';
    }
    gameConfirm('急需周转？典当【' + itemName + '】，可获得 ' + actualPrice + ' 灵石！' + wearNote + '\n\n[ 注意事项 ]\n1. 典当物品只能等额赎回并收取 20% 流水利息。\n2. 典当期仅限 7 天，逾期将自动被系统死当销毁！\n3. 抵押期间不可使用。\n\n[ 赎回指引 ]\n请前往【九霄神庭 - 灵宝司】查阅并办理赎回手续。', async function() {
        _pawnItemLock = true;
        try {
            var res = await api.post('/api/game/pawn/pawn-item', { itemId: itemId });
            if (res.code === 200) {
                showToast(res.data || '典当成功');
                loadInventory();
                loadPlayerInfo();
            } else {
                showToast('典当失败: ' + (res.message || '系统错误'));
            }
        } catch (err) {
            showToast('网络错乱，典当失败');
        } finally {
            _pawnItemLock = false;
        }
    });
}

// ================= 法相穿搭 (Equipment Grid) =================
async function loadEquipGridSummary(force) {
    if (!force && Array.isArray(_equipGridCache)) return _equipGridCache;
    var pendingCanSatisfy = !force || _equipGridPendingForce;
    if (_equipGridPending && pendingCanSatisfy) return _equipGridPending;
    _equipGridPendingForce = !!force;
    _equipGridPending = api.get('/api/game/equipment/current').then(function(res) {
        if (res.code === 200 && Array.isArray(res.data)) {
            _equipGridCache = res.data;
            renderEquipGrid();
            if (typeof renderCraftAspectPanel === 'function') renderCraftAspectPanel();
            return _equipGridCache;
        }
        return _equipGridCache || [];
    }).catch(function() {
        return _equipGridCache || [];
    }).finally(function() {
        _equipGridPending = null;
        _equipGridPendingForce = false;
    });
    return _equipGridPending;
}

function buildEquipInlineMetaHtml(item, options) {
    if (!item) return '';
    var opts = options || {};
    var showAffix = opts.showAffix !== false;
    var showInscriptions = opts.showInscriptions !== false;
    var lines = [];
    var badges = [];
    if (item.refineLevel && item.refineLevel > 0) {
        badges.push('<span class="refine-badge">+' + item.refineLevel + '</span>');
    }
    if (badges.length) {
        lines.push('<div class="equip-meta-row equip-meta-row--badges">' + badges.join('') + '</div>');
    }
    if (showAffix) {
        var affixHtml = buildEquipAffixSummaryHtml(item);
        if (affixHtml) {
            lines.push('<div class="equip-meta-row equip-meta-row--affix">' + affixHtml + '</div>');
        }
    }
    if (showInscriptions) {
        var inscHtml = (typeof formatInscriptionsHtml === 'function') ? formatInscriptionsHtml(item) : '';
        if (inscHtml) {
            lines.push('<div class="equip-meta-row equip-meta-row--inscriptions">' + inscHtml + '</div>');
        }
    }
    return lines.join('');
}

function buildEquipAffixSummaryHtml(item) {
    if (!item || !item.extension || item.extension === 'null') return '';
    try {
        var extJson = JSON.parse(item.extension);
        if (extJson && extJson.affix && extJson.affix.name) {
            var desc = extJson.affix.desc ? '：' + escapeHtml(extJson.affix.desc) : '';
            return '<span class="item-desc-effect" style="display:inline-block;margin-top:2px;">【先天·' + escapeHtml(extJson.affix.name) + '】' + desc + '</span>';
        }
    } catch (e) {}
    return '';
}

function buildEquipRealmBadgeHtml(item) {
    if (!item) return '';
    var label = '';
    if (item.isNatalArtifact) {
        label = '本命法宝';
    } else {
        var minStage = parseInt(item.minStage || 0, 10);
        var minRealmLevel = parseInt(item.minRealmLevel || 1, 10);
        if (!isFinite(minStage) || minStage < 0) minStage = 0;
        if (!isFinite(minRealmLevel) || minRealmLevel < 1) minRealmLevel = 1;
        label = formatRealmRequirement(minStage, minRealmLevel);
    }
    return '<span class="equip-swap-item__realm" style="display:inline-flex;align-items:center;margin-left:6px;padding:1px 6px;border:1px solid rgba(200,160,80,0.34);border-radius:4px;color:var(--text-gold);font-size:11px;font-weight:500;vertical-align:middle;white-space:nowrap;">' + escapeHtml(label) + '</span>';
}

async function getCurrentBodyEquipForCompare(itemType) {
    var slot = String(itemType || '').toLowerCase();
    if (['weapon', 'armor', 'accessory'].indexOf(slot) === -1) return null;

    async function ensureEquipGridData(force) {
        if (typeof loadEquipGridSummary === 'function') {
            return await loadEquipGridSummary(!!force);
        }
        try {
            var res = await api.get('/api/game/equipment/current');
            if (res.code === 200 && Array.isArray(res.data)) {
                window._equipGridCache = res.data;
                return res.data;
            }
        } catch (e) {}
        return Array.isArray(window._equipGridCache) ? window._equipGridCache : [];
    }

    var items = Array.isArray(window._equipGridCache) ? window._equipGridCache : await ensureEquipGridData(false);
    var equipped = (items || []).find(function(item) {
        return item && String(item.type || '').toLowerCase() === slot && !item.isIncarnationEquipped;
    });
    if (equipped) return equipped;

    items = await ensureEquipGridData(true);
    return (items || []).find(function(item) {
        return item && String(item.type || '').toLowerCase() === slot && !item.isIncarnationEquipped;
    }) || null;
}

function openCraftAspectFromEquipTitle(event) {
    if (event) event.stopPropagation();
    if (typeof openCrafting === 'function') {
        openCrafting('aspect');
    }
}

function renderEquipGrid() {
    var container = document.getElementById('equipGridContainer');
    if (!container) return;

    var slots = ['weapon', 'armor', 'accessory', 'ring', 'furnace'];

    // 法相穿搭只需要当前穿戴，不再为 5 个槽位拉完整背包。
    if (!Array.isArray(_equipGridCache)) {
        loadEquipGridSummary(false);
        var titleTextTmp = document.getElementById('equipGridTitleText');
        if (titleTextTmp) titleTextTmp.textContent = '法相穿搭 [数据同步中...]';
    }
    if (!_natalArtifactCache && !_natalArtifactPending) {
        loadNatalArtifactSlot();
    }

    var equippedItems = {};
    var equipItemSlots = ['weapon', 'armor', 'accessory', 'ring', 'furnace'];
    var gridItems = Array.isArray(_equipGridCache)
        ? _equipGridCache
        : buildEquipGridItemsFromInventory(_inventoryCache);
    gridItems.forEach(function(item) {
        var safeType = (item.type || '').toLowerCase();
        if (equipItemSlots.indexOf(safeType) !== -1) equippedItems[safeType] = item;
    });

    var titleTextEl = document.getElementById('equipGridTitleText');
    if (titleTextEl) {
        titleTextEl.textContent = Array.isArray(_equipGridCache) ? '法相穿搭' : '法相穿搭 [数据同步中...]';
    }

    slots.forEach(function(type) {
        var el = document.getElementById('equipSlot-' + type);
        if (!el) return;
        var item = equippedItems[type];
        if (item) {
            var isNatalArtifact = !!item.isNatalArtifact;
            el.className = 'equip-slot has-item rarity-' + item.rarity + (isNatalArtifact ? ' natal-equip-slot' : '');
            var typeName = type === 'weapon' ? '主手' : type === 'armor' ? '服饰' : type === 'accessory' ? '法器' : type === 'ring' ? '须弥戒' : '炼丹炉';
            var wearHtml = '';
            if (!isNatalArtifact && item.wearRate && item.wearRate > 0) {
                var wearPct = (item.wearRate / 100).toFixed(2);
                var wearColor = item.wearRate >= 5000 ? 'var(--text-red)' : item.wearRate >= 2500 ? 'var(--accent-orange)' : 'var(--accent-gold)';
                wearHtml = '<span class="equip-wear-badge" style="color:' + wearColor + '">破损' + wearPct + '%</span>';
            }
            
            var nameHtml = '<span class="equip-name-text" style="color:var(--rarity-' + item.rarity + ')">' + escapeHtml(item.name) + '</span>';
            var extraHtml = wearHtml;
            if (isNatalArtifact) {
                var driveCost = getNatalDriveSpiritCost(item);
                var driveHtml = item.driveCostPercent > 0
                    ? '<span class="equip-wear-badge" style="color:var(--accent-orange)">超限神识 ' + (driveCost > 0 ? (typeof formatNumber === 'function' ? formatNumber(driveCost) : String(driveCost)) + '点/场' : formatNatalPercent(item.driveCostPercent) + '%') + '</span>'
                    : '';
                extraHtml = '<span class="equip-wear-badge">本命 · 吞噬 ' + (item.devourCount || 0) + ' 次</span>' + driveHtml;
            }
            el.innerHTML = '<span class="slot-name">' + typeName + '</span>' +
                           '<div class="equip-info">' + nameHtml + buildEquipInlineMetaHtml(item, { showAffix: false, showInscriptions: false }) + extraHtml + '</div>';
            el.dataset.itemId = item.id;
        } else {
            el.className = 'equip-slot empty';
            var name = type === 'weapon' ? '主手' : type === 'armor' ? '服饰' : type === 'accessory' ? '法器' : type === 'ring' ? '须弥戒' : '炼丹炉';
            
            el.innerHTML = '<span class="slot-name">' + name + '</span>' +
                           '<span class="equip-name-text empty-text">未装备</span>';
            el.dataset.itemId = '';
        }
    });

    updateRepairAllBtn();
}

function updateRepairAllBtn() {
    var btn = document.getElementById('repairAllBtn');
    if (!btn) return;
    var equipTypes = ['weapon', 'armor', 'accessory', 'ring'];
    var broken = 0;
    var source = Array.isArray(_equipGridCache) ? _equipGridCache : (_inventoryCache || []);
    if (source && source.length > 0) {
        source.forEach(function(it) {
            var t = (it.type || '').toLowerCase();
            if (!it.isNatalArtifact && equipTypes.indexOf(t) !== -1 && it.wearRate && it.wearRate > 0) broken++;
        });
    }
    if (broken > 0) {
        btn.style.display = '';
        btn.title = '一键修复 ' + broken + ' 件破损装备';
        btn.setAttribute('aria-label', '一键修复 ' + broken + ' 件破损装备');
        btn.innerHTML = icon('repair', { size: 12 }) + '<span>修 ' + broken + '</span>';
    } else {
        btn.style.display = 'none';
    }
}

async function repairAllEquipment() {
    var pr = await api.get('/api/game/equipment/repair-all/preview');
    if (pr.code !== 200 || !pr.data) {
        showToast(pr.message || '无法获取修复预算');
        return;
    }
    var preview = pr.data;
    if (!preview.count || preview.count <= 0) { showToast('无破损装备'); return; }

    var afford = preview.currentStones >= preview.totalCost;
    var costColor = afford ? 'var(--accent-gold)' : 'var(--text-red)';
    var deficit = Math.max(0, preview.totalCost - preview.currentStones);
    var confirmDisabled = afford ? '' : ' disabled style="opacity:0.45;cursor:not-allowed;filter:none;"';
    var html = '<div class="modal-header-deco">' +
        '<div class="modal-header-deco__subtitle">一键修复感知</div>' +
        '<div class="modal-header-deco__value" style="margin-bottom:4px;">' +
        '<span class="modal-header-deco__num" style="color:var(--accent-orange);">' + formatNumber(preview.count) + '</span>' +
        '<span class="modal-header-deco__unit" style="font-size:18px;">件破损装备</span>' +
        '</div>' +
        '<div style="font-size:12px;color:var(--text-muted);">统一修复当前破损装备，完成后恢复装备全部属性。</div>' +
        '</div>' +
        '<div class="modal-body-padded">' +
        '<div class="modal-info-card modal-info-card--jade">' +
        '<div class="modal-info-card__title modal-info-card__title--jade">✦ 修复预算</div>' +
        '<div class="modal-feat-list" style="margin-left:4px;">' +
        '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--orange">◈</span><span>破损装备: <b style="color:var(--accent-orange);">' + formatNumber(preview.count) + ' 件</b></span></div>' +
        '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--jade">◈</span><span>修复费用: <b style="color:' + costColor + ';">' + formatNumber(preview.totalCost) + ' 灵石</b></span></div>' +
        '<div class="modal-feat-row"><span class="modal-feat-icon modal-feat-icon--blue">◈</span><span>当前持有: <b style="color:var(--text-gold);">' + formatNumber(preview.currentStones) + ' 灵石</b></span></div>' +
        (afford ? '' : '<div class="modal-feat-row"><span class="modal-feat-icon" style="color:var(--text-red);">◈</span><span>仍缺: <b style="color:var(--text-red);">' + formatNumber(deficit) + ' 灵石</b></span></div>') +
        '</div>' +
        '</div>' +
        '<div class="modal-info-card" style="margin-top:16px;">' +
        '<div class="modal-info-card__title">✦ 灵石修复</div>' +
        '<div style="font-size:12px;color:var(--text-muted);line-height:1.6;">' +
        (afford ? '确认后将立即扣除灵石并修复所有可修复装备。' : '灵石不足，暂时无法执行一键修复。') +
        '</div>' +
        '</div>' +
        '<div class="modal-btn-row" style="padding:0;margin-top:16px;">' +
        '<button class="modal-btn modal-btn--outline" id="repairAllCancel">取消</button>' +
        '<button class="modal-btn modal-btn--gold" id="repairAllConfirm"' + confirmDisabled + '>确认修复</button>' +
        '</div>' +
        '</div>';

    showModal(html, 'modal-overlay--top ui-scrollable-modal');

    document.getElementById('repairAllCancel').onclick = function() {
        closeModal();
    };
    var confirmBtn = document.getElementById('repairAllConfirm');
    if (!afford) return;
    confirmBtn.onclick = async function() {
        this.disabled = true;
        this.textContent = '修复中...';
        try {
            var rr = await api.post('/api/game/equipment/repair-all', {});
            if (rr.code === 200 && rr.data && rr.data.success) {
                showToast(rr.data.message || '一键修复成功');
                closeModal();
                loadEquipGridSummary(true);
                loadInventory();
            } else {
                showToast((rr.data && rr.data.message) || rr.message || '修复失败');
                this.disabled = false;
                this.textContent = '确认修复';
            }
        } catch (e) {
            showToast('网络异常，请刷新背包确认是否已扣灵石，勿重复点击');
            closeModal();
            loadEquipGridSummary(true);
            loadInventory();
        }
    };
}

async function handleEquipSlotClick(type, context) {
    var isCraftContext = context === 'craft';
    var el = document.getElementById((isCraftContext ? 'craftEquipSlot-' : 'equipSlot-') + type) || document.getElementById('equipSlot-' + type);
    var itemId = el ? el.dataset.itemId : null;
    
    var slotName = type === 'weapon' ? '主手' : type === 'armor' ? '服饰' : type === 'accessory' ? '法器' : type === 'ring' ? '须弥戒' : '炼丹炉';
    if (!Array.isArray(_equipGridCache)) await loadEquipGridSummary(false);
    var gridSource = Array.isArray(_equipGridCache) ? _equipGridCache : buildEquipGridItemsFromInventory(_inventoryCache);
    var currentItem = gridSource.find(function(i) { return itemId && i.id == itemId; }) ||
        gridSource.find(function(i) { return (i.type || '').toLowerCase() === type; });
    var availableItems = [];
    try {
        var res = await api.get('/api/game/equipment/available?slot=' + encodeURIComponent(type));
        if (res.code !== 200) {
            showToast(res.message || '可替换装备同步失败');
            return;
        }
        availableItems = Array.isArray(res.data) ? res.data : [];
    } catch (e) {
        showToast('可替换装备同步失败');
        return;
    }

    var bodyClass = isCraftContext
        ? 'modal-body-padded craft-dialog-body craft-dialog-host craft-equipment-body'
        : 'modal-body-padded';
    var html = '<div class="modal-header-deco">' +
        '<div class="modal-header-deco__subtitle">装备替换</div>' +
        '<div class="modal-header-deco__value" style="margin-bottom: 4px;">' +
        '<span class="modal-header-deco__num" style="color:var(--text-gold); font-size:24px;">' + slotName + '</span>' +
        '</div>' +
        '<div style="font-size:12px; color:var(--text-muted);">' + (type === 'furnace' ? '更换掌炉器具，用于炼造。' : '更换穿戴装备以提升战力。') + '</div>' +
        '</div>' +
        '<div class="' + bodyClass + '">';
    if (isCraftContext) {
        html += '<div class="craft-dialog-shell craft-equipment-shell">' +
            '<div class="craft-dialog-layout craft-equipment-layout">';
    }
    
    if (currentItem) {
        var isNatalArtifact = !!currentItem.isNatalArtifact;
        var unequipCall = type === 'furnace' ? ('unequipFurnace(' + currentItem.id + ')') : ('unequipItem(' + currentItem.id + ')');
        html += '<div class="' + (isCraftContext ? 'craft-dialog-section craft-equipment-section craft-equipment-current' : 'modal-info-card modal-info-card--jade') + '">' +
                '<div class="modal-info-card__title modal-info-card__title--jade">✦ 当前穿戴</div>';
        html += '<div style="color:var(--rarity-' + currentItem.rarity + '); font-size:16px; font-weight:bold; margin:8px 0 4px 0; text-align:center;">' + escapeHtml(currentItem.name) + buildEquipRealmBadgeHtml(currentItem) + '</div>';
        html += '<div style="font-size:13px; line-height:1.5; margin-bottom:8px; text-align:center;">';
        html += buildStatsHtml(currentItem);
        html += '</div>';
        var currentMetaHtml = buildEquipInlineMetaHtml(currentItem);
        if (currentMetaHtml) {
            html += '<div style="font-size:11px;line-height:1.45;text-align:center;margin-bottom:12px;">' + currentMetaHtml + '</div>';
        }
        html += '<div class="modal-action-list">';
        if (isNatalArtifact) {
            html += '<button class="modal-action-btn modal-action-btn--purple" onclick="closeModal(); openNatalArtifactModal();">' +
                '<span class="modal-action-btn__text"><b>本命详情</b><small>查看成长、吞噬材料与神识催动</small></span></button>';
            html += '<button class="modal-action-btn modal-action-btn--orange" onclick="closeModal(); showRefinePanel(-9000001);">' +
                '<span class="modal-action-btn__text"><b>祭炼</b><small>消耗材料提升本命属性</small></span></button>';
            html += '<button class="modal-action-btn modal-action-btn--purple" onclick="closeModal(); showInscriptionPanel(-9000001);">' +
                '<span class="modal-action-btn__text"><b>铭文</b><small>查看或调整本命铭文</small></span></button>';
        } else if (type !== 'furnace') {
            html += '<button class="modal-action-btn modal-action-btn--orange" onclick="closeModal(); showRefinePanel(' + currentItem.id + ');">' +
                '<span class="modal-action-btn__text"><b>祭炼</b><small>消耗材料提升装备属性</small></span></button>';
            html += '<button class="modal-action-btn modal-action-btn--purple" onclick="closeModal(); showInscriptionPanel(' + currentItem.id + ');">' +
                '<span class="modal-action-btn__text"><b>铭文</b><small>查看或调整装备铭文</small></span></button>';
            if (currentItem.wearRate && currentItem.wearRate > 0) {
                html += '<button class="modal-action-btn modal-action-btn--cyan" onclick="closeModal(); showRepairPanel(' + currentItem.id + ');">' +
                    '<span class="modal-action-btn__text"><b>修复</b><small>修复当前装备破损</small></span></button>';
            }
        }
        html += '<button class="modal-action-btn" style="height:36px; display:flex; justify-content:center; background:rgba(244,67,54,0.15); border:1px solid rgba(244,67,54,0.3);"' +
            ' onclick="closeModal(); ' + unequipCall + ';">' +
            '<span style="color:#f44336; width:100%; text-align:center;">卸下当前</span></button>';
        html += '</div>';
        html += '</div>';
    }
    
    html += '<div class="' + (isCraftContext ? 'craft-dialog-section craft-equipment-section craft-equipment-replacements' : 'modal-info-card') + '"' + (isCraftContext ? '' : ' style="margin-top: 16px;"') + '>' +
            '<div class="modal-info-card__title">✦ 可替换的装备 (' + availableItems.length + ')</div>';
    
    if (availableItems.length === 0) {
        html += '<p style="color:#777; font-size:13px; text-align:center; padding:10px 0;">包裹中没有可用的同部位装备。</p>';
    } else {
        html += '<div class="equip-swap-list">';
        availableItems.forEach(function(item) {
            var equipCall = type === 'furnace' ? ('equipFurnace(' + item.id + ')') : ('equipItem(' + item.id + ')');
            html += '<div class="equip-swap-item" onclick="closeModal(); ' + equipCall + ';">';
            html += '<div class="item-details">';
            html += '<strong style="color:var(--rarity-' + item.rarity + '); font-size:14px;">' + escapeHtml(item.name);
            if (item.refineLevel > 0) html += ' +' + item.refineLevel;
            html += '</strong>' + buildEquipRealmBadgeHtml(item) + '<br>';
            var stats = [];
            if (item.attackBonus) stats.push('攻+' + item.attackBonus);
            if (item.defenseBonus) stats.push('防+' + item.defenseBonus);
            if (item.hpBonus) stats.push('血+' + item.hpBonus);
            if (item.spiritBonus) stats.push('神+' + item.spiritBonus);
            if (item.capacityBonus) stats.push('容+' + item.capacityBonus);
            html += '<span style="color:var(--text-muted); font-size:11px;">' + stats.join(' | ') + '</span>';
            var itemMetaHtml = buildEquipInlineMetaHtml(item);
            if (itemMetaHtml) {
                html += '<div style="font-size:11px;line-height:1.45;margin-top:4px;">' + itemMetaHtml + '</div>';
            }
            html += '</div>';
            html += '<span style="color:var(--accent-gold); font-size:12px; padding:4px 8px; border:1px solid rgba(200,160,80,0.3); border-radius:4px;">装备</span>';
            html += '</div>';
        });
        html += '</div>';
    }
    html += '</div>';
    if (isCraftContext) {
        html += '</div></div>';
    }
    html += '</div>';

    showModal(html, 'modal-overlay--top ui-scrollable-modal' + (isCraftContext ? ' craft-equipment-modal-overlay' : ''));
}

// ================= 装备方案 (一键换装，2套互换) =================
var _equipLoadoutBusy = false;

async function openEquipLoadoutModal() {
    if (_equipLoadoutBusy) return;
    _equipLoadoutBusy = true;
    try {
        var res = await api.get('/api/equip-loadout/list');
        if (res.code !== 200) { showToast(res.message || '方案加载失败'); return; }
        renderEquipLoadoutModal(Array.isArray(res.data) ? res.data : []);
    } catch (e) {
        showToast('网络异常，请稍后再试');
    } finally {
        _equipLoadoutBusy = false;
    }
}

function renderEquipLoadoutModal(loadouts) {
    var slotZh = { weapon:'主手', armor:'服饰', accessory:'法器', ring:'须弥戒' };
    var html = '<div class="equip-loadout-modal">' +
        '<div class="modal-header-deco">' +
        '<div class="modal-header-deco__subtitle">一键换装</div>' +
        '<div style="font-size:12px;color:var(--text-muted);margin-top:4px;">保存当前穿戴为方案，随时一键换回；最多 2 套，可互换。</div>' +
        '</div>' +
        '<div class="modal-body-padded craft-dialog-body craft-dialog-host equip-loadout-body">' +
        '<div class="craft-dialog-shell equip-loadout-shell">' +
        '<div class="craft-dialog-layout equip-loadout-layout">';

    for (var i = 0; i < loadouts.length; i++) {
        var lo = loadouts[i];
        var loadoutName = lo.name || ('方案 ' + lo.slot);
        var hasItems = lo.saved && lo.items && lo.items.length > 0;
        var itemCount = hasItems ? lo.items.length : 0;
        var statusBadge = lo.saved
            ? '<span class="recipe-stage-badge">已保存</span>'
            : '<span class="recipe-type-badge equip-loadout-unsaved">未保存</span>';
        var countBadge = hasItems ? '<span class="recipe-type-badge">' + itemCount + ' 件装备</span>' : '';
        html += '<article class="craft-card equip-loadout-section equip-loadout-card' + (hasItems ? '' : ' equip-loadout-card--empty') + '">';
        html += '<div class="craft-card-topline equip-loadout-card__head">' +
            '<div class="craft-card-title-wrap">' +
            '<div class="recipe-name equip-loadout-card__name">' + escapeHtml(loadoutName) + '</div>' +
            '<div class="recipe-badges">' + statusBadge + countBadge + '</div>' +
            '</div>' +
            (lo.saved ? '<button type="button" class="equip-loadout-rename" data-eql-act="rename" data-eql-slot="' + lo.slot + '">重命名</button>' : '') +
            '</div>';

        if (hasItems) {
            html += '<div class="craft-card-content equip-loadout-items">';
            lo.items.forEach(function(it) {
                var slotLabel = slotZh[it.slot] || it.slot;
                var body;
                if (it.missing) {
                    body = '<span class="equip-loadout-item__missing">已遗失</span>';
                } else {
                    var rarity = it.rarity || 1;
                    var refine = it.refineLevel > 0 ? (' +' + it.refineLevel) : '';
                    var tail = it.isEquipped ? '<span class="recipe-stage-badge equip-loadout-equipped">穿戴中</span>' : '';
                    body = '<span class="equip-loadout-item__name rarity-' + rarity + '">' + escapeHtml(it.name) + refine + '</span>' + tail;
                }
                html += '<div class="equip-loadout-item' + (it.missing ? ' equip-loadout-item--missing' : '') + '">' +
                    '<span class="recipe-type-badge equip-loadout-slot">' + slotLabel + '</span>' +
                    '<span class="equip-loadout-item__text">' + body + '</span>' +
                    '</div>';
            });
            html += '</div>';
        } else {
            html += '<div class="equip-loadout-empty">尚未保存任何装备</div>';
        }

        html += '<div class="craft-card-actions equip-loadout-actions">' +
            '<button class="btn-craft btn-craft-sm btn-batch" data-eql-act="save" data-eql-slot="' + lo.slot + '" data-eql-name="' + escapeHtml(loadoutName) + '">保存当前</button>' +
            (hasItems ?
                '<button class="btn-craft btn-craft-sm" data-eql-act="apply" data-eql-slot="' + lo.slot + '" data-eql-target="body">本体穿上</button>' +
                '<button class="btn-craft btn-craft-sm btn-quickbuy" data-eql-act="apply" data-eql-slot="' + lo.slot + '" data-eql-target="incarnation">化身穿上</button>'
                : '') +
            '</div>';
        html += '</article>';
    }

    html += '<section class="craft-dialog-section equip-loadout-section equip-loadout-note-section">' +
        '<div class="equip-loadout-note">' +
        '※ 本体穿上会卸下当前本体装备，再依方案重新穿戴。<br>' +
        '※ 方案装备在本体或化身身上时会自动转移；修为不足、装备遗失会自动跳过。' +
        '</div>' +
        '</section>';
    html += '</div></div></div></div>';

    showModal(html, 'modal-overlay--top ui-scrollable-modal equip-loadout-modal-overlay');

    document.querySelectorAll('[data-eql-act]').forEach(function(btn) {
        btn.addEventListener('click', function() {
            var act = btn.dataset.eqlAct;
            var slot = parseInt(btn.dataset.eqlSlot, 10);
            if (act === 'save') saveEquipLoadout(slot, btn.getAttribute('data-eql-name') || '');
            else if (act === 'apply') applyEquipLoadout(slot, btn.dataset.eqlTarget || 'body');
            else if (act === 'rename') renameEquipLoadout(slot);
        });
    });
}

async function saveEquipLoadout(slot, defaultName) {
    var promptName = defaultName && String(defaultName).trim() ? String(defaultName).trim() : ('方案 ' + slot);
    gamePrompt('输入方案名称（不超过16字）：', promptName, async function (name) {
        if (!name || !name.trim()) return;
        try {
            var res = await api.post('/api/equip-loadout/save', { slot: slot, name: name.trim() });
            if (res.code === 200) {
                showToast(res.data || '方案已保存');
                openEquipLoadoutModal();
            } else {
                showToast(res.message || '保存失败');
            }
        } catch (e) {
            showToast('网络异常，请重试');
        }
    });
}

async function applyEquipLoadout(slot, target) {
    if (_equipLoadoutBusy) return;
    _equipLoadoutBusy = true;
    try {
        var res = await api.post('/api/equip-loadout/apply', { slot: slot, target: target || 'body' });
        if (res.code === 200 && res.data && res.data.success) {
            showToast(res.data.message || '换装成功');
            closeModal();
            loadPlayerInfo();
            loadEquipGridSummary(true);
            loadInventory();
        } else {
            showToast((res.data && res.data.message) || res.message || '换装失败');
        }
    } catch (e) {
        showToast('网络异常，请重试');
    } finally {
        _equipLoadoutBusy = false;
    }
}

async function renameEquipLoadout(slot) {
    gamePrompt('输入新的方案名称（不超过16字）：', '', async function (name) {
        if (!name || !name.trim()) return;
        try {
            var res = await api.post('/api/equip-loadout/rename', { slot: slot, name: name.trim() });
            if (res.code === 200) {
                showToast(res.data || '已重命名');
                openEquipLoadoutModal();
            } else {
                showToast(res.message || '重命名失败');
            }
        } catch (e) {
            showToast('网络异常，请重试');
        }
    });
}
